def slog(*args):
    """Append a timestamped line to ~/.amux/logs/server.log (and stderr if TTY)."""
    import datetime
    msg = " ".join(str(a) for a in args)
    line = f"{datetime.datetime.now().strftime('%Y-%m-%d %H:%M:%S')} {msg}\n"
    # Only write to stderr if it's a real terminal — launchd redirects stderr
    # to server.log, so writing to both would double every line.
    if sys.stderr.isatty():
        sys.stderr.write(line)
    try:
        with _server_log_lock:
            with open(SERVER_LOG, "a") as f:
                f.write(line)
    except Exception:
        pass

_server_start_time = time.time()

# Cached process info — updated by background thread, never blocks request handlers
_proc_info_cache: dict = {}
_proc_info_lock = threading.Lock()
_proc_info_last_update: float = 0.0
_PROC_INFO_TTL = 10.0  # refresh every 10s

def _build_proc_info() -> dict:
    """Gather process-level diagnostics (blocks ~500ms for CPU sampling)."""
    info = {}
    try:
        # Longer sample window + actual elapsed time divisor: a 100ms window was
        # small enough that any brief multi-thread burst inflated the reading to
        # 150-200%, triggering false watchdog alerts.
        t1 = os.times()
        w1 = time.monotonic()
        time.sleep(0.5)
        t2 = os.times()
        elapsed = max(time.monotonic() - w1, 0.001)
        cpu_seconds = (t2.user - t1.user) + (t2.system - t1.system)
        info["cpu_percent"] = round(cpu_seconds / elapsed * 100, 1)
    except Exception:
        pass
    try:
        # Use current RSS (not peak) so the watchdog reacts to actual pressure,
        # not a one-time spike that has since been reclaimed.
        import resource as _res
        ru = _res.getrusage(_res.RUSAGE_SELF)
        peak_mb = round(ru.ru_maxrss / (1024 * 1024), 1) if sys.platform == "darwin" else round(ru.ru_maxrss / 1024, 1)
        info["peak_memory_mb"] = peak_mb
        # Current RSS from /proc or ps
        import subprocess as _sp
        current_mb = None
        try:
            with open(f"/proc/{os.getpid()}/status") as f:
                for line in f:
                    if line.startswith("VmRSS:"):
                        current_mb = round(int(line.split()[1]) / 1024, 1)
                        break
        except FileNotFoundError:
            r = _sp.run(["ps", "-o", "rss=", "-p", str(os.getpid())],
                        capture_output=True, text=True, timeout=3)
            if r.returncode == 0 and r.stdout.strip():
                current_mb = round(int(r.stdout.strip()) / 1024, 1)
        info["memory_mb"] = current_mb if current_mb is not None else peak_mb
    except Exception:
        pass
    try:
        info["fd_count"] = len(os.listdir(f"/dev/fd"))
    except Exception:
        pass
    try:
        import subprocess
        out = subprocess.check_output(["tmux", "list-sessions", "-F", "#{session_name}"], stderr=subprocess.DEVNULL, timeout=5)
        info["session_count"] = len([l for l in out.decode().strip().splitlines() if l])
    except Exception:
        info["session_count"] = -1
    return info

def psutil_process_info():
    """Return cached process info (non-blocking). Triggers background refresh if stale."""
    global _proc_info_last_update
    now = time.time()
    with _proc_info_lock:
        cached = dict(_proc_info_cache)
        age = now - _proc_info_last_update
    if age > _PROC_INFO_TTL:
        def _refresh():
            global _proc_info_last_update
            data = _build_proc_info()
            with _proc_info_lock:
                _proc_info_cache.update(data)
                _proc_info_last_update = time.time()
        if not cached:
            # Cold start: build synchronously so first call returns real data
            _refresh()
            with _proc_info_lock:
                return dict(_proc_info_cache)
        threading.Thread(target=_refresh, daemon=True).start()
    return cached

def _log_resource_snapshot(label="snapshot"):
    """Log a resource snapshot to server.log."""
    info = psutil_process_info()
    slog(f"[{label}] pid={os.getpid()} cpu={info.get('cpu_percent','?')}% mem={info.get('memory_mb','?')}MB fds={info.get('fd_count','?')} threads={threading.active_count()} sessions={info.get('session_count','?')} requests={_server_request_count}")

_active_servers: list = []  # populated in main(); used by signal handler for clean shutdown

def _install_signal_handlers():
    """Install signal handlers that log before exit."""
    import signal
    def _sig_handler(signum, frame):
        sig_name = signal.Signals(signum).name
        slog(f"[SIGNAL] received {sig_name} ({signum}) — logging diagnostics before exit")
        _log_resource_snapshot("crash-dump")
        # Close listening sockets so the port is freed immediately for the next
        # process (launchd KeepAlive respawn).  Without this, the socket lingers
        # in TIME_WAIT and the replacement process can't bind.
        for _s in _active_servers:
            try:
                _s.socket.close()
            except Exception:
                pass
        try:
            _db_conn().close()
        except Exception:
            pass
        slog(f"[SIGNAL] exiting due to {sig_name}")
        os._exit(128 + signum)
    signal.signal(signal.SIGTERM, _sig_handler)
    # Ignore SIGHUP so the server survives terminal disconnects and
    # os.execv auto-restarts (where nohup protection is lost).
    signal.signal(signal.SIGHUP, signal.SIG_IGN)

# ── Torrent (aria2c RPC) helpers ──────────────────────────────────────────────
_ARIA2_RPC_PORT = 6800
_ARIA2_RPC_SECRET = "amux"
_ARIA2_DOWNLOAD_DIR = str(Path.home() / "Downloads" / "amux-torrents")
_aria2_proc = None

def _aria2_ensure():
    """Start aria2c daemon if not running."""
    global _aria2_proc
    if _aria2_proc and _aria2_proc.poll() is None:
        return True
    # Check if already running
    try:
        r = _aria2_rpc("aria2.getVersion")
        if r: return True
    except Exception:
        pass
    aria2 = shutil.which("aria2c")
    if not aria2:
        return False
    os.makedirs(_ARIA2_DOWNLOAD_DIR, exist_ok=True)
    _aria2_proc = subprocess.Popen([
        aria2, "--enable-rpc", "--rpc-listen-port", str(_ARIA2_RPC_PORT),
        "--rpc-secret", _ARIA2_RPC_SECRET,
        "--dir", _ARIA2_DOWNLOAD_DIR,
        "--seed-time=0",  # don't seed after download
        "--bt-enable-lpd=true",
        "--enable-dht=true",
        "--enable-peer-exchange=true",
        "--max-concurrent-downloads=5",
        "--file-allocation=none",
        "--daemon=false",
        "--quiet=true",
    ], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
    time.sleep(0.5)
    return _aria2_proc.poll() is None

def _aria2_rpc(method, params=None):
    """Call aria2 JSON-RPC."""
    payload = {
        "jsonrpc": "2.0",
        "id": "amux",
        "method": method,
        "params": [f"token:{_ARIA2_RPC_SECRET}"] + (params or [])
    }
    import urllib.request
    req = urllib.request.Request(
        f"http://localhost:{_ARIA2_RPC_PORT}/jsonrpc",
        data=json.dumps(payload).encode(),
        headers={"Content-Type": "application/json"},
    )
    with urllib.request.urlopen(req, timeout=5) as resp:
        return json.loads(resp.read()).get("result")

def _aria2_list_all():
    """Get all torrents (active + waiting + stopped)."""
    torrents = []
    for method in ("aria2.tellActive", "aria2.tellWaiting", "aria2.tellStopped"):
        try:
            params = [0, 100] if method != "aria2.tellActive" else []
            items = _aria2_rpc(method, params) or []
            torrents.extend(items)
        except Exception:
            pass
    result = []
    for t in torrents:
        gid = t.get("gid", "")
        total = int(t.get("totalLength", 0))
        completed = int(t.get("completedLength", 0))
        speed = int(t.get("downloadSpeed", 0))
        status = t.get("status", "unknown")
        bt = t.get("bittorrent", {})
        name = ""
        if bt.get("info"):
            name = bt["info"].get("name", "")
        if not name and t.get("files"):
            name = t["files"][0].get("path", "").split("/")[-1]
        files = []
        for f in t.get("files", []):
            fp = f.get("path", "")
            if not fp:
                continue
            fsize = int(f.get("length", 0))
            fcomplete = int(f.get("completedLength", 0)) >= fsize and fsize > 0
            files.append({"path": fp, "size": fsize, "complete": fcomplete})
        result.append({
            "gid": gid, "name": name, "status": status,
            "total": total, "completed": completed, "speed": speed,
            "files": files,
        })
    return result


# ── Browser automation helpers (browser-use CLI) ─────────────────────────────
_BROWSER_USE_BIN = shutil.which("browser-use") or "/usr/local/bin/browser-use"
_browser_session_activity: dict[str, float] = {}  # session_name -> last_activity epoch
_browser_locks: dict[str, threading.Lock] = {}     # per-session lock to serialize subprocess calls
_browser_locks_mu = threading.Lock()               # protects _browser_locks dict

def _browser_lock_for(session: str) -> threading.Lock:
    """Return (or create) the per-session lock for browser-use calls."""
    with _browser_locks_mu:
        if session not in _browser_locks:
            _browser_locks[session] = threading.Lock()
        return _browser_locks[session]

def _browser_touch(session: str = "amux"):
    """Record activity for a browser-use session (called on every _bu_call)."""
    _browser_session_activity[session] = time.time()

def _bu_call(args: list, timeout_s: int = 30, session: str = "amux") -> dict:
    """Run a browser-use CLI command, return parsed JSON result.

    Serialized per-session via lock to prevent concurrent subprocess spawning
    (multiple Chromium launches cause sustained high CPU).
    """
    lock = _browser_lock_for(session)
    if not lock.acquire(timeout=timeout_s + 5):
        return {"error": "browser session busy, try again later"}
    try:
        if args and args[0] != "close":
            _browser_touch(session)
        cmd = [_BROWSER_USE_BIN, "--json", "--session", session] + args
        # Self-heal the transient "SessionManager not initialized" race: the
        # persistent browser-use session server can lag a beat behind /start, so
        # the next action/screenshot lands before it's ready. Retry ONLY that
        # (and empty-output) transient — real command errors return immediately.
        last = None
        for attempt in range(3):
            try:
                r = subprocess.run(cmd, capture_output=True, text=True, timeout=timeout_s)
            except subprocess.TimeoutExpired:
                return {"error": "browser operation timed out"}
            except Exception as e:
                return {"error": str(e)}
            out = r.stdout.strip()
            if not out:
                last = {"error": r.stderr.strip() or f"browser-use exited {r.returncode}"}
            else:
                try:
                    res = json.loads(out)
                except json.JSONDecodeError:
                    return {"error": out[:200]}
                err = (res.get("error") or "") if isinstance(res, dict) else ""
                if not (err and ("SessionManager" in err or "not initialized" in err)):
                    return res  # success, or a real (non-transient) error
                last = res
            if attempt < 2:
                time.sleep(1.2)
        return last or {"error": "browser call failed"}
    finally:
        lock.release()

def _bu_list_profiles() -> list:
    """List available Chrome profiles via browser-use."""
    try:
        r = subprocess.run(
            [_BROWSER_USE_BIN, "-b", "real", "profile", "list"],
            capture_output=True, text=True, timeout=10,
        )
        profiles = []
        for line in r.stdout.strip().splitlines():
            line = line.strip()
            if line.startswith("Local Chrome") or not line:
                continue
            # Format: "Profile 11: Ethan (email@example.com)"
            if ":" in line:
                name = line.split(":")[0].strip()
                profiles.append(name)
        return profiles
    except Exception:
        return []

# ── Browser profile registry ──────────────────────────────────────────────────
# A "profile" is a named persistent Chrome context: browser-use runs it via
# `-b real --profile <name>`, which reuses the real Chrome user-data-dir with
# <name> as the profile sub-directory. Logging in once under a name persists —
# so the whole game is to ALWAYS run under a named profile and remember which
# domains each is logged into. The registry below is that memory: a small JSON
# mapping profile name -> {domains, label, updated}. It lets us AUTO-SELECT the
# right (already-logged-in) profile from a target URL's host. An agent only has
# to call /api/browser/start with a URL — the matching profile loads itself.
_PROFILES_REGISTRY = CC_HOME / "playwright-auth" / "profiles.json"
_registry_lock = threading.Lock()

def _bu_registry_load() -> dict:
    try:
        if _PROFILES_REGISTRY.exists():
            data = json.loads(_PROFILES_REGISTRY.read_text())
            return data if isinstance(data, dict) else {}
    except Exception:
        pass
    return {}

def _bu_registry_save(reg: dict) -> bool:
    try:
        _PROFILES_REGISTRY.parent.mkdir(parents=True, exist_ok=True)
        tmp = _PROFILES_REGISTRY.with_name(_PROFILES_REGISTRY.name + ".tmp")
        tmp.write_text(json.dumps(reg, indent=2, sort_keys=True))
        tmp.replace(_PROFILES_REGISTRY)
        return True
    except Exception:
        return False

def _host_of(url: str) -> str:
    """Return the lowercase hostname of a URL (tolerates missing scheme)."""
    try:
        from urllib.parse import urlparse
        u = url if "://" in url else "https://" + url
        return (urlparse(u).hostname or "").lower()
    except Exception:
        return ""

def _domain_matches(host: str, domain: str) -> bool:
    """Suffix match: host equals domain or is a sub-domain of it."""
    host = (host or "").lower().lstrip(".")
    domain = (domain or "").lower().lstrip(".")
    if not host or not domain:
        return False
    return host == domain or host.endswith("." + domain)

def _bu_registry_register(name: str, host: str = "", label: str = "") -> dict:
    """Ensure a profile is registered; add host to its domains. Returns the entry."""
    with _registry_lock:
        reg = _bu_registry_load()
        entry = reg.get(name) if isinstance(reg.get(name), dict) else None
        if entry is None:
            entry = {"domains": [], "label": "", "updated": 0}
        if host and host not in entry["domains"]:
            entry["domains"].append(host)
        if label:
            entry["label"] = label
        entry["updated"] = int(time.time())
        reg[name] = entry
        _bu_registry_save(reg)
        return entry

def _bu_pick_profile(url: str, explicit: str = "") -> tuple:
    """Resolve which profile to use for a URL.

    Explicit wins. Otherwise auto-select the registered profile whose domains
    best (longest / most specific) match the URL's host. Falls back to 'default'.
    Returns (name, auto_selected_bool).
    """
    if explicit:
        return explicit, False
    host = _host_of(url)
    reg = _bu_registry_load()
    best, best_len = None, -1
    for name, meta in reg.items():
        if not isinstance(meta, dict):
            continue
        for dom in (meta.get("domains") or []):
            if _domain_matches(host, dom) and len(dom) > best_len:
                best, best_len = name, len(dom)
    if best:
        return best, True
    return "default", False

def _bu_session_profile(session: str) -> str:
    """Profile the running browser-use session was created with (from its meta), or ''."""
    try:
        import tempfile
        meta = Path(tempfile.gettempdir()) / f"browser-use-{session}.meta"
        if meta.exists():
            return json.loads(meta.read_text()).get("profile") or ""
    except Exception:
        pass
    return ""

def _bu_open(url: str, session: str = "amux", explicit_profile: str = "",
             fresh: bool = False, timeout_s: int = 30) -> dict:
    """Open a URL under the correct profile.

    Auto-selects a registered profile by domain when explicit_profile is empty,
    so callers/agents stay logged in without tracking cookies themselves. The
    session is (re)created with the resolved profile when the currently running
    session uses a different one — that's what makes `-b real --profile` login
    persistence actually take effect. Same-profile navigation reuses the session.
    The response carries `profile` (chosen) and `auto_profile` (was it inferred).
    """
    profile, auto = _bu_pick_profile(url, explicit_profile)
    cur = _bu_session_profile(session)
    if cur and cur == profile and not fresh:
        res = _bu_call(["open", url], session=session, timeout_s=timeout_s)
    else:
        if cur:  # existing session runs a different profile — close before reopening
            _bu_call(["close"], session=session, timeout_s=10)
        res = _bu_call(["-b", "real", "--profile", profile, "open", url],
                       session=session, timeout_s=timeout_s)
        # Graceful fallback: if real-Chrome mode can't launch, browse anyway
        if isinstance(res, dict) and res.get("error"):
            fb = _bu_call(["open", url], session=session, timeout_s=timeout_s)
            if isinstance(fb, dict) and not fb.get("error"):
                fb["profile"] = profile
                fb["auto_profile"] = auto
                fb["profile_fallback"] = True
                return fb
    if isinstance(res, dict):
        res = dict(res)
        res["profile"] = profile
        res["auto_profile"] = auto
        # Re-install the console/network capture shim on every navigation (page
        # globals reset on load) so /api/browser/inspect can troubleshoot the page.
        if not res.get("error"):
            try: _bu_inject_capture(session)
            except Exception: pass
    return res

def _bu_parse_elements(raw_text: str, limit: int = 120) -> dict:
    """Parse browser-use `state` _raw_text into {viewport, elements[]}.

    _raw_text lines look like:  [1102]<button />   then an indented label line.
    Returns numbered, index-addressable elements for ref-based clicking — the
    structured (accessibility-first) perception surface, more reliable than
    pixel clicking.
    """
    vp = None
    els = []
    if not raw_text:
        return {"viewport": vp, "elements": els}
    el_re = re.compile(r"^(\s*)\*?\[(\d+)\]<([a-zA-Z0-9\-]+)([^>]*?)/?>\s*$")
    attr_label_re = re.compile(r'(?:aria-label|id|role|name|placeholder|value)=([^\s/>]+)')
    lines = raw_text.splitlines()
    for i, line in enumerate(lines):
        if vp is None and line.startswith("viewport:"):
            m = re.search(r"(\d+)\s*x\s*(\d+)", line)
            if m:
                vp = {"w": int(m.group(1)), "h": int(m.group(2))}
            continue
        m = el_re.match(line)
        if not m:
            continue
        indent, idx, tag, attrs = m.groups()
        # Label: prefer a following deeper-indented text (non-bracket) line
        label = ""
        for j in range(i + 1, min(i + 4, len(lines))):
            nxt = lines[j]
            if "[" in nxt and "]<" in nxt:
                break
            t = nxt.strip()
            if t and not t.startswith("|") and not t.startswith("<"):
                label = t
                break
        if not label:
            am = attr_label_re.search(attrs or "")
            if am:
                label = am.group(1)
        els.append({"index": int(idx), "tag": tag, "label": label[:80]})
        if len(els) >= limit:
            break
    return {"viewport": vp, "elements": els}

def _bu_screenshot(session: str = "amux", path: str = "", retries: int = 3) -> dict:
    """Take a screenshot, return {path, size}. Retries on SessionManager errors."""
    dest = path or str(CC_HOME / "browser-screenshots" / "latest.jpg")
    Path(dest).parent.mkdir(parents=True, exist_ok=True)
    for attempt in range(retries):
        result = _bu_call(["screenshot", dest], session=session)
        if result.get("success"):
            try:
                size = Path(dest).stat().st_size
            except Exception:
                size = 0
            return {"path": dest, "size": size}
        err = result.get("error", "")
        if "SessionManager" in err and attempt < retries - 1:
            import time as _t; _t.sleep(1.5)
            continue
        return result
    return result

# ── Browser troubleshooting: console / network / error capture ────────────────
# browser-use is subprocess-per-action, so we can't hold a live CDP listener.
# Instead we inject an idempotent capture shim into the page (re-injected on every
# navigation by _bu_open) that mirrors console.*, fetch, and XHR into page-global
# ring buffers, plus window error/unhandledrejection. Network is additionally
# back-filled from the Resource Timing API (performance.getEntriesByType), which
# retroactively lists EVERY request — even ones that fired before injection.
_BROWSER_CAPTURE_JS = r"""
(function(){
  if (window.__amux && window.__amux.__installed) return 'already';
  var CAP = 500;
  var S = window.__amux = window.__amux || {};
  S.console = S.console || []; S.net = S.net || []; S.errors = S.errors || [];
  S.__installed = true;
  var now = function(){ return Date.now(); };
  function push(a, x){ a.push(x); if (a.length > CAP) a.shift(); }
  function fmt(a){
    try {
      if (a instanceof Error) return a.stack || (a.name + ': ' + a.message);
      if (typeof a === 'object' && a !== null) { try { return JSON.stringify(a); } catch(e){ return String(a); } }
      return String(a);
    } catch(e){ return '[unserializable]'; }
  }
  ['log','info','warn','error','debug'].forEach(function(level){
    var orig = console[level]; if (!orig) return;
    console[level] = function(){
      try { push(S.console, { level: level, text: [].map.call(arguments, fmt).join(' '), ts: now() }); } catch(e){}
      return orig.apply(console, arguments);
    };
  });
  window.addEventListener('error', function(e){
    push(S.errors, { text: (e.message || 'error') + (e.filename ? (' @ ' + e.filename + ':' + e.lineno + ':' + e.colno) : ''),
                     stack: (e.error && e.error.stack) || '', ts: now() });
  });
  window.addEventListener('unhandledrejection', function(e){
    var r = e.reason; push(S.errors, { text: 'unhandledrejection: ' + ((r && r.message) || fmt(r)), stack: (r && r.stack) || '', ts: now() });
  });
  if (window.fetch) {
    var of = window.fetch;
    window.fetch = function(input, init){
      var url = (typeof input === 'string') ? input : (input && input.url) || '';
      var method = (init && init.method) || (input && input.method) || 'GET';
      var t0 = now();
      return of.apply(this, arguments).then(function(res){
        push(S.net, { type:'fetch', method:method, url:url, status:res.status, ok:res.ok, ms: now()-t0, ts: t0 }); return res;
      }, function(err){
        push(S.net, { type:'fetch', method:method, url:url, status:0, ok:false, error:String(err), ms: now()-t0, ts: t0 }); throw err;
      });
    };
  }
  var OX = window.XMLHttpRequest;
  if (OX) {
    var NX = function(){
      var xhr = new OX();
      var rec = { type:'xhr', method:'GET', url:'', status:0, ok:false, ms:0, ts: now() };
      var open = xhr.open;
      xhr.open = function(m, u){ rec.method = m; rec.url = u; return open.apply(xhr, arguments); };
      var send = xhr.send;
      xhr.send = function(){ var t0 = now();
        xhr.addEventListener('loadend', function(){ rec.status = xhr.status; rec.ok = (xhr.status >= 200 && xhr.status < 400); rec.ms = now()-t0; push(S.net, rec); });
        return send.apply(xhr, arguments); };
      return xhr;
    };
    NX.prototype = OX.prototype; window.XMLHttpRequest = NX;
  }
  return 'installed';
})()
"""

_BROWSER_INSPECT_JS = r"""
(function(){
  var S = window.__amux || {};
  var L = __LIMIT__;
  function tail(a){ a = a || []; return a.slice(Math.max(0, a.length - L)); }
  var res = [];
  try {
    res = performance.getEntriesByType('resource').slice(-L).map(function(e){
      return { url:e.name, type:e.initiatorType, ms:Math.round(e.duration), size:e.transferSize||0, start:Math.round(e.startTime) };
    });
  } catch(e){}
  var out = { url: location.href, title: document.title, installed: !!S.__installed,
    console: tail(S.console), network: tail(S.net), errors: tail(S.errors), resources: res,
    counts: { console:(S.console||[]).length, network:(S.net||[]).length, errors:(S.errors||[]).length, resources:res.length } };
  if (__CLEAR__) { if (S.console) S.console.length = 0; if (S.net) S.net.length = 0; if (S.errors) S.errors.length = 0; }
  return out;
})()
"""

def _bu_inject_capture(session: str = "amux") -> dict:
    """Inject the console/network/error capture shim (idempotent per page)."""
    return _bu_call(["eval", _BROWSER_CAPTURE_JS], session=session, timeout_s=15)

def _bu_inspect(session: str = "amux", clear: bool = False, limit: int = 200) -> dict:
    """Read captured console/network/errors (+ Resource Timing) from the page."""
    js = (_BROWSER_INSPECT_JS
          .replace("__LIMIT__", str(int(limit)))
          .replace("__CLEAR__", "true" if clear else "false"))
    res = _bu_call(["eval", js], session=session, timeout_s=15)
    if not isinstance(res, dict) or res.get("error"):
        return res if isinstance(res, dict) else {"error": "inspect failed"}
    data = (res.get("data") or {}).get("result")
    if isinstance(data, str):
        try: data = json.loads(data)
        except Exception: pass
    if isinstance(data, dict):
        # If the shim isn't installed (e.g. page navigated), still return Resource Timing.
        return data
    return {"error": "no capture data", "raw": data}


def _resolve_claude_bin() -> str:
    """Locate the claude CLI binary (PATH first, then common install locations)."""
    found = shutil.which("claude")
    if found:
        return found
    for p in (Path.home() / ".local" / "bin" / "claude",
              Path.home() / ".claude" / "local" / "claude",
              Path("/usr/local/bin/claude"),
              Path("/opt/homebrew/bin/claude")):
        if p.exists():
            return str(p)
    return ""


def _on_claude_plan() -> bool:
    """True when logged in via OAuth (a Claude Plan), independent of any API key."""
    try:
        cj = Path.home() / ".claude.json"
        if cj.exists():
            return bool(json.loads(cj.read_text()).get("oauthAccount"))
    except Exception:
        pass
    return False


_usage_cache = {"data": None, "time": 0.0}
_USAGE_TTL = 30  # seconds — the modal can be reopened without hammering Anthropic


def _claude_oauth_token():
    """Best-effort read of the Claude Code subscription OAuth token — macOS
    keychain first, then ~/.claude/.credentials.json. Returns (token, expires_ms)
    or (None, 0). Cloud hosts have neither, so usage simply reports unavailable —
    no IS_CLOUD branch, just presence/absence of the credential."""
    try:
        r = subprocess.run(
            ["security", "find-generic-password", "-s", "Claude Code-credentials", "-w"],
            capture_output=True, text=True, timeout=5)
        if r.returncode == 0 and r.stdout.strip():
            d = json.loads(r.stdout).get("claudeAiOauth", {})
            if d.get("accessToken"):
                return d["accessToken"], int(d.get("expiresAt") or 0)
    except Exception:
        pass
    try:
        p = Path.home() / ".claude" / ".credentials.json"
        if p.exists():
            d = json.loads(p.read_text()).get("claudeAiOauth", {})
            if d.get("accessToken"):
                return d["accessToken"], int(d.get("expiresAt") or 0)
    except Exception:
        pass
    return None, 0


def _fetch_claude_usage() -> dict:
    """Fetch subscription usage from Claude Code's OAuth usage endpoint. The
    `limits` array is model-agnostic — session (5h) + weekly, plus per-model
    `weekly_scoped` entries carrying scope.model.display_name — so the UI reads
    it the same regardless of which of the models is in use."""
    token, exp = _claude_oauth_token()
    if not token:
        return {"available": False, "reason": "No Claude subscription token on this host"}
    if exp and int(time.time() * 1000) > exp:
        return {"available": False, "reason": "Token expired — run any Claude command to refresh it"}
    try:
        req = urllib.request.Request(
            "https://api.anthropic.com/api/oauth/usage",
            headers={"Authorization": f"Bearer {token}",
                     "anthropic-beta": "oauth-2025-04-20",
                     "anthropic-version": "2023-06-01"})
        with urllib.request.urlopen(req, timeout=10, context=_push_ssl_context()) as resp:
            data = json.loads(resp.read().decode())
        data["available"] = True
        return data
    except urllib.error.HTTPError as e:
        if e.code == 401:
            return {"available": False, "reason": "Token rejected (401) — run any Claude command to refresh it"}
        return {"available": False, "reason": f"Usage fetch failed (HTTP {e.code})"}
    except Exception as e:
        return {"available": False, "reason": f"Usage fetch failed: {e}"}


def _claude_oneshot(prompt: str, model: str = "haiku", timeout: int = 35) -> tuple:
    """Run a one-shot headless `claude -p` query using the active Claude Code
    session's auth — Plan OAuth or API key, whichever the CLI is configured with.

    Returns (text, error). Mirrors amux's session launch: when on a Plan, the
    ANTHROPIC_API_KEY is unset so the subscription is used rather than a key.
    """
    claude_bin = _resolve_claude_bin()
    if not claude_bin:
        return ("", "claude CLI not found")
    env = dict(os.environ)
    env.pop("CLAUDECODE", None)
    env.pop("CLAUDE_CODE_ENTRYPOINT", None)
    if _on_claude_plan():
        env.pop("ANTHROPIC_API_KEY", None)
    try:
        r = subprocess.run(
            [claude_bin, "-p", prompt, "--model", model],
            capture_output=True, text=True, timeout=timeout,
            cwd=str(CC_HOME), env=env)
        if r.returncode != 0:
            return ("", (r.stderr or r.stdout or "claude exited non-zero").strip()[:500])
        return (r.stdout.strip(), "")
    except subprocess.TimeoutExpired:
        return ("", "lookup timed out")
    except Exception as e:
        return ("", str(e))


# Peek "Look up" should ride whatever provider the peeked session already uses,
# on that provider's fastest/lightest model — so a Gemini- or Ollama-only setup
# doesn't need an Anthropic key just to explain a snippet. Not the session's own
# (possibly heavy) model: the point is a cheap, snappy answer.
_PROVIDER_LOOKUP_MODEL = {
    "claude": "haiku",
    "gemini": "gemini-2.5-flash-lite",
    "codex":  "gpt-5-mini",
}


def _session_provider(name: str) -> str:
    if not name:
        return "claude"
    try:
        cfg = parse_env_file(CC_SESSIONS / f"{name}.env")
        return (cfg.get("CC_PROVIDER") or "claude").strip().lower() or "claude"
    except Exception:
        return "claude"


def _session_model_flag(name: str) -> str:
    try:
        cfg = parse_env_file(CC_SESSIONS / f"{name}.env")
        m = re.search(r'(?:--model|-m)\s+(\S+)', cfg.get("CC_FLAGS", "") or "")
        return m.group(1) if m else ""
    except Exception:
        return ""


def _ollama_first_model() -> str:
    """Smallest sensible default: the first model `ollama list` reports."""
    try:
        ob = shutil.which("ollama")
        if not ob:
            return ""
        r = subprocess.run([ob, "list"], capture_output=True, text=True, timeout=5)
        for line in r.stdout.splitlines()[1:]:
            parts = line.split()
            if parts:
                return parts[0]
    except Exception:
        pass
    return ""


def _lookup_via_claude(prompt: str, timeout: int = 35) -> tuple:
    """Claude haiku one-shot — SDK when an API key is present and not on a Plan,
    else the claude CLI (OAuth subscription). This is the universal fallback."""
    api_key = os.environ.get("ANTHROPIC_API_KEY", "")
    if api_key and not _on_claude_plan():
        try:
            import anthropic as _anthropic
            client = _anthropic.Anthropic(api_key=api_key)
            msg = client.messages.create(
                model="claude-haiku-4-5-20251001", max_tokens=400,
                messages=[{"role": "user", "content": prompt}],
            )
            return (msg.content[0].text.strip(), "")
        except Exception as e:
            return ("", str(e))
    return _claude_oneshot(prompt, model="haiku", timeout=timeout)


def _lookup_via_provider(provider: str, prompt: str, name: str = "", timeout: int = 35) -> tuple:
    """Try the session provider's fastest model via its CLI. Returns (text, err);
    empty text means the caller should fall back to _lookup_via_claude. codex and
    unknown providers fall straight through (codex exec is agentic/verbose — no
    clean one-shot completion, so we don't parse it here)."""
    try:
        if provider == "gemini":
            gem = shutil.which("gemini")
            if gem:
                env = dict(os.environ)
                env["GEMINI_CLI_TRUST_WORKSPACE"] = "true"
                env.pop("CLAUDECODE", None)
                env.pop("CLAUDE_CODE_ENTRYPOINT", None)
                r = subprocess.run(
                    [gem, "-p", prompt, "-m", _PROVIDER_LOOKUP_MODEL["gemini"]],
                    capture_output=True, text=True, timeout=timeout, cwd=str(CC_HOME), env=env)
                if r.returncode == 0 and r.stdout.strip():
                    return (r.stdout.strip(), "")
        elif provider == "ollama":
            ob = shutil.which("ollama")
            model = _session_model_flag(name) or _ollama_first_model()
            if ob and model:
                r = subprocess.run(
                    [ob, "run", model, prompt],
                    capture_output=True, text=True, timeout=timeout, cwd=str(CC_HOME))
                if r.returncode == 0 and r.stdout.strip():
                    return (r.stdout.strip(), "")
    except Exception:
        pass
    return ("", "")   # fall back to claude


def _bu_agent_run(task: str, session: str = "amux-agent", profile: str = "default",
                  start_url: str = "", max_iterations: int = 25,
                  model: str = "claude-sonnet-4-5") -> dict:
    """Run an Anthropic Computer Use agent loop driving the browser-use Playwright session.

    The model takes screenshots, decides actions, and we execute them via _bu_call.
    Default model is Sonnet 4.5 because computer use is canonically a Sonnet feature;
    pass model='claude-opus-4-6' or similar to override.
    """
    try:
        import anthropic
    except ImportError:
        return {"error": "anthropic package not installed (pip install anthropic)"}
    import base64

    # Ensure session is open
    if profile and start_url:
        _bu_call(["-b", "real", "--profile", profile, "open", start_url], session=session, timeout_s=30)
    elif profile:
        _bu_call(["-b", "real", "--profile", profile, "open", "about:blank"], session=session, timeout_s=30)
    elif start_url:
        _bu_call(["open", start_url], session=session, timeout_s=30)
    else:
        _bu_call(["open", "about:blank"], session=session, timeout_s=30)

    DISPLAY_W, DISPLAY_H = 1280, 800

    # Computer Use requires a real Anthropic API key — there is NO Plan/OAuth path
    # for it (unlike the lookup/task-label CLI shots, which ride the subscription).
    # This machine runs the claude CLI on OAuth with ANTHROPIC_API_KEY unset, so a
    # bare anthropic.Anthropic() 401s at call time with an opaque error (gtm-videos
    # hit this on /record, 2026-07-14). Read a DEDICATED key so the browser agent
    # can be enabled without setting the global ANTHROPIC_API_KEY — which would
    # switch every claude session, the lookup, and task-labels to per-token API
    # billing instead of the Plan subscription. Fail loud and actionable otherwise.
    _bu_key = os.environ.get("AMUX_ANTHROPIC_API_KEY") or os.environ.get("ANTHROPIC_API_KEY")
    if not _bu_key:
        return {"error": "browser agent needs an Anthropic API key",
                "detail": "Computer Use has no Plan/OAuth path. Set AMUX_ANTHROPIC_API_KEY "
                          "in ~/.amux/server.env (a key scoped to the browser agent only — this "
                          "does NOT switch your claude sessions to API-key billing), then "
                          "`touch amux-server.py`. Until then, drive the browser with the "
                          "raw browser API / Playwright (/api/browser/*), which uses your saved "
                          "auth profiles and needs no model key."}
    try:
        client = anthropic.Anthropic(api_key=_bu_key)
    except Exception as e:
        return {"error": f"failed to init Anthropic client: {e}"}

    def _shot_b64():
        s = _bu_screenshot(session=session)
        p = s.get("path", "")
        if not p or not Path(p).exists():
            return None, None, f"screenshot failed: {s}"
        try:
            data = Path(p).read_bytes()
            # Detect media type from magic bytes (browser-use may write PNG to .jpg path)
            if data[:8] == b"\x89PNG\r\n\x1a\n":
                media = "image/png"
            elif data[:3] == b"\xff\xd8\xff":
                media = "image/jpeg"
            elif data[:6] in (b"GIF87a", b"GIF89a"):
                media = "image/gif"
            elif data[:4] == b"RIFF" and data[8:12] == b"WEBP":
                media = "image/webp"
            else:
                media = "image/png"
            return base64.standard_b64encode(data).decode(), media, None
        except Exception as e:
            return None, None, str(e)

    def _exec_action(inp):
        a = inp.get("action", "")
        coord = inp.get("coordinate") or [0, 0]
        x, y = (coord + [0, 0])[:2]
        text = inp.get("text", "")
        try:
            if a == "screenshot":
                pass
            elif a == "left_click":
                _bu_call(["click", str(int(x)), str(int(y))], session=session)
            elif a == "double_click":
                _bu_call(["click", str(int(x)), str(int(y))], session=session)
                time.sleep(0.1)
                _bu_call(["click", str(int(x)), str(int(y))], session=session)
            elif a == "triple_click":
                for _ in range(3):
                    _bu_call(["click", str(int(x)), str(int(y))], session=session)
                    time.sleep(0.05)
            elif a == "right_click":
                _bu_call(["eval",
                    f"(()=>{{const el=document.elementFromPoint({int(x)},{int(y)});"
                    f"if(el)el.dispatchEvent(new MouseEvent('contextmenu',{{bubbles:true,clientX:{int(x)},clientY:{int(y)}}}));}})()"
                ], session=session)
            elif a == "middle_click":
                _bu_call(["click", str(int(x)), str(int(y))], session=session)
            elif a == "type":
                _bu_call(["type", text], session=session)
            elif a == "key":
                _bu_call(["keys", text], session=session)
            elif a == "scroll":
                direction = inp.get("scroll_direction", "down")
                amount = max(1, int(inp.get("scroll_amount", 3))) * 100
                _bu_call(["scroll", direction, "--amount", str(amount)], session=session)
            elif a == "wait":
                time.sleep(min(float(inp.get("duration", 1)), 10))
            elif a in ("mouse_move", "left_mouse_down", "left_mouse_up", "cursor_position", "hold_key"):
                pass  # no-op (browser-use doesn't expose hover/drag)
            else:
                return {"is_error": True, "text": f"unsupported action: {a}"}
        except Exception as e:
            return {"is_error": True, "text": f"action {a} failed: {e}"}
        b64, media, err = _shot_b64()
        if err:
            return {"is_error": True, "text": err}
        return {"image_b64": b64, "media": media}

    tools = [{
        "type": "computer_20250124",
        "name": "computer",
        "display_width_px": DISPLAY_W,
        "display_height_px": DISPLAY_H,
    }]
    messages = [{"role": "user", "content": task}]
    action_log = []
    final_text = ""
    iterations = 0

    for it in range(max_iterations):
        iterations = it + 1
        try:
            resp = client.beta.messages.create(
                model=model,
                max_tokens=4096,
                tools=tools,
                messages=messages,
                betas=["computer-use-2025-01-24"],
            )
        except Exception as e:
            return {"error": f"anthropic call failed: {e}", "iterations": iterations, "log": action_log}

        # Re-serialize content blocks to plain dicts so we can append
        assistant_content = []
        tool_uses = []
        for block in resp.content:
            try:
                d = block.model_dump(exclude_none=True)
            except Exception:
                d = {"type": getattr(block, "type", "unknown")}
            assistant_content.append(d)
            if block.type == "text":
                final_text = block.text
                action_log.append({"type": "text", "text": block.text[:500]})
            elif block.type == "tool_use":
                tool_uses.append(block)
                action_log.append({"type": "tool_use", "name": block.name, "input": block.input})
        messages.append({"role": "assistant", "content": assistant_content})

        if resp.stop_reason == "end_turn" or not tool_uses:
            break

        results = []
        for tu in tool_uses:
            r = _exec_action(tu.input)
            content = []
            if r.get("image_b64"):
                content.append({
                    "type": "image",
                    "source": {"type": "base64", "media_type": r.get("media", "image/png"), "data": r["image_b64"]},
                })
            if r.get("text"):
                content.append({"type": "text", "text": r["text"]})
            tr = {"type": "tool_result", "tool_use_id": tu.id, "content": content}
            if r.get("is_error"):
                tr["is_error"] = True
            results.append(tr)
        messages.append({"role": "user", "content": results})

    return {
        "success": True,
        "result": final_text,
        "iterations": iterations,
        "stop_reason": getattr(resp, "stop_reason", None),
        "log": action_log,
    }

# ── Terminal (PTY) session management ─────────────────────────────────────────
import pty
import fcntl
import struct
import select
import signal

_terminals: dict[str, dict] = {}  # id -> {pid, fd, created, host, cols, rows}
_term_lock = threading.Lock()

def _term_create(host: str = "", cols: int = 120, rows: int = 40) -> dict:
    """Spawn a PTY shell (local or SSH)."""
    env = os.environ.copy()
    env["TERM"] = "xterm-256color"
    env["COLORTERM"] = "truecolor"
    env["LANG"] = env.get("LANG", "en_US.UTF-8")

    if host and host != "local":
        # SSH to remote host
        cmd = ["ssh", "-o", "StrictHostKeyChecking=accept-new",
               "-o", "ServerAliveInterval=30", "-t", host]
    else:
        # Local shell
        shell = os.environ.get("SHELL", "/bin/bash")
        cmd = [shell, "-l"]

    pid, fd = pty.fork()
    if pid == 0:
        # Child — exec the command
        os.execvpe(cmd[0], cmd, env)
    else:
        # Parent — set terminal size
        fcntl.ioctl(fd, termios_TIOCSWINSZ, struct.pack("HHHH", rows, cols, 0, 0))
        # Make fd non-blocking
        flags = fcntl.fcntl(fd, fcntl.F_GETFL)
        fcntl.fcntl(fd, fcntl.F_SETFL, flags | os.O_NONBLOCK)

        tid = f"term-{uuid.uuid4().hex[:8]}"
        with _term_lock:
            _terminals[tid] = {
                "pid": pid, "fd": fd, "created": int(time.time()),
                "host": host or "local", "cols": cols, "rows": rows,
            }
        return {"id": tid, "host": host or "local", "cols": cols, "rows": rows}

# TIOCSWINSZ constant
try:
    import termios
    termios_TIOCSWINSZ = termios.TIOCSWINSZ
except (ImportError, AttributeError):
    termios_TIOCSWINSZ = 0x5414  # Linux default

def _term_read(tid: str, max_bytes: int = 65536) -> bytes:
    """Read available output from terminal."""
    with _term_lock:
        t = _terminals.get(tid)
    if not t:
        return b""
    fd = t["fd"]
    try:
        ready, _, _ = select.select([fd], [], [], 0.05)
        if ready:
            return os.read(fd, max_bytes)
    except (OSError, IOError):
        pass
    return b""

def _term_read_wait(tid: str, timeout: float, max_bytes: int = 262144) -> bytes:
    """Long-poll read: block up to `timeout`s for the FIRST output byte, then
    briefly coalesce a burst (e.g. a screen redraw) into one response. Returns
    the instant the PTY produces data, so the client gets near-real-time output
    instead of waiting out a fixed polling interval. Empty bytes on timeout.
    """
    with _term_lock:
        t = _terminals.get(tid)
    if not t:
        return b""
    fd = t["fd"]
    try:
        ready, _, _ = select.select([fd], [], [], max(0.0, timeout))
        if not ready:
            return b""
        chunks: list[bytes] = []
        total = 0
        # Drain what's available, coalescing a short burst to cut round-trips.
        while total < max_bytes:
            try:
                buf = os.read(fd, 65536)
            except (OSError, IOError):
                break
            if not buf:
                break
            chunks.append(buf)
            total += len(buf)
            more, _, _ = select.select([fd], [], [], 0.015)
            if not more:
                break
        return b"".join(chunks)
    except (OSError, IOError):
        return b""


def _term_write(tid: str, data: bytes):
    """Write input to terminal."""
    with _term_lock:
        t = _terminals.get(tid)
    if not t:
        return
    try:
        os.write(t["fd"], data)
    except (OSError, IOError):
        pass

def _term_resize(tid: str, cols: int, rows: int):
    """Resize terminal."""
    with _term_lock:
        t = _terminals.get(tid)
    if not t:
        return
    try:
        fcntl.ioctl(t["fd"], termios_TIOCSWINSZ, struct.pack("HHHH", rows, cols, 0, 0))
        t["cols"] = cols
        t["rows"] = rows
        # Send SIGWINCH to the process group
        os.kill(t["pid"], signal.SIGWINCH)
    except (OSError, IOError):
        pass

def _term_destroy(tid: str):
    """Kill terminal session."""
    with _term_lock:
        t = _terminals.pop(tid, None)
    if not t:
        return
    try:
        os.kill(t["pid"], signal.SIGHUP)
    except (OSError, ProcessLookupError):
        pass
    try:
        os.close(t["fd"])
    except OSError:
        pass
    try:
        os.waitpid(t["pid"], os.WNOHANG)
    except (ChildProcessError, OSError):
        pass

def _term_alive(tid: str) -> bool:
    """Check if terminal process is still running."""
    with _term_lock:
        t = _terminals.get(tid)
    if not t:
        return False
    try:
        pid, status = os.waitpid(t["pid"], os.WNOHANG)
        return pid == 0  # 0 means still running
    except (ChildProcessError, OSError):
        return False


# SSE shared cache — avoids redundant subprocess calls when multiple tabs connect
_sse_cache = {
    "sessions": {"data": None, "json": "", "time": 0},
    "board": {"data": None, "json": "", "time": 0},
}
_sse_cache_lock = threading.Lock()  # prevents thundering herd on cache refresh
_SSE_CACHE_TTL = 2  # seconds

# ── Structured event log (in-memory ring buffer, 2 000 events) ─────────────────
import collections
_event_log: "collections.deque[dict]" = collections.deque(maxlen=2000)
_event_log_lock = threading.Lock()
_req_tl = threading.local()  # per-request enrichment (set by handlers, read by _route)

def _emit_http_event(etype: str, action: str, target: str = "", session: str = "",
                     detail: str = "", status: int = 200, ip: str = "") -> None:
    # Don't emit semantic events (e.g. message-sent, started) for failed requests.
    # Downgrade to a plain http event so they don't spam the event log as false positives.
    if status >= 400 and etype != "http":
        etype = "http"
        action = action  # keep as-is for http type
    with _event_log_lock:
        _event_log.append({
            "ts": time.time(),
            "type": etype,
            "action": action,
            "target": target,
            "session": session,
            "detail": detail,
            "status": status,
            "ip": ip,
        })

def _classify_request(method: str, path: str) -> tuple:
    """Returns (type, action, target, session) from method+path."""
    # Board
    if path == "/api/board" and method == "POST":
        return ("board", "created", "", "")
    m = re.match(r"^/api/board/([A-Za-z0-9-]+)$", path)
    if m:
        iid = m.group(1)
        if method == "PATCH":   return ("board", "updated",  iid, "")
        if method == "DELETE":  return ("board", "deleted",  iid, "")
    m = re.match(r"^/api/board/([A-Za-z0-9-]+)/claim$", path)
    if m and method == "POST":
        return ("board", "claimed", m.group(1), "")
    if path == "/api/board/clear-done" and method == "POST":
        return ("board", "cleared", "done", "")
    if path == "/api/board/statuses" and method == "POST":
        return ("board", "status-added", "", "")
    m = re.match(r"^/api/board/statuses/([a-z0-9-]+)$", path)
    if m:
        sid = m.group(1)
        if method == "DELETE": return ("board", "status-removed", sid, "")
        if method == "PATCH":  return ("board", "status-renamed", sid, "")
    # Sessions
    if path == "/api/sessions" and method == "POST":
        return ("session", "created", "", "")
    m = re.match(r"^/api/sessions/([^/]+)/([^/]+)$", path)
    if m:
        sname, sub = m.group(1), m.group(2)
        if method == "POST"  and sub == "start":   return ("session", "started",      sname, sname)
        if method == "POST"  and sub == "stop":    return ("session", "stopped",      sname, sname)
        if method == "POST"  and sub == "send":    return ("session", "message-sent", sname, sname)
        if method == "POST"  and sub == "steer":   return ("session", "steered",      sname, sname)
        if method == "DELETE"and sub == "steer":   return ("session", "steer-cleared",sname, sname)
        if method == "POST"  and sub == "archive": return ("session", "archived",     sname, sname)
        if method == "POST"  and sub == "wake":    return ("session", "woken",        sname, sname)
        if method == "PATCH" and sub == "config":  return ("session", "configured",   sname, sname)
        if method == "DELETE":                     return ("session", "deleted",       sname, sname)
        if method == "POST"  and sub == "memory":  return ("memory",  "updated",      sname, sname)
        if method == "POST"  and sub == "peek":    return ("session", "peeked",       sname, sname)
    m = re.match(r"^/api/sessions/([^/]+)$", path)
    if m:
        sname = m.group(1)
        if method == "DELETE": return ("session", "deleted", sname, sname)
        if method == "PATCH":  return ("session", "updated", sname, sname)
    # Memory
    if path == "/api/memory/global" and method == "POST":
        return ("memory", "updated", "global", "")
    # Uploads
    if path.startswith("/api/uploads") and method == "POST":
        return ("file", "uploaded", "", "")
    if path == "/api/fs/upload" and method == "POST":
        return ("file", "uploaded", "", "")
    if path == "/api/fs/delete" and method == "DELETE":
        return ("file", "deleted", "", "")
    # System
    if path == "/api/pull" and method == "POST":
        return ("system", "pull", "repo", "")
    # Generic reads (low-priority)
    if method == "GET":
        return ("http", "get", path, "")
    action_map = {"POST": "post", "PATCH": "patch", "DELETE": "delete"}
    return ("http", action_map.get(method, method.lower()), path, "")

# Auto-recovery state
_sse_alerts: list = []           # ring buffer of alert dicts pushed to all SSE clients
_notes_version: int = 0             # bumped on any notes write; triggers SSE invalidation
_crm_version: int = 0               # bumped on any CRM write; triggers SSE invalidation
_journal_version: int = 0           # bumped on any journal write; triggers SSE invalidation
_sse_alert_lock = threading.Lock()
_send_locks: dict = {}          # per-session locks for serializing send_text/send_keys
_send_locks_lock = threading.Lock()  # protects _send_locks dict itself
_session_locks: dict = {}           # per-session RLocks for stop/start serialization
_session_locks_init = threading.Lock()  # protects _session_locks dict itself

_VALID_CC_SESSION_NAME = re.compile(r'^[a-zA-Z0-9][a-zA-Z0-9_.\-]*$')
_stop_pool = __import__("concurrent.futures", fromlist=["ThreadPoolExecutor"]).ThreadPoolExecutor(max_workers=4)
_USER_SHELL = os.environ.get("SHELL", "/bin/bash")
_session_auto_actions: dict = {} # {name: {"last_compact": ts, "last_restart": ts}}
_steering_queue: dict = {}      # {session_name: [{"text": str, "queued_at": float, "id": str}]}
_steering_lock = threading.Lock()


def _get_session_lock(name: str) -> threading.RLock:
    with _session_locks_init:
        if name not in _session_locks:
            _session_locks[name] = threading.RLock()
        return _session_locks[name]


def _find_claude_pid(name: str) -> int:
    """Find Claude's PID as a child of the tmux pane's shell process."""
    try:
        r = subprocess.run(["tmux", "list-panes", "-t", tmux_target(name), "-F", "#{pane_pid}"],
                           capture_output=True, text=True, timeout=5)
        if r.returncode != 0 or not r.stdout.strip():
            return 0
        shell_pid = r.stdout.strip().split("\n")[0]
        r2 = subprocess.run(["pgrep", "-P", shell_pid, "-x", "claude"],
                            capture_output=True, text=True, timeout=5)
        if r2.stdout.strip():
            pid = int(r2.stdout.strip().split("\n")[0])
            return pid if pid > 1 else 0
        # Fallback: check any child (claude might be named differently)
        r3 = subprocess.run(["pgrep", "-P", shell_pid],
                            capture_output=True, text=True, timeout=5)
        for line in r3.stdout.strip().split("\n"):
            if not line.strip():
                continue
            cpid = int(line.strip())
            sf = Path.home() / ".claude" / "sessions" / f"{cpid}.json"
            if sf.exists():
                return cpid
        return 0
    except Exception:
        return 0


def _read_claude_session_name(claude_pid: int) -> str:
    """Read the session name from Claude's PID-keyed session file."""
    if claude_pid <= 1:
        return ""
    sf = Path.home() / ".claude" / "sessions" / f"{claude_pid}.json"
    try:
        if not sf.is_file() or sf.stat().st_size > 1_000_000:
            return ""
        data = json.loads(sf.read_text(errors="replace"))
        return data.get("name", "")
    except Exception:
        return ""


def _validate_cc_session_name(name: str) -> bool:
    return bool(name and len(name) <= 64 and _VALID_CC_SESSION_NAME.match(name))


def _cc_session_exists_in_project(session_name: str, work_dir: str) -> bool:
    """Check if a Claude Code session with this name exists in the project directory."""
    proj_dir = CLAUDE_HOME / "projects" / _project_name(work_dir)
    if not proj_dir.is_dir():
        return False
    try:
        for jf in proj_dir.glob("*.jsonl"):
            try:
                first_line = jf.open().readline()
                if not first_line:
                    continue
                rec = json.loads(first_line)
                if rec.get("customTitle") == session_name or rec.get("sessionName") == session_name:
                    return True
            except Exception:
                continue
    except Exception:
        pass
    return False


def _cc_session_id_for_name(session_name: str, work_dir: str) -> str:
    """Return the UUID of a uniquely-named Claude Code session, or '' if ambiguous/missing.

    When exactly one session matches, return its UUID so we can --resume <uuid>
    (which bypasses the interactive picker). When multiple match, return '' to
    force a fresh --name start instead of opening the picker."""
    proj_dir = CLAUDE_HOME / "projects" / _project_name(work_dir)
    if not proj_dir.is_dir():
        return ""
    matches = []
    try:
        for jf in proj_dir.glob("*.jsonl"):
            try:
                first_line = jf.open().readline()
                if not first_line:
                    continue
                rec = json.loads(first_line)
                if rec.get("customTitle") == session_name or rec.get("sessionName") == session_name:
                    sid = rec.get("sessionId", jf.stem)
                    matches.append(sid)
            except Exception:
                continue
    except Exception:
        pass
    return matches[0] if len(matches) == 1 else ""


# Per-session token cache — refreshed every 30s, keyed by resolved dir
_token_cache = {"data": {}, "timestamps": {}, "time": 0}
_TOKEN_CACHE_TTL = 120

def _refresh_token_cache():
    """Rebuild per-directory token counts and last-activity timestamps from Claude JSONL files."""
    now = time.time()
    if now - _token_cache["time"] < _TOKEN_CACHE_TTL:
        return
    from datetime import datetime
    result = {}
    ts_result = {}
    projects_dir = Path.home() / ".claude" / "projects"
    if not projects_dir.is_dir():
        _token_cache["data"] = result
        _token_cache["timestamps"] = ts_result
        _token_cache["time"] = now
        return
    # Only scan project dirs that registered sessions actually use
    needed_proj_keys = set()
    if CC_SESSIONS.is_dir():
        for f in CC_SESSIONS.glob("*.env"):
            cfg = parse_env_file(f)
            raw_dir = cfg.get("CC_DIR", "")
            if raw_dir:
                needed_proj_keys.add(_project_name(raw_dir))
    for proj_dir in projects_dir.iterdir():
        if not proj_dir.is_dir():
            continue
        if needed_proj_keys and proj_dir.name not in needed_proj_keys:
            continue
        # Find most recent JSONL
        jsonl_files = sorted(proj_dir.glob("*.jsonl"), key=lambda f: f.stat().st_mtime, reverse=True)
        if not jsonl_files:
            continue
        dir_total = 0
        last_ts = 0
        # Read tail of top 5 most recent JSONL files to cover multiple conversations
        for jf in jsonl_files[:5]:
            file_total = 0
            file_last_ts = 0
            try:
                size = jf.stat().st_size
                with jf.open("rb") as fh:
                    offset = max(0, size - 200_000)
                    if offset > 0:
                        fh.seek(offset)
                        fh.readline()  # skip partial line
                    prev_sig = None
                    for raw_line in fh:
                        try:
                            entry = json.loads(raw_line)
                            # Track last Claude API call timestamp
                            ts_str = entry.get("timestamp", "")
                            if ts_str:
                                try:
                                    ts_unix = int(datetime.fromisoformat(
                                        ts_str.replace("Z", "+00:00")
                                    ).timestamp())
                                    if ts_unix > last_ts:
                                        last_ts = ts_unix
                                    if ts_unix > file_last_ts:
                                        file_last_ts = ts_unix
                                except Exception:
                                    pass
                            usage = entry.get("message", {}).get("usage", {})
                            if usage:
                                sig = (usage.get("input_tokens", 0),
                                       usage.get("cache_read_input_tokens", 0),
                                       usage.get("output_tokens", 0))
                                if sig == prev_sig:
                                    continue
                                prev_sig = sig
                                t = (usage.get("input_tokens", 0)
                                     + usage.get("cache_read_input_tokens", 0)
                                     + usage.get("cache_creation_input_tokens", 0)
                                     + usage.get("output_tokens", 0))
                                file_total += t
                                dir_total += t
                            else:
                                prev_sig = None
                        except (json.JSONDecodeError, AttributeError):
                            continue
            except Exception:
                continue
            # Store per-conversation-ID totals so sessions with cc_conversation_id
            # can look up their own JSONL directly (avoids sharing counts when
            # multiple sessions share the same CC_DIR).
            conv_id = jf.stem  # JSONL filename = Claude session UUID
            result[(proj_dir.name, conv_id)] = file_total
            if file_last_ts:
                ts_result[(proj_dir.name, conv_id)] = file_last_ts
        if dir_total > 0:
            result[proj_dir.name] = dir_total
        if last_ts > 0:
            ts_result[proj_dir.name] = last_ts
    _token_cache["data"] = result
    _token_cache["timestamps"] = ts_result
    _token_cache["time"] = now

# ═══════════════════════════════════════════
# SESSION FILE HELPERS
# ═══════════════════════════════════════════

def parse_env_file(path: Path) -> dict:
    """Parse a amux session .env file into a dict."""
    data = {}
    for line in path.read_text().splitlines():
        line = line.strip()
        if not line or line.startswith("#"):
            continue
        m = re.match(r'^(\w+)="(.*)"$', line)
        if m:
            data[m.group(1)] = m.group(2)
            continue
        m = re.match(r"^(\w+)='(.*)'$", line)
        if m:
            data[m.group(1)] = m.group(2)
            continue
        m = re.match(r"^(\w+)=(.*)$", line)
        if m:
            data[m.group(1)] = m.group(2)
    return data


def _atomic_write_secure(path: Path, content: str) -> None:
    """Atomically and durably write content to path with mode 0o600.

    Uses NamedTemporaryFile (which calls mkstemp under the hood, defaulting
    to mode 0o600) plus flush + fsync + os.replace for a crash-safe atomic
    write. The result file at `path` never exists with permissions other
    than 0o600 — even briefly. After this function returns successfully,
    the data is durably persisted to disk: a system crash cannot leave
    `path` empty or partially-written.

    Use this for any .env file that may contain secrets or per-user config.
    """
    import tempfile
    dir_path = str(path.parent)
    with tempfile.NamedTemporaryFile(
        mode="w",
        encoding="utf-8",
        dir=dir_path,
        prefix=f".{path.name}.",
        suffix=".tmp",
        delete=False,
    ) as tmp:
        tmp.write(content)
        # Flush Python's userspace buffer to the OS kernel buffer, then
        # flush the kernel buffer to disk. Without this, a system crash
        # after os.replace() could leave the file at `path` with empty
        # or stale contents — the rename succeeded but the data wasn't
        # yet persisted. fsync is the canonical durability barrier.
        tmp.flush()
        os.fsync(tmp.fileno())
        tmp_path = tmp.name
    try:
        os.replace(tmp_path, str(path))
    except Exception:
        try:
            os.unlink(tmp_path)
        except FileNotFoundError:
            pass
        raise


def _write_env(path: Path, cfg: dict):
    """Write a cfg dict back to a amux .env file with secure permissions.

    Uses _atomic_write_secure to ensure the file is created with mode 0o600,
    preventing world-readable .env files that may contain secrets like
    ANTHROPIC_API_KEY or per-session credentials.
    """
    lines = [f'# updated: {__import__("datetime").datetime.now().isoformat()}']
    for k, v in cfg.items():
        lines.append(f'{k}="{v}"')
    _atomic_write_secure(path, "\n".join(lines) + "\n")


def _blocked_session_names() -> set[str]:
    """Return session names quarantined from create/start/wake/auto-resume."""
    try:
        names = set()
        for line in CC_BLOCKED_SESSIONS.read_text().splitlines():
            line = line.strip()
            if line and not line.startswith("#"):
                names.add(line)
        return names
    except FileNotFoundError:
        return set()
    except Exception:
        return set()


def _is_session_blocked(name: str) -> bool:
    return name in _blocked_session_names()


# ═══════════════════════════════════════════
# TMUX HELPERS
# ═══════════════════════════════════════════

_tmux_name_migrated = set()  # Sessions already checked for legacy name migration

def tmux_name(session: str) -> str:
    new = f"amux-{session}"
    # Only check for legacy cmux-*/cc-* names once per session per process lifetime
    if session not in _tmux_name_migrated:
        _tmux_name_migrated.add(session)
        for old in [f"cmux-{session}", f"cc-{session}"]:
            try:
                r = subprocess.run(["tmux", "has-session", "-t", old], capture_output=True, timeout=3)
                if r.returncode == 0:
                    subprocess.run(["tmux", "rename-session", "-t", old, new], capture_output=True, timeout=5)
                    break
            except Exception:
                pass
    return new


def tmux_target(session: str) -> str:
    """Return the tmux target for -t flags."""
    return tmux_name(session)


def is_running(session: str) -> bool:
    """Check if Claude is running in this session's tmux pane."""
    iterm2_id = _session_iterm2_id(session)
    if iterm2_id:
        return _iterm2_session_exists(iterm2_id)
    try:
        r = subprocess.run(
            ["tmux", "list-sessions", "-F", "#{session_name}"],
            capture_output=True, text=True,
        )
        tmux_sess = tmux_name(session)
        if tmux_sess not in r.stdout.splitlines():
            return False
        # Tmux exists -- check if Claude is actually running (not at shell prompt)
        output = tmux_capture(session, 10)
        if not output:
            return True  # empty output but tmux exists -- assume running (startup)
        if _at_shell_prompt(output):
            return False
        # Terminal-based check can false-positive when Claude's status bar text
        # leaks into scrollback after a SIGKILL. Cross-check by verifying the
        # shell actually has a child process (Claude).
        try:
            r_pp = subprocess.run(
                ["tmux", "list-panes", "-t", tmux_sess, "-F", "#{pane_pid}"],
                capture_output=True, text=True, timeout=5)
            if r_pp.returncode == 0 and r_pp.stdout.strip():
                shell_pid = r_pp.stdout.strip().split("\n")[0]
                r_ch = subprocess.run(
                    ["pgrep", "-P", shell_pid],
                    capture_output=True, text=True, timeout=5)
                if not r_ch.stdout.strip():
                    return False
        except Exception:
            pass
        return True
    except FileNotFoundError:
        return False


def tmux_capture(session: str, lines: int = 500) -> str:
    iterm2_id = _session_iterm2_id(session)
    if iterm2_id:
        return _iterm2_capture(iterm2_id)
    try:
        r = subprocess.run(
            ["tmux", "capture-pane", "-t", tmux_target(session), "-p", "-e", "-S", f"-{lines}"],
            capture_output=True, text=True, timeout=5,
        )
        # Strip leading/trailing blank lines so content isn't cut off
        return r.stdout.strip()
    except Exception:
        return ""


# Canonical tmux window size for amux sessions. tmux's default `window-size
# latest` resizes a window to whatever client attached to it most recently —
# and a headless/scripted attach defaults to 80x24. Every width change makes
# Claude Code redraw its whole transcript reflowed and tmux rewrap scrollback,
# so the peek shows content "reformatted" at whatever width touched the
# session last (tables mangled at 80 cols, prose rewrapped mid-history).
try:
    _TMUX_COLS = int(os.environ.get("AMUX_TMUX_COLS", "220"))
except ValueError:
    _TMUX_COLS = 220
try:
    _TMUX_ROWS = int(os.environ.get("AMUX_TMUX_ROWS", "50"))
except ValueError:
    _TMUX_ROWS = 50


def _tmux_size_watchdog():
    """Restore DETACHED amux sessions to the canonical window size.

    A live human terminal always owns the size while attached (window-size
    latest); once every client detaches, drift is restored so all future
    turns render at a stable, wide width for the peek. resize-window flips
    the window to manual sizing, so 'latest' is reset right after to keep
    the next human attach working normally.
    """
    try:
        r = subprocess.run(
            ["tmux", "list-windows", "-a", "-F",
             "#{session_name}\t#{session_attached}\t#{window_width}\t#{window_height}"],
            capture_output=True, text=True, timeout=5,
        )
        if r.returncode != 0:
            return
        for line in r.stdout.splitlines():
            try:
                name, attached, w, h = line.split("\t")
            except ValueError:
                continue
            if not name.startswith("amux-") or attached != "0":
                continue
            if w == str(_TMUX_COLS) and h == str(_TMUX_ROWS):
                continue
            subprocess.run(["tmux", "resize-window", "-t", name,
                            "-x", str(_TMUX_COLS), "-y", str(_TMUX_ROWS)],
                           capture_output=True, timeout=5)
            subprocess.run(["tmux", "set-option", "-w", "-t", name,
                            "window-size", "latest"],
                           capture_output=True, timeout=5)
            slog(f"[tmux-size] {name}: {w}x{h} -> {_TMUX_COLS}x{_TMUX_ROWS} (detached drift restored)")
    except Exception:
        pass


def _tmux_alt_screen(session: str) -> bool:
    """True if the pane is in the alternate screen buffer (TUI mode, e.g. Claude
    Code). The alt buffer has NO scrollback, so capture-pane only ever returns
    the visible window — peek must fall back to the saved log for history."""
    iterm2_id = _session_iterm2_id(session)
    if iterm2_id:
        return False
    try:
        r = subprocess.run(
            ["tmux", "display-message", "-t", tmux_target(session), "-p", "#{alternate_on}"],
            capture_output=True, text=True, timeout=5,
        )
        return r.stdout.strip() == "1"
    except Exception:
        return False


_capture_cache: dict[str, tuple[int, str]] = {}  # session -> (activity_ts, output)


def _tmux_capture_batch(sessions: list, lines: int = 30,
                        activity: dict | None = None) -> dict:
    """Capture pane output for multiple sessions in parallel using threads.
    Returns {session_name: output_str}.

    When *activity* is provided (from _tmux_info_map()), sessions whose
    tmux activity timestamp hasn't changed since the last capture are served
    from _capture_cache, avoiding a subprocess fork per unchanged session.
    """
    if not sessions:
        return {}
    result = {}
    need_capture = []
    for name in sessions:
        if activity:
            act_ts = activity.get(tmux_name(name), {}).get("activity", 0)
            cached = _capture_cache.get(name)
            if cached and cached[0] == act_ts:
                result[name] = cached[1]
                continue
        need_capture.append(name)
    if need_capture:
        from concurrent.futures import ThreadPoolExecutor
        def _cap(name):
            return name, tmux_capture(name, lines)
        with ThreadPoolExecutor(max_workers=min(len(need_capture), 16)) as pool:
            for name, output in pool.map(_cap, need_capture):
                act_ts = activity.get(tmux_name(name), {}).get("activity", 0) if activity else 0
                _capture_cache[name] = (act_ts, output)
                result[name] = output
    return result


# ── iTerm2 integration (AppleScript via osascript) ────────────────────────────

def _iterm2_applescript(script: str, timeout: int = 8) -> str:
    """Run an AppleScript and return stdout, or '' on error."""
    try:
        r = subprocess.run(["osascript", "-e", script],
                           capture_output=True, text=True, timeout=timeout)
        return r.stdout.strip()
    except Exception:
        return ""


def _iterm2_list_panes() -> list:
    """Return list of dicts describing every open iTerm2 pane.
    Each dict: {id, name, tty, window, tab}"""
    script = """
tell application "iTerm2"
    set out to ""
    set wi to 0
    repeat with w in windows
        set ti to 0
        repeat with t in tabs of w
            repeat with s in sessions of t
                set out to out & (id of s) & "|" & (name of s) & "|" & (tty of s) & "|" & wi & "|" & ti & "\n"
            end repeat
            set ti to ti + 1
        end repeat
        set wi to wi + 1
    end repeat
    return out
end tell"""
    raw = _iterm2_applescript(script)
    panes = []
    for line in raw.splitlines():
        parts = line.split("|")
        if len(parts) >= 5:
            panes.append({"id": parts[0], "name": parts[1], "tty": parts[2],
                          "window": int(parts[3]), "tab": int(parts[4])})
    return panes


def _iterm2_capture(session_id: str) -> str:
    """Return the visible screen content of an iTerm2 pane by its session ID."""
    sid = session_id.replace('"', '')
    script = f"""
tell application "iTerm2"
    repeat with w in windows
        repeat with t in tabs of w
            repeat with s in sessions of t
                if (id of s) = "{sid}" then
                    return contents of s
                end if
            end repeat
        end repeat
    end repeat
    return ""
end tell"""
    return _iterm2_applescript(script, timeout=10)


def _iterm2_session_exists(session_id: str) -> bool:
    """Return True if the iTerm2 pane with this ID is still open."""
    return bool(_iterm2_capture(session_id))


def _iterm2_send(session_id: str, text: str) -> tuple[bool, str]:
    """Send text (followed by newline) to an iTerm2 pane."""
    sid = session_id.replace('"', '')
    # Write text to a temp file to avoid AppleScript quoting issues
    import tempfile as _tmp
    with _tmp.NamedTemporaryFile(mode='w', delete=False, suffix='.txt', encoding='utf-8') as f:
        f.write(text)
        tmp_path = f.name
    try:
        script = f"""
tell application "iTerm2"
    repeat with w in windows
        repeat with t in tabs of w
            repeat with s in sessions of t
                if (id of s) = "{sid}" then
                    set fileRef to open for access POSIX file "{tmp_path}"
                    set txt to read fileRef as «class utf8»
                    close access fileRef
                    tell s to write text txt
                    return "ok"
                end if
            end repeat
        end repeat
    end repeat
    return "not found"
end tell"""
        result = _iterm2_applescript(script, timeout=15)
        if result == "ok":
            return True, "sent"
        return False, result or "not found"
    finally:
        try:
            os.unlink(tmp_path)
        except Exception:
            pass


def _session_iterm2_id(name: str) -> str:
    """Return the stored iTerm2 session ID for an amux session, or ''."""
    env_file = CC_SESSIONS / f"{name}.env"
    if not env_file.exists():
        return ""
    return parse_env_file(env_file).get("CC_ITERM2_SESSION_ID", "").strip()


def _log_path(session: str) -> Path:
    return CC_LOGS / f"{session}.log"


_last_log_save: dict[str, float] = {}  # session -> monotonic time of last save
_LOG_SAVE_INTERVAL = 30  # seconds between saves per session

_peek_cache: dict[str, tuple[float, int, dict]] = {}  # session -> (monotonic_time, lines, response_dict)
_PEEK_CACHE_TTL = 2.5  # seconds — long enough that multiple clients share one cached result
# session -> the transcript string the last FULL peek response's history was built
# from. A live=1 poll trims its frame against this exact text, so the seam stays
# duplicate-free against the history the client is actually displaying — without
# re-rendering the 120KB transcript on every poll. Written only for peeked sessions.
_peek_transcript_cache: dict[str, str] = {}

_transcript_render_cache: dict[tuple, tuple[float, int, str]] = {}  # (path, max_chars) -> (mtime, size, rendered)
_jsonl_path_cache: dict[str, tuple[float, "Path | None"]] = {}  # session -> (monotonic, path)


def save_session_log(session: str, content: str, force: bool = False):
    """Append content to session log, trimming from the front when > MAX_LOG_BYTES.

    Throttled to once per _LOG_SAVE_INTERVAL seconds per session to avoid
    continuous 10MB read/write cycles when clients poll peek frequently.
    Pass force=True to bypass the throttle (e.g. on session stop).
    """
    if not content.strip():
        return
    now = time.monotonic()
    if not force:
        last = _last_log_save.get(session, 0)
        if now - last < _LOG_SAVE_INTERVAL:
            return
    _last_log_save[session] = now
    lp = _log_path(session)
    CC_LOGS.mkdir(parents=True, exist_ok=True)
    try:
        data = content.encode("utf-8", errors="replace")
        # Trim from front if combined size would exceed limit
        existing_size = lp.stat().st_size if lp.exists() else 0
        if existing_size + len(data) > MAX_LOG_BYTES:
            # Read existing, trim oldest bytes, append new
            existing = lp.read_bytes() if lp.exists() else b""
            combined = existing + data
            combined = combined[-MAX_LOG_BYTES:]
            lp.write_bytes(combined)
        else:
            with lp.open("ab") as f:
                f.write(data)
    except Exception:
        pass


def _alt_conv_lines(capture: str) -> tuple[list[str], list[str]]:
    """Split a Claude Code alt-screen capture into the conversation portion,
    trimming the trailing TUI chrome (spinner + task list, separator bars, the
    prompt box and the status bar, plus trailing blanks). Returns
    (orig_lines, plain_lines) for just the conversation — the chrome is volatile
    and re-drawn every capture, so it must not be accumulated into history."""
    orig = capture.splitlines()
    plain = [_STRIP_ANSI.sub("", l) for l in orig]
    n = len(orig)
    lo = max(0, n - 22)
    cut = n
    # If a spinner line (… ellipsis) sits in the bottom region, chrome begins at
    # the run of blank lines just above it (spinner + task list + footer below).
    for i in range(n - 1, lo - 1, -1):
        if "…" in plain[i]:
            j = i
            while j - 1 >= 0 and plain[j - 1].strip() == "":
                j -= 1
            cut = j
            break
    else:
        # Idle (no spinner): trim trailing separator bars / prompt / status / blanks.
        for i in range(n - 1, lo - 1, -1):
            p = plain[i].strip()
            bar_ct = sum(1 for c in p if c in "─━—-=")
            is_bar = len(p) >= 8 and (all(c in "─━—-=· " for c in p)
                                      or bar_ct >= len(p) * 0.5)
            if (p == "" or is_bar or "bypass permissions on" in p
                    or "for shortcuts" in p or p.startswith("❯")):
                cut = i
            else:
                break
    while cut > 0 and plain[cut - 1].strip() == "":
        cut -= 1
    return orig[:cut], plain[:cut]


def save_alt_capture(name: str, capture: str):
    """Append only the genuinely-new conversation lines from an alt-screen
    capture to the session log. Claude Code's alt buffer redraws the same
    viewport in place, so naively appending each capture stacks ~30 near-
    identical snapshots (repeated status bars, boot messages, 77% dupes). This
    trims the TUI chrome and de-duplicates the overlap with what's already
    saved, keeping the log a clean linear transcript. Throttled like
    save_session_log."""
    if not capture.strip():
        return
    now = time.monotonic()
    last = _last_log_save.get(name, 0)
    if now - last < _LOG_SAVE_INTERVAL:
        return
    # Only persist a STABLE frame. Capturing a redrawing alt-screen mid-stream
    # yields torn text (dropped chars/spaces) that can't be de-duplicated. Take
    # a couple of fresh captures a beat apart; if the pane is still changing,
    # bail WITHOUT bumping the throttle so the next poll retries once it settles.
    f1 = tmux_capture(name, 300)
    if not f1:
        return
    time.sleep(0.18)
    f2 = tmux_capture(name, 300)
    if not f2 or _STRIP_ANSI.sub("", f1) != _STRIP_ANSI.sub("", f2):
        return  # still rendering — wait for a quiet frame
    capture = f2
    conv_orig, conv_plain = _alt_conv_lines(capture)
    cnp = [p.rstrip() for p in conv_plain]
    if not any(p.strip() for p in cnp):
        return
    lp = _log_path(name)
    existing_tail = ""
    if lp.exists():
        try:
            size = lp.stat().st_size
            with lp.open("rb") as f:
                if size > 32_768:
                    f.seek(size - 32_768)
                existing_tail = f.read().decode("utf-8", errors="replace")
        except Exception:
            existing_tail = ""
    # Collapse blank runs in both sides before comparing — the log has already
    # been collapsed, but the alt-screen capture hasn't, so line counts diverge.
    def _collapse_lines(lines, orig_lines=None):
        out, out_orig = [], []
        blank = 0
        for i, l in enumerate(lines):
            if l.strip() == "":
                blank += 1
                if blank <= 1:
                    out.append(l)
                    if orig_lines is not None:
                        out_orig.append(orig_lines[i])
            else:
                blank = 0
                out.append(l)
                if orig_lines is not None:
                    out_orig.append(orig_lines[i])
        return (out, out_orig) if orig_lines is not None else (out, None)
    cnp, conv_orig_c = _collapse_lines(cnp, conv_orig)
    tailp_raw = [_STRIP_ANSI.sub("", l).rstrip() for l in existing_tail.splitlines()]
    tailp, _ = _collapse_lines(tailp_raw)
    # Longest prefix of the new conversation that already exists as a contiguous
    # block in the recent tail → append only the lines after it.
    k = 0
    maxk = min(len(cnp), 80)
    for cand in range(maxk, 0, -1):
        block = cnp[:cand]
        for st in range(len(tailp) - cand, -1, -1):
            if tailp[st:st + cand] == block:
                k = cand
                break
        if k:
            break
    new_lines = conv_orig_c[k:]
    _last_log_save[name] = now
    if not any(_STRIP_ANSI.sub("", l).strip() for l in new_lines):
        return  # nothing new since last save
    CC_LOGS.mkdir(parents=True, exist_ok=True)
    # Collapse the alt-screen's big empty band (input box anchored at the bottom)
    # so the log stays a tight transcript instead of accumulating blank gaps.
    chunk = (_collapse_blank_runs("\n".join(new_lines)) + "\n").encode("utf-8", errors="replace")
    try:
        existing_size = lp.stat().st_size if lp.exists() else 0
        if existing_size + len(chunk) > MAX_LOG_BYTES:
            existing = lp.read_bytes() if lp.exists() else b""
            lp.write_bytes((existing + chunk)[-MAX_LOG_BYTES:])
        else:
            with lp.open("ab") as f:
                f.write(chunk)
    except Exception:
        pass


# Raw cursor-move / hide-cursor escapes — the fingerprint of pre-stable-frame
# alt-screen garbage (captured TUI redraws). Clean logs and clean transcript
# renders use only colour SGR codes (…m) and have effectively zero of these.
_CURSOR_MOVE_RE = re.compile(r'\x1b\[(?:\d+;\d+H|\?25[lh]|\d+[ABCD]|H)')


def _log_looks_torn(text: str) -> bool:
    """True if a saved-log chunk is dense with raw cursor-move escapes — i.e. it
    predates the stable-frame saver and is torn TUI-redraw spam rather than a
    clean linear transcript."""
    if not text:
        return False
    n = len(text)
    if n < 2000:
        return False
    c = len(_CURSOR_MOVE_RE.findall(text))
    return c >= 20 and (c / (n / 1024)) >= 2.0


def _collapse_blank_runs(text: str, keep: int = 1) -> str:
    """Collapse runs of blank lines down to `keep`. Claude Code's alt-screen
    anchors its input box at the bottom of the terminal, so a short conversation
    leaves a big empty band between the content and the prompt that capture-pane
    records verbatim — that band reads as 'funky whitespace' in the peek. Blank
    detection is ANSI-aware (a line of only colour codes counts as blank)."""
    out: list[str] = []
    blanks = 0
    for ln in text.split("\n"):
        if _STRIP_ANSI.sub("", ln).strip() == "":
            blanks += 1
            if blanks <= keep:
                out.append("")
        else:
            blanks = 0
            out.append(ln)
    return "\n".join(out)


# amux's session-launch/relaunch scaffolding — leaks into a live capture whenever
# Claude has exited to a shell and been restarted (rate-limit, crash, /compact).
# All of it forms a contiguous block at the TOP of the frame, above the real
# terminal content, so we cut through the LAST scaffolding line we find.
_LAUNCH_MARKERS = re.compile(
    r'--dangerously-skip-permissions\s+--name\b'
    r'|unset CLAUDECODE CLAUDE_CODE_ENTRYPOINT'
    r'|Resume this session with:'
    r'|claude --resume\b'
    r'|The default interactive shell is now zsh'
    r'|please visit https://support\.apple\.com/kb/HT208050'
)
_BARE_PROMPT_RE = re.compile(r'^[A-Za-z0-9._-]{1,24}\$$')


def _strip_launch_noise(text: str) -> str:
    """Remove amux's session-launch scaffolding from a captured frame (the
    `unset …; cd …; claude --model … --name <s>` relaunch command, the macOS zsh
    notice, and 'Resume this session with:' blocks). Conservative: only acts when
    a scaffolding marker is present, cuts through the LAST such line plus any
    trailing blank/bare-shell-prompt lines, and if nothing real remains it
    returns the input unchanged rather than blanking the peek."""
    if not text or ("--name" not in text and "Resume this session with" not in text
                    and "shell is now zsh" not in text):
        return text
    lines = text.split("\n")
    last = -1
    for i, ln in enumerate(lines):
        if _LAUNCH_MARKERS.search(_STRIP_ANSI.sub("", ln)):
            last = i
    if last < 0:
        return text
    j = last + 1
    while j < len(lines):
        clean = _STRIP_ANSI.sub("", lines[j]).strip()
        if clean == "" or _BARE_PROMPT_RE.match(clean):
            j += 1
        else:
            break
    kept = lines[j:]
    if not any(_STRIP_ANSI.sub("", l).strip() for l in kept):
        return text  # frame is all scaffolding — leave it rather than blank the peek
    return "\n".join(kept)


def load_session_log(session: str, tail_bytes: int = 0) -> str:
    """Load saved session log from disk.

    If tail_bytes > 0, read only the last tail_bytes of the file to avoid
    loading multi-MB logs into memory when only the end is needed.
    """
    lp = _log_path(session)
    if lp.exists():
        try:
            if tail_bytes > 0:
                size = lp.stat().st_size
                if size <= tail_bytes:
                    return lp.read_text(errors="replace")
                with lp.open("rb") as f:
                    f.seek(size - tail_bytes)
                    return f.read().decode("utf-8", errors="replace")
            return lp.read_text(errors="replace")
        except Exception:
            pass
    return ""


def _plain_log_path(session: str) -> Path:
    """Path to the ANSI-stripped mirror of a session log. Kept in a hidden
    subdir so it never collides with a real `<name>.log` or gets swept up by
    CC_LOGS.glob('*.log') (log-search, session listing)."""
    return CC_LOGS / ".plain" / f"{session}.log"


def _write_plain_log(session: str):
    """Materialize an ANSI-stripped copy of the session log — colour SGR *and*
    torn cursor-move escapes removed, blank runs collapsed — so a session can
    Read its own history as clean text instead of a wall of escape codes.
    Returns (path, size_bytes) or None when there is no source log."""
    lp = _log_path(session)
    if not lp.exists():
        return None
    try:
        text = _collapse_blank_runs(_STRIP_ANSI.sub("", lp.read_text(errors="replace")))
        data = text.encode("utf-8", errors="replace")
        cp = _plain_log_path(session)
        cp.parent.mkdir(parents=True, exist_ok=True)
        cp.write_bytes(data)
        return cp, len(data)
    except Exception:
        return None


def _session_jsonl_path(name: str):
    """Newest Claude Code JSONL conversation file for a session's working dir,
    or None. This is the authoritative, complete transcript (never torn like the
    alt-screen snapshot log)."""
    now = time.monotonic()
    cached = _jsonl_path_cache.get(name)
    if cached and (now - cached[0]) < 10:
        return cached[1]
    result = _session_jsonl_path_uncached(name)
    _jsonl_path_cache[name] = (now, result)
    return result


# A plan nobody has touched in over a day is not the session's live execution
# plan — the session moved on without maintaining it (Claude often leaves the
# last item 'completed' and starts new work with no TaskUpdate). Past this cutoff
# hide the strip entirely rather than headline a dead plan; the 6h client-side
# "· plan last updated Nh ago" caveat still covers the fresher-but-stale band.
# (mixpeek-clustering, 2026-07-10/14: a 4-day-old completed plan kept headlining.)
_PLAN_STALE_HIDE_SECS = float(os.environ.get("AMUX_PLAN_STALE_HIDE_HOURS", "24")) * 3600


def _session_cc_tasks(name: str) -> dict:
    """Read Claude Code's native task list for a session — the ephemeral
    TaskCreate/TaskUpdate items it stores in ~/.claude/tasks/<conv_id>/<n>.json
    (the agent's live execution plan, with blockedBy/blocks deps). Surfaced
    READ-ONLY in peek so you can see the agent's checklist without it touching
    the amux board (the durable, gated ledger stays the source of truth).
    Returns {tasks, counts, active, total}."""
    try:
        p = _session_jsonl_path(name)
        if not p:
            return {"tasks": [], "counts": {}, "active": None, "total": 0}
        tdir = CLAUDE_HOME / "tasks" / p.stem
        if not tdir.is_dir():
            return {"tasks": [], "counts": {}, "active": None, "total": 0}
        # A pane showing the Claude splash with NO turns after it is a brand-new
        # conversation (previous one died — e.g. session limit — and Claude was
        # restarted). Its own id has no JSONL yet, so the resolver title-matches
        # the DEAD conversation and its plan renders as if live ("Plan 2/5" over
        # an empty session). Any plan is stale here. A --continue resume paints
        # prior ⏺ turns below the splash, so it is not suppressed.
        raw = tmux_capture(name, 40)
        if raw:
            clean = _STRIP_ANSI.sub("", raw)
            i = clean.rfind("Claude Code v")
            if i >= 0 and "⏺" not in clean[i:]:
                return {"tasks": [], "counts": {}, "active": None, "total": 0}
        tasks = []
        for jf in tdir.glob("[0-9]*.json"):
            try:
                d = json.loads(jf.read_text())
                mtime = jf.stat().st_mtime
            except Exception:
                continue
            if not isinstance(d, dict):
                continue
            tasks.append({
                "id": str(d.get("id") or jf.stem),
                "subject": (d.get("subject") or d.get("activeForm") or "").strip(),
                "activeForm": (d.get("activeForm") or "").strip(),
                "status": d.get("status") or "pending",
                "blockedBy": [str(x) for x in (d.get("blockedBy") or [])],
                "_mtime": mtime,
            })
        tasks.sort(key=lambda t: int(t["id"]) if t["id"].isdigit() else 1_000_000)
        counts = {}
        for t in tasks:
            counts[t["status"]] = counts.get(t["status"], 0) + 1
        # The headline should reflect what the session ACTUALLY last worked on.
        # Claude's convention is one in_progress at a time, but it often leaves
        # several stale in_progress items AND marks the real current task done —
        # so "first in_progress by id" points at a stale task (the reported bug).
        # The single most-recently-updated task file is the truest signal: in the
        # normal flow that's the current in_progress task; when a session just
        # finished something and hasn't started the next, it's that completed task
        # ("between tasks"), which matches reality better than a stale in_progress.
        active = max(tasks, key=lambda t: t["_mtime"]) if tasks else None
        # Newest task-file mtime = when the session last maintained its plan.
        # Surfaced so the UI can flag a stale plan: a session can keep working
        # for days without a single TaskUpdate, and a 2-day-old "Plan 10/15"
        # headline silently reads as current (mixpeek-clustering, 2026-07-10).
        updated_at = int(max((t["_mtime"] for t in tasks), default=0))
        # Dead-plan cutoff: untouched for >_PLAN_STALE_HIDE_SECS → the session
        # moved on without maintaining it, so suppress rather than headline it.
        if updated_at and (time.time() - updated_at) > _PLAN_STALE_HIDE_SECS:
            return {"tasks": [], "counts": {}, "active": None, "total": 0}
        for t in tasks:
            t.pop("_mtime", None)
        if active:
            active = {k: v for k, v in active.items() if k != "_mtime"}
        return {"tasks": tasks, "counts": counts, "active": active,
                "total": len(tasks), "updated_at": updated_at}
    except Exception:
        return {"tasks": [], "counts": {}, "active": None, "total": 0}


def _session_jsonl_path_uncached(name: str):
    env_file = CC_SESSIONS / f"{name}.env"
    if not env_file.exists():
        return None
    try:
        cfg = parse_env_file(env_file)
    except Exception:
        return None
    wd = (cfg.get("CC_DIR") or "").strip()
    if not wd:
        return None
    try:
        # Deterministic path first: the PostToolUse hook reports Claude's live
        # session_id (+ real cwd) on every tool call — <id>.jsonl IS this
        # session's conversation. Title matching below is only a fallback: in
        # shared workdirs conversations get resumed across sessions and titles
        # go stale, which made peeks render another session's (or an old)
        # transcript — whole turns missing vs tmux.
        meta = _load_meta(name)
        conv_id = (meta.get("cc_conversation_id") or "").strip()
        for base in ((meta.get("cc_cwd") or "").strip(), wd):
            if not (conv_id and base):
                continue
            cand = CLAUDE_HOME / "projects" / _project_name(base) / f"{conv_id}.jsonl"
            if cand.is_file():
                return cand
        project_dir = CLAUDE_HOME / "projects" / _project_name(wd)
        if not project_dir.is_dir():
            return None
        files = sorted(project_dir.glob("*.jsonl"),
                       key=lambda f: f.stat().st_mtime, reverse=True)
        if not files:
            return None
        if len(files) == 1:
            return files[0]
        # Multiple conversations live in this project dir — several amux sessions
        # share one CC_DIR (e.g. studio-plg + mixpeek-studio). Returning the
        # newest bleeds ANOTHER session's transcript into this session's peek, so
        # resolve to THIS session's own conversation by matching Claude Code's
        # per-conversation title (set from the launch `--name`) to the amux
        # session name. Files are mtime-desc, so the first match is this
        # session's newest conversation.
        for jf in files:
            try:
                with jf.open() as fh:
                    rec = json.loads(fh.readline() or "{}")
            except Exception:
                continue
            if rec.get("customTitle") == name or rec.get("sessionName") == name:
                return jf
        # No titled match. Do NOT fall back to the newest file — in a shared
        # workdir that's a SIBLING session's transcript bleeding into this one
        # (e.g. a freshly-created session that has no conversation of its own
        # yet). Exclude conversations already claimed by other amux sessions
        # (their meta records cc_conversation_id); only return a file if exactly
        # one plausibly-ours candidate remains, else show live-only (None).
        owned = set()
        try:
            for oenv in CC_SESSIONS.glob("*.env"):
                if oenv.stem == name:
                    continue
                ocid = (_load_meta(oenv.stem).get("cc_conversation_id") or "").strip()
                if ocid:
                    owned.add(ocid)
        except Exception:
            pass
        unclaimed = [jf for jf in files if jf.stem not in owned]
        return unclaimed[0] if len(unclaimed) == 1 else None
    except Exception:
        return None


def _tool_brief(name: str, inp) -> str:
    """A short one-line argument summary for a tool_use block."""
    if not isinstance(inp, dict):
        return ""
    for k in ("command", "file_path", "path", "pattern", "query", "url",
              "prompt", "description", "old_string"):
        v = inp.get(k)
        if isinstance(v, str) and v.strip():
            v = v.replace("\n", " ").strip()
            return v[:90] + ("…" if len(v) > 90 else "")
    return ""


def _tool_result_text(content) -> str:
    if content is None:
        return ""
    if isinstance(content, str):
        return content
    if isinstance(content, list):
        parts = []
        for x in content:
            if isinstance(x, dict) and x.get("type") == "text":
                parts.append(x.get("text", ""))
            elif isinstance(x, str):
                parts.append(x)
        return "\n".join(parts)
    return str(content)


# ── Markdown → ANSI (make transcript history look like Claude Code's terminal
#    render instead of raw markdown source) ─────────────────────────────────────
_MD_TABLE_SEP_RE = re.compile(r'^\s*\|?\s*:?-{2,}:?\s*(?:\|\s*:?-{2,}:?\s*)+\|?\s*$')
# base fg the assistant text is wrapped in — inline styles restore to it
_MD_BASE = "\x1b[39m"


def _md_inline(s: str) -> str:
    """Render inline Markdown (bold, italic, inline code) to ANSI, matching how
    Claude Code renders it in the terminal. Restores to the base assistant color
    so the surrounding wrapper's colour is preserved."""
    # inline code first so ** inside code isn't treated as bold. Colour 153
    # (lavender) is Claude Code's actual terminal inline-code colour — verified
    # against live `tmux capture-pane -e` frames; earlier blue/orange were wrong.
    s = re.sub(r'`([^`\n]+)`', lambda m: '\x1b[38;5;153m' + m.group(1) + _MD_BASE, s)
    # **bold** / __bold__
    s = re.sub(r'\*\*([^*\n]+?)\*\*', lambda m: '\x1b[1m' + m.group(1) + '\x1b[22m', s)
    s = re.sub(r'(?<!\w)__([^_\n]+?)__(?!\w)', lambda m: '\x1b[1m' + m.group(1) + '\x1b[22m', s)
    # *italic* / _italic_ — single delimiter, not adjacent to a word char or a
    # space (so it never eats `2*3`, `*.py` globs, `- ` bullets, or math).
    s = re.sub(r'(?<![\w*])\*(?!\s)([^*\n]+?)(?<!\s)\*(?![\w*])',
               lambda m: '\x1b[3m' + m.group(1) + '\x1b[23m', s)
    s = re.sub(r'(?<![\w_])_(?!\s)([^_\n]+?)(?<!\s)_(?![\w_])',
               lambda m: '\x1b[3m' + m.group(1) + '\x1b[23m', s)
    return s


def _md_render_table(block: list, max_width: int = 100) -> str:
    """Render a Markdown table as a box-drawing table, WRAPPING cells so the whole
    table fits within max_width columns — like Claude Code's terminal render. This
    caps table width so a wide cell can't blow the row out to hundreds of columns
    and break the peek (the box-drawing then wraps mid-glyph in the browser)."""
    import textwrap

    def cells(row: str) -> list:
        r = row.strip()
        if r.startswith('|'):
            r = r[1:]
        if r.endswith('|'):
            r = r[:-1]
        return [c.strip() for c in r.split('|')]

    def strip_md(s: str) -> str:  # width math is on plain text; no ANSI inside cells
        s = re.sub(r'`([^`]+)`', r'\1', s)
        s = re.sub(r'\*\*([^*]+)\*\*', r'\1', s)
        s = re.sub(r'__([^_]+)__', r'\1', s)
        return s

    rows = [[strip_md(c) for c in cells(block[0])]] + [[strip_md(c) for c in cells(r)] for r in block[2:]]
    ncol = max((len(r) for r in rows), default=0)
    if ncol == 0:
        return "\n".join(block)
    for r in rows:
        r.extend([''] * (ncol - len(r)))
    natural = [max((len(rows[ri][ci]) for ri in range(len(rows))), default=0) for ci in range(ncol)]
    avail = max(ncol * 6, max_width - (3 * ncol + 1))   # leave room for the borders
    widths = list(natural)
    guard = 0
    while sum(widths) > avail and guard < 10000:        # shrink the widest column until it fits
        guard += 1
        mx = max(range(ncol), key=lambda c: widths[c])
        if widths[mx] <= 6:
            break
        widths[mx] -= 1

    widths = [max(1, w) for w in widths]   # never 0 — textwrap.wrap(w=0) raises

    def wrap_cell(text: str, w: int) -> list:
        return textwrap.wrap(text, max(1, w), break_long_words=True, break_on_hyphens=False) or ['']

    def render_row(cs: list, header: bool = False) -> str:
        wrapped = [wrap_cell(cs[ci], widths[ci]) for ci in range(ncol)]
        h = max(len(w) for w in wrapped)
        out = []
        for k in range(h):
            parts = []
            for ci in range(ncol):
                seg = wrapped[ci][k] if k < len(wrapped[ci]) else ''
                pad = seg + ' ' * (widths[ci] - len(seg))
                parts.append(('\x1b[1m' + pad + '\x1b[22m') if (header and seg) else pad)
            out.append('│ ' + ' │ '.join(parts) + ' │')
        return '\n'.join(out)

    top = '┌' + '┬'.join('─' * (w + 2) for w in widths) + '┐'
    mid = '├' + '┼'.join('─' * (w + 2) for w in widths) + '┤'
    bot = '└' + '┴'.join('─' * (w + 2) for w in widths) + '┘'
    res = [top, render_row(rows[0], header=True), mid]
    res.extend(render_row(r) for r in rows[1:])
    res.append(bot)
    return "\n".join(res)


def _md_to_ansi(text: str) -> str:
    """Render a practical subset of Markdown (bold, inline code, headers, and
    tables) to ANSI so transcript history matches Claude Code's terminal render
    rather than showing raw `**`, backticks and `| pipe |` tables.

    Fail-safe: any rendering error returns the ORIGINAL text — a formatting bug
    must never blank the transcript (a table crash once turned peeks into
    "(no output)")."""
    try:
        return _md_to_ansi_inner(text)
    except Exception:
        return text


def _md_to_ansi_inner(text: str) -> str:
    lines = text.split("\n")
    out: list = []
    i = 0
    while i < len(lines):
        ln = lines[i]
        # table: a pipe row followed by a |---|---| separator
        if (ln.strip().startswith('|') and ln.count('|') >= 2
                and i + 1 < len(lines) and _MD_TABLE_SEP_RE.match(lines[i + 1])):
            blk = [ln, lines[i + 1]]
            j = i + 2
            while j < len(lines) and lines[j].strip().startswith('|') and lines[j].count('|') >= 2:
                blk.append(lines[j])
                j += 1
            out.append(_md_render_table(blk))
            i = j
            continue
        # ATX header → bold, drop the leading #s
        hm = re.match(r'^(#{1,6})\s+(.*)$', ln)
        if hm:
            out.append('\x1b[1m' + _md_inline(hm.group(2)) + '\x1b[22m')
            i += 1
            continue
        out.append(_md_inline(ln))
        i += 1
    return "\n".join(out)


def _USER_ECHO_ANSI(txt: str) -> str:
    """User-message echo in Claude Code's exact style: fg-239 '❯ ' and fg-231
    text on a bg-237 highlight block, continuations indented 2 (captured from
    a live Claude Code pane — keep byte-identical for visual parity)."""
    return ("\x1b[38;5;239m\x1b[48;5;237m❯ \x1b[38;5;231m"
            + txt.replace("\n", "\n  ") + "\x1b[39m\x1b[49m")


def _render_session_transcript(name: str, max_chars: int = 40000) -> str:
    """Render a session's JSONL conversation as clean ANSI-colored text for the
    peek Transcript tab — the gap-free, never-torn alternative to the alt-screen
    snapshot history. Returns the tail (last max_chars)."""
    path = _session_jsonl_path(name)
    if not path:
        return ""
    try:
        st = path.stat()
    except OSError:
        return ""
    cache_key = (str(path), max_chars)
    cached = _transcript_render_cache.get(cache_key)
    if cached and cached[0] == st.st_mtime and cached[1] == st.st_size:
        return cached[2]
    # Read only the tail of the file — JSONL entries are much larger than their
    # rendered form, so 5x max_chars (min 5MB) is a safe overread estimate.
    max_read = max(max_chars * 5, 5_000_000)
    out: list[str] = []
    for o in _iter_jsonl_tail(path, max_bytes=max_read):
        if o.get("type") not in ("user", "assistant"):
            continue
        msg = o.get("message")
        if not isinstance(msg, dict):
            continue
        role = msg.get("role")
        content = msg.get("content")
        if isinstance(content, str):
            blocks = [{"type": "text", "text": content}]
        elif isinstance(content, list):
            blocks = content
        else:
            continue
        for b in blocks:
            if not isinstance(b, dict):
                continue
            bt = b.get("type")
            if bt == "text":
                txt = (b.get("text") or "").strip()
                if not txt:
                    continue
                if role == "user":
                    # Harness-injected wrappers are invisible in Claude Code's own UI
                    # (reminders, background-task completions, local-command caveats) —
                    # hide them here too instead of dumping the raw XML into the peek.
                    if ("<system-reminder>" in txt or "<task-notification>" in txt
                            or "<local-command-caveat>" in txt):
                        txt = re.sub(r"<system-reminder>.*?</system-reminder>", "", txt, flags=re.S)
                        txt = re.sub(r"<task-notification>.*?</task-notification>", "", txt, flags=re.S)
                        txt = re.sub(r"<local-command-caveat>.*?</local-command-caveat>", "", txt, flags=re.S)
                        txt = txt.strip()
                        if not txt:
                            continue
                    # Local slash-command turns are stored with meta tags; Claude Code
                    # shows the bare command + dim ⎿ output, never the raw tags
                    m_cmd = re.search(r"<command-name>(.*?)</command-name>", txt, re.S)
                    m_arg = re.search(r"<command-args>(.*?)</command-args>", txt, re.S)
                    m_out = re.search(r"<local-command-stdout>(.*?)</local-command-stdout>", txt, re.S)
                    if m_cmd or m_out:
                        if m_cmd and m_cmd.group(1).strip():
                            cmd_line = m_cmd.group(1).strip()
                            if m_arg and m_arg.group(1).strip():
                                cmd_line += " " + m_arg.group(1).strip()
                            out.append(_USER_ECHO_ANSI(cmd_line))
                        body = m_out.group(1).strip() if m_out else ""
                        if body:
                            for k, ln in enumerate(body.split("\n")[:6]):
                                prefix = "  ⎿  " if k == 0 else "     "
                                out.append("\x1b[38;5;246m" + prefix + ln.rstrip() + "\x1b[0m")
                        out.append("")
                        continue
                    # Match Claude Code's real echo: dim-gray ❯ on a subtle bg-237
                    # highlight block, near-white text — captured from a live pane
                    out.append(_USER_ECHO_ANSI(txt))
                else:
                    # Claude Code prefixes each assistant message with a white
                    # ⏺ bullet and renders prose in the default fg (not dim);
                    # continuation lines indent 2 cols under the bullet.
                    body = _md_to_ansi(txt).replace("\n", "\n  ")
                    out.append("\x1b[38;5;231m⏺\x1b[39m " + body + "\x1b[0m")
                out.append("")
            elif bt == "tool_use":
                nm = b.get("name", "tool")
                arg = _tool_brief(nm, b.get("input"))
                # Claude's tool line: green ⏺ + bold ToolName + (args) in default fg
                out.append("\x1b[38;5;114m⏺\x1b[39m \x1b[1m" + str(nm) + "\x1b[0m"
                           + ("(" + arg + ")" if arg else ""))
            elif bt == "tool_result":
                # Preserve multi-line tool output (tables, query results, logs)
                # as indented continuation lines — matching Claude Code's own ⎿
                # display — instead of flattening newlines into one dense run-on
                # line, which rendered as garbled "logs" in the peek.
                raw = _tool_result_text(b.get("content"))
                rlines = [ln.rstrip() for ln in raw.split("\n")]
                while rlines and not rlines[0].strip():
                    rlines.pop(0)
                while rlines and not rlines[-1].strip():
                    rlines.pop()
                if rlines:
                    MAXL, MAXW = 6, 200
                    for k, ln in enumerate(rlines[:MAXL]):
                        if len(ln) > MAXW:
                            ln = ln[:MAXW] + "…"
                        prefix = "  ⎿  " if k == 0 else "     "
                        out.append("\x1b[38;5;246m" + prefix + ln + "\x1b[0m")
                    extra = len(rlines) - MAXL
                    if extra > 0:
                        out.append("\x1b[38;5;246m     … +" + str(extra)
                                   + (" more lines" if extra != 1 else " more line") + "\x1b[0m")
    text = "\n".join(out).strip("\n")
    if len(text) > max_chars:
        text = text[-max_chars:]
        nl = text.find("\n")
        if nl > 0:
            text = text[nl + 1:]
    _transcript_render_cache[cache_key] = (st.st_mtime, st.st_size, text)
    return text


def _trim_live_overlap(transcript: str, live: str) -> str:
    """Return the live frame minus the portion that re-renders content the
    transcript already covers. History must render from ONE source: the
    transcript is canonical and width-stable, while the frame re-renders the
    same messages at whatever width the tmux window happens to be at the time
    (attach/detach resizes change it) — the old approach kept the whole frame
    and trimmed the transcript, so width-mismatched re-renders slipped past the
    string matching and the same table/paragraph appeared twice at two
    different wraps. The frame's unique value is only its tail: in-progress
    streaming output (not yet flushed to the JSONL), the input box, and the
    status bar — everything after the last frame line the transcript already
    has. If fewer than 3 frame lines match the transcript tail, the frame is
    assumed disjoint (transcript stale/empty) and kept whole."""
    if not transcript or not live:
        return live

    def _norm(s: str) -> str:
        s = _STRIP_ANSI.sub("", s)
        # drop markdown / box-drawing / status decoration so raw-markdown
        # transcript lines match their rendered live-frame counterparts
        s = re.sub(r"[*#`_|\u2502\u250c\u2510\u2514\u2518\u251c\u2524\u252c\u2534\u253c\u2500=>\u2022\u00b7\u00bb\u276f\u23bf\u23fa\u273b\u2726\u25cf]+", " ", s)
        return re.sub(r"\s+", " ", s).strip().lower()

    tail_norm = [n for n in (_norm(x) for x in transcript.split("\n")[-140:]) if len(n) >= 12]
    tail_set = set(tail_norm)
    long_tail = [n for n in tail_norm if len(n) >= 46]

    def _in_transcript(n: str) -> bool:
        if len(n) < 12:
            return False
        if n in tail_set:
            return True
        # Wrap tolerance: a frame line wrapped at the tmux width is a substring
        # of the transcript's full logical line (or vice versa for short rows).
        if len(n) >= 24:
            for tv in long_tail:
                if n in tv or tv in n:
                    return True
        return False

    ll = live.split("\n")
    matches = [i for i, x in enumerate(ll) if _in_transcript(_norm(x))]
    if len(matches) < 3:
        return live
    return "\n".join(ll[matches[-1] + 1:]).lstrip("\n")


_healing_logs: set = set()  # sessions whose log is being rebuilt right now


def _heal_log_from_transcript(name: str):
    """One-time repair: replace a torn pre-stable-frame alt-screen log with a
    clean tail rendered from the authoritative JSONL transcript. No-op if the
    session has no JSONL or a heal for it is already in flight. The full history
    always remains available via the Transcript tab; we keep only a ~2MB tail in
    the log since the peek only ever displays the last 64KB."""
    if name in _healing_logs:
        return
    _healing_logs.add(name)
    try:
        clean = _render_session_transcript(name, max_chars=2_000_000)
        if not clean.strip():
            return  # no JSONL (e.g. non-Claude session) — leave the log as-is
        header = ("=== history rebuilt from clean JSONL transcript "
                  "(full history in the Transcript tab) ===\n\n")
        data = (header + clean).rstrip() + "\n"
        lp = _log_path(name)
        CC_LOGS.mkdir(parents=True, exist_ok=True)
        lp.write_bytes(data.encode("utf-8", errors="replace"))
    except Exception:
        pass
    finally:
        _healing_logs.discard(name)


# Tracks last JSONL backup mtime per session to avoid redundant copies
_last_jsonl_backup: dict[str, float] = {}


def _session_work_dir_early(name: str) -> str:
    """Return CC_DIR for a session (early binding — before _session_work_dir is defined)."""
    env_file = CC_SESSIONS / f"{name}.env"
    if not env_file.exists():
        return ""
    for line in env_file.read_text(errors="replace").splitlines():
        line = line.strip()
        if line.startswith("CC_DIR="):
            val = line[len("CC_DIR="):].strip()
            if val:
                return str(Path(val).expanduser().resolve())
    return ""


def _install_channel() -> str:
    """How this copy of amux was installed: 'source' (git checkout — updates via
    git pull), 'brew' (Homebrew cellar), 'pip' (site-packages via pip/pipx), or
    'standalone' (a bare copied file). Drives update routing — package-managed
    copies must not git-pull themselves."""
    here = Path(__file__).resolve()
    p = str(here)
    d = here.parent
    while d != d.parent:
        if (d / ".git").exists():
            return "source"
        d = d.parent
    if "/Cellar/" in p or "/homebrew/" in p or "/Homebrew/" in p:
        return "brew"
    if "site-packages" in p or "dist-packages" in p:
        return "pip"
    return "standalone"


def backup_session_jsonl(session: str, reason: str = "manual") -> str | None:
    """Copy the latest JSONL conversation file for a session to ~/.amux/transcripts/<session>/.

    Returns the backup path on success, None if nothing to back up.
    Keeps at most 20 backups per session (removes oldest when exceeded).
    """
    wd = _session_work_dir_early(session)
    if not wd:
        return None
    project_dir = CLAUDE_HOME / "projects" / _project_name(wd)
    if not project_dir.is_dir():
        return None
    jsonl_files = sorted(project_dir.glob("*.jsonl"), key=lambda f: f.stat().st_mtime, reverse=True)
    if not jsonl_files:
        return None
    src = jsonl_files[0]
    src_mtime = src.stat().st_mtime
    # Skip if already backed up this exact version
    last_mtime = _last_jsonl_backup.get(session, 0)
    if src_mtime <= last_mtime:
        return None
    dest_dir = CC_TRANSCRIPTS / session
    dest_dir.mkdir(parents=True, exist_ok=True)
    ts = time.strftime("%Y%m%dT%H%M%S")
    dest = dest_dir / f"{ts}_{reason}_{src.name}"
    try:
        import shutil
        shutil.copy2(str(src), str(dest))
        _last_jsonl_backup[session] = src_mtime
        # Prune oldest if > 20 backups
        all_backups = sorted(dest_dir.glob("*.jsonl"), key=lambda f: f.stat().st_mtime)
        for old in all_backups[:-20]:
            try:
                old.unlink()
            except Exception:
                pass
        _emit_event(session, "checkpoint.created", {"reason": reason, "path": str(dest)}, source="jsonl-backup")
        return str(dest)
    except Exception:
        return None


def list_session_transcripts(session: str) -> list[dict]:
    """List JSONL backup transcripts for a session, newest first."""
    dest_dir = CC_TRANSCRIPTS / session
    if not dest_dir.is_dir():
        return []
    files = sorted(dest_dir.glob("*.jsonl"), key=lambda f: f.stat().st_mtime, reverse=True)
    result = []
    for f in files:
        stat = f.stat()
        result.append({
            "name": f.name,
            "size": stat.st_size,
            "mtime": int(stat.st_mtime),
        })
    return result


# ── Yolo auto-responder ──────────────────────────────────────────────────────
# When a session runs with --dangerously-skip-permissions, some Claude Code
# internal safety prompts still require a keypress. We detect and answer them.
_YOLO_PROMPTS = [
    # Claude Code internal safety prompts always show "Esc to cancel" UI chrome.
    # Model-level direction questions never do. We require that marker so we never
    # auto-answer open-ended questions where the model is asking for user guidance.
    #
    # Shell command substitution: "Command contains $() command substitution … Esc to cancel"
    (re.compile(r'command contains.*command substitution.*esc to cancel', re.IGNORECASE | re.DOTALL), '1'),
    # Generic tool proceed prompt: "Do you want to proceed? ❯ 1. Yes … Esc to cancel"
    (re.compile(r'do you want to proceed.*esc to cancel', re.IGNORECASE | re.DOTALL), '1'),
    # Leaked permission prompt: "Yes, and don't ask again … Esc to cancel"
    (re.compile(r'yes.*and don.t ask again.*esc to cancel', re.IGNORECASE | re.DOTALL), '1'),
    # Codex MCP/plugin tool approval: "Allow X to <verb> …? 1. Allow 2. Allow for this session"
    (re.compile(r'allow\s+\S+\s+to\s+\w+.*\d\.\s*allow\b.*esc to cancel', re.IGNORECASE | re.DOTALL), '2'),
]
_YOLO_COOLDOWN = 6  # seconds between auto-responses per session
_yolo_last_responded: dict = {}


def _yolo_auto_respond():
    """Check yolo sessions for known blocking prompts and auto-answer them."""
    now = time.time()
    # Fetch running tmux sessions once to avoid spawning a subprocess per session
    running_sessions = set()
    try:
        r = subprocess.run(
            ["tmux", "list-sessions", "-F", "#{session_name}"],
            capture_output=True, text=True, timeout=5,
        )
        if r.returncode == 0:
            running_sessions = set(r.stdout.splitlines())
    except Exception:
        return  # tmux not available, nothing to do
    for f in CC_SESSIONS.glob("*.env"):
        name = f.stem
        try:
            if tmux_name(name) not in running_sessions:
                continue
            if now - _yolo_last_responded.get(name, 0) < _YOLO_COOLDOWN:
                continue
            cfg = parse_env_file(f)
            _flags = cfg.get('CC_FLAGS', '')
            _is_yolo = (
                '--dangerously-skip-permissions' in _flags
                or '--dangerously-bypass-approvals-and-sandbox' in _flags
                or cfg.get('CC_AUTO_CONTINUE') in ('1', 'true', 'yes')
            )
            if not _is_yolo:
                continue
            raw = tmux_capture(name, 50)
            if not raw:
                continue
            clean = re.sub(r'\x1b\[[0-9;?]*[a-zA-Z]|\x1b[^a-zA-Z]*[a-zA-Z]', '', raw)
            for i, (pattern, response) in enumerate(_YOLO_PROMPTS):
                if pattern.search(clean):
                    send_text(name, response)
                    _yolo_last_responded[name] = now
                    _posthog_emit("yolo_auto_answered", {
                        "session": name,
                        "pattern_idx": i,
                        "response": response,
                    }, distinct_id=name)
                    break
        except Exception:
            pass


def _yolo_loop():
    try:
        _yolo_auto_respond()
    except Exception:
        pass


# ── Rate-limit watchdog ──────────────────────────────────────────────────────
# Claude Code's /rate-limit-options prompt appears when a subscription usage
# cap is hit. The three-option menu lets the user either wait, add funds, or
# upgrade. amux auto-selects option 1 ("Stop and wait for limit to reset")
# fleet-wide — when one Max account hits its cap, every active session blocks
# at once, and pressing 1 by hand on each is impractical at scale.
#
# Unlike _YOLO_PROMPTS, this runs regardless of --dangerously-skip-permissions:
# the rate-limit prompt blocks every session equally, YOLO or not.
_RATE_LIMIT_PROMPTS = [
    # Anchor on the option-1 menu line. The "1." prefix confirms it's a menu
    # render and not the phrase appearing in arbitrary scrollback noise; the
    # full phrase ("Stop and wait for limit to reset") is distinctive enough
    # that we don't need to also match options 2/3, which keeps the pattern
    # robust if Anthropic relabels the other choices.
    (re.compile(r'1\.\s*stop and wait for limit to reset', re.IGNORECASE), '1'),
]


# Reset-time formats Claude Code is known to render in scrollback when a
# session hits the cap. We scan the surrounding tmux capture for any of them
# and convert to a unix timestamp so the watchdog can schedule an auto-resume.
_RATE_LIMIT_RESET_PATTERNS = [
    # "resets HH:MM" — wall-clock; today if still ahead, otherwise tomorrow.
    re.compile(r'resets?\s+(?:at\s+)?(\d{1,2}):(\d{2})\s*(am|pm)?\b', re.IGNORECASE),
    # "Resets in: 4 hours 23 minutes" — relative duration (hours and/or minutes).
    re.compile(r'resets?\s+in[:\s]+(?:(\d+)\s*h(?:ours?)?)?\s*(?:(\d+)\s*m(?:in(?:ute)?s?)?)?', re.IGNORECASE),
    # "reset on April 15, 2026 at 10:49 PM" — absolute date + 12h time.
    re.compile(
        r'reset(?:s|\s+on)?\s+(?:on\s+)?'
        r'(jan(?:uary)?|feb(?:ruary)?|mar(?:ch)?|apr(?:il)?|may|jun(?:e)?|jul(?:y)?|'
        r'aug(?:ust)?|sep(?:tember)?|oct(?:ober)?|nov(?:ember)?|dec(?:ember)?)'
        r'\s+(\d{1,2}),?\s+(\d{4})\s+at\s+(\d{1,2}):(\d{2})\s*(am|pm)',
        re.IGNORECASE,
    ),
]

_MONTHS = {
    'jan': 1, 'feb': 2, 'mar': 3, 'apr': 4, 'may': 5, 'jun': 6,
    'jul': 7, 'aug': 8, 'sep': 9, 'oct': 10, 'nov': 11, 'dec': 12,
}

# Weekly/usage-cap banner: "resets Jun 26 at 5am" / "resets Jun 26 at 5:30 pm" /
# "resets Jun 26, 2026 at 5am" — month + day, OPTIONAL year, hour with am/pm,
# OPTIONAL minutes. Distinct from the strict absolute pattern above (which needs
# a year AND :MM), this catches the weekly-limit format which omits both.
_RATE_LIMIT_RESET_MONTHDAY_RE = re.compile(
    r'reset(?:s|\s+on)?\s+(?:on\s+)?'
    r'(jan(?:uary)?|feb(?:ruary)?|mar(?:ch)?|apr(?:il)?|may|jun(?:e)?|jul(?:y)?|'
    r'aug(?:ust)?|sep(?:tember)?|oct(?:ober)?|nov(?:ember)?|dec(?:ember)?)'
    r'\s+(\d{1,2})(?:,?\s+(\d{4}))?\s+at\s+(\d{1,2})(?::(\d{2}))?\s*(am|pm)',
    re.IGNORECASE,
)

# The weekly/usage-limit banner itself (no interactive menu to answer, unlike
# the 5-hour /rate-limit-options prompt). Detecting it lets amux record the
# reset time so badges, bulk actions and auto-resume treat it like any other
# rate limit. e.g. "You've hit your weekly limit · resets Jun 26 at 5am (...)".
_WEEKLY_LIMIT_RE = re.compile(
    r"(?:you'?ve\s+)?(?:hit|reached)\s+your\s+(?:weekly|usage)\s+limit",
    re.IGNORECASE,
)

# The newer session-limit banner — also menu-less, but the 5-hour window
# (resets same-day at a wall-clock time) rather than the weekly cap. Phrased
# "You've hit your session limit · resets 9:50am (America/New_York)". Without
# this, such sessions never get a reset time recorded, so they stay invisible
# to the badge/bulk-actions/auto-resume path. Classified as NON-weekly so it
# lands in the transient ("Rate-limited until") bucket, not the weekly one.
_SESSION_LIMIT_RE = re.compile(
    r"(?:you'?ve\s+)?(?:hit|reached)\s+your\s+session\s+limit",
    re.IGNORECASE,
)

# Per-model credit/usage limit — a DIFFERENT class than the weekly/session caps
# above. Phrased "You've reached your Fable 5 limit. Run /usage-credits to
# continue or switch models with /model." There is NO reset time: the fix is to
# top up credits or switch models, so "continue" won't unblock it (and auto
# resume must NOT fire on it). Anchor on the two strings unique to this banner
# (/usage-credits, "switch models with /model") so normal content never matches;
# like the other banners it's only tested against the LIVE tail.
_MODEL_CREDIT_LIMIT_RE = re.compile(
    r"/usage-credits\b|switch\s+models?\s+with\s+/model",
    re.IGNORECASE,
)
# Pull the model name out for display ("Fable 5", "Opus", ...). Best-effort.
_MODEL_CREDIT_NAME_RE = re.compile(
    r"reached\s+your\s+([A-Za-z0-9][A-Za-z0-9.\s-]{0,19}?)\s+limit",
    re.IGNORECASE,
)

# Permissive fallback: any bare HH:MM (optionally with AM/PM) in the
# scrollback when none of the labeled patterns above match. Real-world
# Claude Code rendering wraps lines and may push the "resets" label off
# the same line as the time, so a bare-time scan within the menu's
# scrollback window is more robust than requiring the strict label.
# A >=5min-in-the-future filter blocks pickup of the current-time status
# bar (e.g. "✦ 14:23 thinking…").
_RATE_LIMIT_BARE_TIME_RE = re.compile(r'\b(\d{1,2}):(\d{2})\s*(am|pm)?\b', re.IGNORECASE)


def _parse_rate_limit_reset(text: str, now: float | None = None) -> int | None:
    """Scan text for a Claude Code rate-limit reset time and return a unix ts.

    Recognizes three TUI formats:
      - "resets HH:MM" or "resets at H:MM PM" (today, or tomorrow if past)
      - "Resets in: <N> hours <M> minutes" (relative duration)
      - "reset on <Month> <D>, <YYYY> at <H:MM AM/PM>" (absolute)

    Returns None if no recognizable format is present. The wall-clock formats
    are interpreted in the server's local time zone — Claude Code renders
    them in the user's local zone, and amux runs on the same machine.
    """
    import datetime as _dt
    if not text:
        return None
    now_ts = now if now is not None else time.time()
    base = _dt.datetime.fromtimestamp(now_ts)
    # Defensive ANSI strip — the handler already cleans the capture before
    # calling this, but selftests and any future direct caller may pass
    # raw tmux output.
    text = _STRIP_ANSI.sub("", text)

    # 1. "Resets in: N hours M minutes" — check first so it doesn't get
    #    swallowed by the bare "resets HH:MM" pattern (no colon → no match
    #    anyway, but ordering keeps intent obvious).
    m = _RATE_LIMIT_RESET_PATTERNS[1].search(text)
    if m and (m.group(1) or m.group(2)):
        hours = int(m.group(1) or 0)
        minutes = int(m.group(2) or 0)
        if hours or minutes:
            return int(now_ts + hours * 3600 + minutes * 60)

    # 2. Absolute "reset on April 15, 2026 at 10:49 PM"
    m = _RATE_LIMIT_RESET_PATTERNS[2].search(text)
    if m:
        month_key = m.group(1).lower()[:3]
        month = _MONTHS.get(month_key)
        day = int(m.group(2))
        year = int(m.group(3))
        hour = int(m.group(4))
        minute = int(m.group(5))
        meridiem = m.group(6).lower()
        if meridiem == 'pm' and hour != 12:
            hour += 12
        elif meridiem == 'am' and hour == 12:
            hour = 0
        if month and 0 <= hour < 24 and 0 <= minute < 60:
            try:
                dt = _dt.datetime(year, month, day, hour, minute)
                return int(dt.timestamp())
            except ValueError:
                pass

    # 2b. Absolute month/day "resets Jun 26 at 5am" (weekly-limit banner) —
    #     optional year, optional minutes. Checked before the bare HH:MM scan so
    #     the full date wins (otherwise "5am" would resolve to the next 5am, not
    #     the correct future day).
    m = _RATE_LIMIT_RESET_MONTHDAY_RE.search(text)
    if m:
        month = _MONTHS.get(m.group(1).lower()[:3])
        day = int(m.group(2))
        has_year = m.group(3) is not None
        year = int(m.group(3)) if has_year else base.year
        hour = int(m.group(4))
        minute = int(m.group(5) or 0)
        meridiem = m.group(6).lower()
        if meridiem == 'pm' and hour != 12:
            hour += 12
        elif meridiem == 'am' and hour == 12:
            hour = 0
        if month and 0 <= hour < 24 and 0 <= minute < 60:
            try:
                dt = _dt.datetime(year, month, day, hour, minute)
                # No explicit year and the date already passed → roll to next year.
                if not has_year and dt.timestamp() <= now_ts:
                    dt = dt.replace(year=year + 1)
                return int(dt.timestamp())
            except ValueError:
                pass

    # 3. "resets HH:MM" — today if still ahead, otherwise tomorrow.
    m = _RATE_LIMIT_RESET_PATTERNS[0].search(text)
    if m:
        hour = int(m.group(1))
        minute = int(m.group(2))
        meridiem = (m.group(3) or '').lower()
        if meridiem == 'pm' and hour != 12:
            hour += 12
        elif meridiem == 'am' and hour == 12:
            hour = 0
        if 0 <= hour < 24 and 0 <= minute < 60:
            candidate = base.replace(hour=hour, minute=minute, second=0, microsecond=0)
            if candidate.timestamp() <= now_ts:
                candidate += _dt.timedelta(days=1)
            return int(candidate.timestamp())

    # 4. Bare-time fallback. Take the earliest HH:MM at least 5 minutes
    # in the future — that filters out current-time status-bar renders
    # like "✦ 14:23 thinking…" while still catching a "resets 14:30"
    # that landed on its own wrapped line away from the "resets" word.
    candidates = []
    for mm in _RATE_LIMIT_BARE_TIME_RE.finditer(text):
        hour = int(mm.group(1))
        minute = int(mm.group(2))
        meridiem = (mm.group(3) or '').lower()
        if meridiem == 'pm' and hour != 12:
            hour += 12
        elif meridiem == 'am' and hour == 12:
            hour = 0
        if not (0 <= hour < 24 and 0 <= minute < 60):
            continue
        cand = base.replace(hour=hour, minute=minute, second=0, microsecond=0)
        if cand.timestamp() <= now_ts:
            cand += _dt.timedelta(days=1)
        if cand.timestamp() - now_ts < 300:
            continue  # too close to now — likely the current-time bar
        candidates.append(int(cand.timestamp()))
    if candidates:
        return min(candidates)

    return None


_RATE_LIMIT_DEFAULT_RESUME_TEXT = "continue"


def _should_skip_rate_limit_resume(scrollback_clean: str) -> tuple[bool, str]:
    """Decide whether auto-resume should be skipped at reset time.

    The watchdog parks a session by pressing 1 on the /rate-limit-options
    menu, which leaves Claude Code displaying a "waiting for limit to reset"
    confirmation. If at reset time the scrollback still shows that wait
    state, auto-resume is safe — we're just unblocking what we parked.

    If the user intervened (picked option 2 or 3 from the menu, typed
    something new, or otherwise moved past the wait state), the session
    is no longer parked where we left it, and steering "continue" would
    fight the user. Skip in that case.

    Returns (skip, reason). Reason is a short human-readable string for
    the log line; empty string when skip is False.
    """
    if not scrollback_clean:
        # Empty scrollback usually means the session is stopped/archived
        # and we can't see anything; safest to skip rather than risk
        # poking a session in an unknown state.
        return True, "no scrollback to inspect"
    tail = "\n".join(scrollback_clean.splitlines()[-30:]).lower()
    # Positive markers: Claude is still parked at the wait-for-reset state.
    if "waiting for" in tail and "reset" in tail:
        return False, ""
    if "stop and wait for limit to reset" in tail:
        # User hasn't pressed anything yet — pattern was matched but
        # the menu is still showing. Resume is premature; the auto-respond
        # cycle will press 1 first.
        return True, "rate-limit menu still showing"
    if "rate-limit-options" in tail or "rate limit" in tail:
        # Some related rate-limit UI is still on screen; user may be
        # interacting with it.
        return False, ""
    # No rate-limit-related markers anywhere in the tail → the session
    # has moved on. Don't fight the user.
    return True, "session moved past wait-state"


def _session_rate_limit_resume_text(cfg: dict) -> str:
    """Return the per-session text to steer at rate-limit reset.

    Read from CC_RATE_LIMIT_RESUME_TEXT in ~/.amux/sessions/<name>.env
    (defaults to "continue"). Lets supervisors/orchestrators use a
    richer resume prompt than a bare "continue".
    """
    val = cfg.get("CC_RATE_LIMIT_RESUME_TEXT", "").strip()
    return val or _RATE_LIMIT_DEFAULT_RESUME_TEXT


# Seconds between consecutive auto-responses for the same session. The
# scheduler tick is 3s, so with a 10s cooldown the watchdog fires no more
# than once every ~12s on a persistently-matching prompt (matches the
# behavior observed during manual verification). Real Claude clears the
# menu immediately after pressing 1, so this loop only matters when the
# menu text persists in scrollback — typically a simulation artifact
# where the prompt was injected via tmux send-keys without Enter and
# stayed pinned in the input area.
_RATE_LIMIT_COOLDOWN = 10
_RATE_LIMIT_DRIFT_TOLERANCE = 30  # seconds; reset times closer than this are "in sync"
_RATE_LIMIT_DRIFT_LOG_COOLDOWN = 600  # don't repeat the drift warning more than every 10 min
_rate_limit_last_responded: dict = {}
_rate_limit_last_drift_log: float = 0.0

# Proof the session produced output on a line: an assistant message (⏺), an
# echoed user message (❯ [09:32 AM] …), or a tool-run summary.
_LIMIT_ACTIVITY_RE = re.compile(r"^(?:⏺\s|❯\s*\[\d|Ran \d+ shell command)")


def _live_limit_region(clean: str) -> str:
    """The slice of the live screen a usage-limit banner may legitimately occupy.

    Claude Code hits a limit at the END of a turn, so a real banner is the last
    transcript content before the input box. The exact same sentence also lands
    in ordinary scrollback when a *subagent* dies on its own limit —
    '⏺ Agent "x" failed: … You've reached your Fable 5 limit. Run /usage-credits …'
    — while the main loop shrugs and keeps working. Matching the raw tail flags
    those sessions forever: the text never leaves the screen, so the flag
    outlives the event and contradicts the live 'working' status.

    Both cases are separated by one signal: whether the session produced any
    output BELOW the banner. So drop the input box and everything under it (UI
    chrome + the background-agents panel), then keep only what follows the last
    activity marker. A banner in that slice is live; anything above it is history.
    """
    lines = clean.splitlines()[-30:]
    box = -1
    for i, l in enumerate(lines):
        if l.strip()[:1] == "❯":
            box = i  # last ❯ wins: earlier ones are echoed user messages
    region = lines[:box] if box >= 0 else lines
    cut = -1
    for i, l in enumerate(region):
        if _LIMIT_ACTIVITY_RE.match(l.strip()):
            cut = i
    return "\n".join(region[cut + 1:])


def _rate_limit_budget_state(actions: dict, today_utc: str, budget: int) -> tuple[bool, int]:
    """Return (exhausted, used) for a session's auto-resume budget.

    Resets the per-session counter when the stored UTC day differs from
    today_utc (mutating `actions`). Isolated here so the selftest can verify
    midnight-rollover behavior without spinning up tmux.
    """
    if actions.get("rate_limit_budget_day") != today_utc:
        actions["rate_limit_budget_day"] = today_utc
        actions["rate_limit_resumes_today"] = 0
    used = int(actions.get("rate_limit_resumes_today", 0))
    return (used >= budget, used)


def _check_rate_limit_drift():
    """Warn if reset times parsed across the fleet disagree by >30s.

    The subscription cap is account-wide, so every blocked session should
    have the same reset time (within ~seconds). Larger drift usually means
    our parser misread one session's scrollback. Log-only — no behavior
    change.
    """
    global _rate_limit_last_drift_log
    now = time.time()
    if now - _rate_limit_last_drift_log < _RATE_LIMIT_DRIFT_LOG_COOLDOWN:
        return
    future_resets = []
    for name, actions in _session_auto_actions.items():
        r = actions.get("rate_limit_reset_at")
        if r and r > now:
            future_resets.append((name, r))
    if len(future_resets) < 2:
        return
    spread = max(r for _, r in future_resets) - min(r for _, r in future_resets)
    if spread > _RATE_LIMIT_DRIFT_TOLERANCE:
        _rate_limit_last_drift_log = now
        sample = ", ".join(f"{n}={r}" for n, r in sorted(future_resets)[:6])
        slog(f"[rate-limit] reset-time drift across fleet: spread={int(spread)}s "
             f"across {len(future_resets)} sessions ({sample}). "
             f"Likely a parser mis-read — verify by peeking each session.")


def _rate_limit_auto_respond():
    """Detect /rate-limit-options across the fleet and press 1 on each match.

    Mirrors _yolo_auto_respond's shape but runs on every running session
    regardless of YOLO mode — the rate-limit prompt blocks YOLO and
    non-YOLO sessions equally. On match, presses 1 to park the session
    at "waiting for limit to reset", parses the reset time from the
    surrounding scrollback, and stores it in _session_auto_actions[name]
    for the auto-resume scheduler to pick up later.
    """
    now = time.time()
    running_sessions = set()
    try:
        r = subprocess.run(
            ["tmux", "list-sessions", "-F", "#{session_name}"],
            capture_output=True, text=True, timeout=5,
        )
        if r.returncode == 0:
            running_sessions = set(r.stdout.splitlines())
    except Exception:
        return  # tmux not available
    for f in CC_SESSIONS.glob("*.env"):
        name = f.stem
        try:
            if tmux_name(name) not in running_sessions:
                continue
            if now - _rate_limit_last_responded.get(name, 0) < _RATE_LIMIT_COOLDOWN:
                continue
            # 300 lines is enough to catch the reset-time line, which can
            # appear ~10-20 lines above the menu in Claude Code's UI.
            raw = tmux_capture(name, 300)
            if not raw:
                continue
            clean = _STRIP_ANSI.sub("", raw)
            existing = _session_auto_actions.get(name)
            # An actively-generating session is, by definition, NOT rate-limited.
            # Clear any stale/false flag (e.g. the weekly-limit phrase printed by
            # a tool or sitting in scrollback) so the badge stops contradicting
            # the live "working" status.
            if _detect_claude_status(raw) == "active":
                if existing and (existing.get("rate_limit_reset_at")
                                 or existing.get("rate_limit_weekly")
                                 or existing.get("rate_limit_banner")
                                 or existing.get("rate_limit_credits")):
                    existing.pop("rate_limit_reset_at", None)
                    existing.pop("rate_limit_reset_at_fallback", None)
                    existing.pop("rate_limit_weekly", None)
                    existing.pop("rate_limit_banner", None)
                    existing.pop("rate_limit_credits", None)
                    existing.pop("rate_limit_model_name", None)
                    slog(f"[rate-limit] session={name} active — cleared stale rate-limit flag")
                continue
            # The interactive /rate-limit-options menu is always rendered LIVE at
            # the bottom of the screen, so match it against the tail only — never
            # the full 300-line capture. Scanning the whole capture for the menu
            # phrase false-matches on stale scrollback (a selftest fixture, a doc,
            # or a session discussing rate limits) and then presses "1" into a
            # healthy session. The reset-TIME parse below still scans full `clean`
            # (the reset line can sit ~10-20 lines above the menu); only the
            # decision to press a key requires a live menu render.
            tail = "\n".join(clean.splitlines()[-30:])
            matched_idx = -1
            for i, (pattern, response) in enumerate(_RATE_LIMIT_PROMPTS):
                if pattern.search(tail):
                    send_text(name, response)
                    _rate_limit_last_responded[name] = now
                    matched_idx = i
                    break
            # Weekly/usage-cap banner has no menu to answer — detect it on its own
            # so we still record the reset time (badges, bulk actions, auto-resume).
            # Only match it on the LIVE screen (bottom ~30 lines): the phrase often
            # appears in scrollback or tool output (e.g. an API echoing another
            # session's state), which must NOT flag a healthy session.
            # ...and only against the slice below the session's last output: the
            # same banner text sits in scrollback whenever a *subagent* died on
            # its own limit, and that must not flag a healthy main loop.
            live = _live_limit_region(clean)
            is_weekly = matched_idx < 0 and bool(_WEEKLY_LIMIT_RE.search(live))
            is_session_banner = (matched_idx < 0 and not is_weekly
                                 and bool(_SESSION_LIMIT_RE.search(live)))
            # Both weekly and session-limit banners are menu-less and keep their
            # banner on screen until reset — group them as "banner" limits.
            is_banner = is_weekly or is_session_banner
            # Per-model credit limit: menu-less, no reset time, NOT auto-resumable.
            is_credit = (matched_idx < 0 and not is_banner
                         and bool(_MODEL_CREDIT_LIMIT_RE.search(live)))
            if matched_idx < 0 and not is_banner and not is_credit:
                # No live rate-limit UI. A real banner cap keeps its banner on
                # screen until reset, so a session flagged from a banner without a
                # live banner was a false match — clear it. (5-hour menu flags park
                # in a bannerless "waiting for reset" state, so leave those alone.)
                if existing and (existing.get("rate_limit_weekly")
                                 or existing.get("rate_limit_banner")
                                 or existing.get("rate_limit_credits")):
                    existing.pop("rate_limit_reset_at", None)
                    existing.pop("rate_limit_reset_at_fallback", None)
                    existing.pop("rate_limit_weekly", None)
                    existing.pop("rate_limit_banner", None)
                    existing.pop("rate_limit_credits", None)
                    existing.pop("rate_limit_model_name", None)
                    slog(f"[rate-limit] session={name} limit banner not on live "
                         f"screen — cleared stale flag")
                continue
            if is_banner or is_credit:
                _rate_limit_last_responded[name] = now  # cooldown; nothing to press
            actions = _session_auto_actions.setdefault(name, {})
            actions["rate_limit_weekly"] = is_weekly
            actions["rate_limit_banner"] = is_banner
            actions["rate_limit_credits"] = is_credit
            if is_credit:
                # No reset time exists for a credit limit; auto-resume keys off
                # rate_limit_reset_at, so leaving it unset keeps auto-resume from
                # firing a useless "continue". Record the model name for the UI.
                m = _MODEL_CREDIT_NAME_RE.search(live)
                actions["rate_limit_model_name"] = (m.group(1).strip() if m else "")
                actions["rate_limit_last_event_ts"] = int(now)
                actions.pop("rate_limit_reset_at", None)
                actions.pop("rate_limit_reset_at_fallback", None)
                slog(f"[rate-limit] session={name} model/credit limit "
                     f"(model={actions['rate_limit_model_name']!r}) — no reset, "
                     f"needs model switch or credit top-up")
                _posthog_emit("rate_limit_model_credit", {
                    "session": name,
                    "model": actions["rate_limit_model_name"],
                }, distinct_id=name)
                continue
            actions.pop("rate_limit_credits", None)
            actions.pop("rate_limit_model_name", None)
            parsed_reset = _parse_rate_limit_reset(clean, now=now)
            actions["rate_limit_last_event_ts"] = int(now)
            if parsed_reset:
                reset_at = parsed_reset
                actions["rate_limit_reset_at"] = reset_at
                actions.pop("rate_limit_reset_at_fallback", None)
                slog(f"[rate-limit] session={name} auto-selected option 1, "
                     f"reset_at={reset_at}")
            else:
                # Couldn't parse a reset time. Apply a safety fallback so
                # auto-resume still has a target. For the 5-hour menu prompt, 5 min
                # is safe (real windows are 1h+). For a banner cap (weekly or
                # session), a 5-min retry would just re-hit the cap in a loop, so
                # fall back to 6h — far enough to avoid churn, and the banner
                # re-detection will refine it once a parseable reset is on screen.
                reset_at = int(now + (6 * 3600 if is_banner else 300))
                actions["rate_limit_reset_at"] = reset_at
                actions["rate_limit_reset_at_fallback"] = True
                # Log a sanitized snippet so future debugging can see
                # what the parser actually saw. Single-line, capped
                # length so the server log stays readable.
                snippet = " | ".join(
                    l.strip() for l in clean.splitlines()[-12:] if l.strip()
                )[:240]
                slog(f"[rate-limit] session={name} auto-selected option 1, "
                     f"reset_at={reset_at} (5min safety fallback — no "
                     f"parseable reset time in scrollback); "
                     f"tail-snippet={snippet!r}")
            _posthog_emit("rate_limit_auto_handled", {
                "session": name,
                "pattern_idx": matched_idx,
                "reset_at": reset_at,
                "fallback": not parsed_reset,
            }, distinct_id=name)
        except Exception:
            pass


def _rate_limit_auto_resume():
    """Steer the configured resume text to sessions whose reset time passed.

    Respects fleet mode (off/capped/unlimited) and per-session budget.
    Calls the state-aware skip predicate to avoid fighting a user who
    moved past the wait-for-reset state.
    """
    import datetime as _dt
    now = time.time()
    today_utc = _dt.datetime.now(_dt.timezone.utc).strftime("%Y-%m-%d")

    # Collect candidates first so we can bail out cheaply when nothing's due.
    candidates = [name for name, actions in list(_session_auto_actions.items())
                  if actions.get("rate_limit_reset_at")
                  and actions["rate_limit_reset_at"] <= now]
    if not candidates:
        return

    if _RATE_LIMIT_MODE == "off":
        # Clear stale reset-at so the badge doesn't linger past reset time.
        # The user has to steer the resume themselves in this mode.
        for name in candidates:
            actions = _session_auto_actions.get(name) or {}
            actions.pop("rate_limit_reset_at", None)
            slog(f"[rate-limit] session={name} reset time reached; "
                 f"auto-resume disabled (mode=off)")
        return

    running_sessions = set()
    try:
        r = subprocess.run(
            ["tmux", "list-sessions", "-F", "#{session_name}"],
            capture_output=True, text=True, timeout=5,
        )
        if r.returncode == 0:
            running_sessions = set(r.stdout.splitlines())
    except Exception:
        return

    resumed = 0
    skipped = 0
    budget_exhausted = 0
    for name in candidates:
        actions = _session_auto_actions.get(name) or {}
        env_file = CC_SESSIONS / f"{name}.env"
        if not env_file.exists():
            actions.pop("rate_limit_reset_at", None)
            continue
        try:
            cfg = parse_env_file(env_file)

            # Archived sessions have no live tmux to resume — drop the stale
            # reset so they stop being candidates instead of retrying forever.
            if cfg.get("CC_ARCHIVED") == "1":
                actions.pop("rate_limit_reset_at", None)
                continue

            # Always run the rollover so the per-day counter doesn't grow
            # forever in unlimited mode; second return is ignored unless
            # we're enforcing a cap.
            exhausted, used = _rate_limit_budget_state(
                actions, today_utc, _RATE_LIMIT_BUDGET)
            if _RATE_LIMIT_MODE == "capped":
                if exhausted:
                    actions.pop("rate_limit_reset_at", None)
                    budget_exhausted += 1
                    slog(f"[rate-limit] session={name} auto-resume budget "
                         f"exhausted ({used}/{_RATE_LIMIT_BUDGET}), "
                         f"falling back to manual")
                    _push_alert("rate_limit_manual", name,
                                f"Rate-limit auto-resume budget exhausted for "
                                f"'{name}' — manual resume required")
                    continue

            scrollback = ""
            if tmux_name(name) in running_sessions:
                raw = tmux_capture(name, 100)
                if raw:
                    scrollback = _STRIP_ANSI.sub("", raw)
            skip, reason = _should_skip_rate_limit_resume(scrollback)
            if skip:
                actions.pop("rate_limit_reset_at", None)
                skipped += 1
                slog(f"[rate-limit] session={name} auto-resume skipped at "
                     f"reset, {reason}")
                continue

            resume_text = _session_rate_limit_resume_text(cfg)
            ok, err = send_text(name, resume_text)
            if ok:
                actions.pop("rate_limit_reset_at", None)
                actions["rate_limit_resumes_today"] = \
                    actions.get("rate_limit_resumes_today", 0) + 1
                resumed += 1
                slog(f"[rate-limit] session={name} resumed at reset, "
                     f"resume_text={resume_text!r}")
                _posthog_emit("rate_limit_auto_resumed", {
                    "session": name,
                    "resume_text": resume_text,
                }, distinct_id=name)
            else:
                # Don't clear reset_at — next tick will retry. Send can fail
                # transiently if tmux is briefly unavailable.
                slog(f"[rate-limit] session={name} resume send failed: {err}")
        except Exception as e:
            slog(f"[rate-limit] session={name} resume error: {e}")

    total = resumed + skipped + budget_exhausted
    if total > 1:
        slog(f"[rate-limit] fleet resume: {resumed} sessions steered, "
             f"{skipped} skipped (user intervened), "
             f"{budget_exhausted} budget-exhausted")
        _posthog_emit("rate_limit_fleet_event", {
            "kind": "resume",
            "resumed": resumed,
            "skipped": skipped,
            "budget_exhausted": budget_exhausted,
        })


def _rate_limit_loop():
    """Single rate-limit watchdog tick: detect prompts, handle reset."""
    try:
        _rate_limit_auto_respond()
    except Exception:
        pass
    try:
        _check_rate_limit_drift()
    except Exception:
        pass
    try:
        _rate_limit_auto_resume()
    except Exception:
        pass


_EVENTS_RETENTION_DAYS = 30
_events_last_sweep = [0.0]

def _emit_event(session: str, etype: str, data: dict | None = None,
                idem: str | None = None, source: str = "") -> None:
    """Append one observable event to the session_events log (issue #48).
    Append-only, never raises, idempotent when `idem` is set (INSERT OR IGNORE
    on the unique key — a client retry or server-restart replay can't
    double-record an externally visible action). Records observable state
    transitions and action receipts ONLY — never model reasoning."""
    try:
        db = get_db()
        db.execute(
            "INSERT OR IGNORE INTO session_events (ts, session, type, data, idem, source) "
            "VALUES (?,?,?,?,?,?)",
            (time.time(), session or "", etype,
             json.dumps(data, ensure_ascii=False) if data else None, idem, source))
        db.commit()
        now = time.time()
        if now - _events_last_sweep[0] > 3600:   # hourly retention sweep
            _events_last_sweep[0] = now
            db.execute("DELETE FROM session_events WHERE ts < ?",
                       (now - _EVENTS_RETENTION_DAYS * 86400,))
            db.commit()
    except Exception as e:
        try: slog(f"[events] emit failed ({etype}): {e}")
        except Exception: pass


def _push_alert(alert_type: str, session: str, message: str):
    """Enqueue an alert to be streamed to all SSE clients, and fan it out to
    any registered Web Push subscriptions so it reaches phones even when the
    app/tab is closed."""
    global _sse_alerts
    with _sse_alert_lock:
        _sse_alerts.append({"type": alert_type, "session": session, "message": message, "ts": int(time.time())})
        if len(_sse_alerts) > 50:
            _sse_alerts = _sse_alerts[-50:]
    try:
        # iOS notification format (no emojis): title = session, body = "<type>\n<description>"
        _web_push_broadcast(session or "amux",
                            _ALERT_TYPE_LABELS.get(alert_type, alert_type) + "\n" + message,
                            session=session, tag=alert_type)
    except Exception:
        pass


# ── Web Push (RFC 8030/8291/8292) — background notifications to phones ────────
# Implemented with stdlib + `cryptography` only (no pywebpush dependency), so it
# stays inside amux's single-file model. Delivers to the browser push service
# (Apple/Mozilla/Google) which forwards to the device even when the PWA is shut.
# Human-readable type label shown on the notification's first body line.
_ALERT_TYPE_LABELS = {
    "scheduler": "schedule", "auto_restart": "auto-restart", "auto_continue": "auto-continue",
    "auto_compact": "compact", "rate_limit_manual": "rate limit", "task_pickup": "task",
    "steering_delivered": "steering", "uncommitted": "uncommitted", "thinking_reset": "thinking reset",
    "urgent": "URGENT",
}


def _env_set(key: str, value: str):
    """Upsert KEY=value in ~/.amux/server.env and apply it live to os.environ."""
    lines = _server_env_file.read_text().splitlines() if _server_env_file.exists() else []
    found = False
    for i, l in enumerate(lines):
        if l.startswith(key + "=") or l.startswith(key + " ="):
            lines[i] = f"{key}={value}"; found = True; break
    if not found:
        lines.append(f"{key}={value}")
    _server_env_file.parent.mkdir(parents=True, exist_ok=True)
    _server_env_file.write_text("\n".join(lines) + "\n")
    if value:
        os.environ[key] = value
    else:
        os.environ.pop(key, None)


def _send_sms(phone: str, text: str):
    """Best-effort SMS to the owner. Twilio if TWILIO_* configured, else macOS
    Messages (timeout-guarded so a permission/TCC wall can't hang the server).
    Returns (ok, detail)."""
    if not phone:
        return False, "no phone configured"
    sid = os.environ.get("TWILIO_ACCOUNT_SID", ""); tok = os.environ.get("TWILIO_AUTH_TOKEN", "")
    frm = os.environ.get("TWILIO_FROM", "")
    if sid and tok and frm:
        try:
            import urllib.request, urllib.parse
            data = urllib.parse.urlencode({"From": frm, "To": phone, "Body": text}).encode()
            req = urllib.request.Request(
                f"https://api.twilio.com/2010-04-01/Accounts/{sid}/Messages.json",
                data=data, method="POST",
                headers={"Authorization": "Basic " + base64.b64encode(f"{sid}:{tok}".encode()).decode()})
            urllib.request.urlopen(req, timeout=15).read()
            return True, "twilio"
        except Exception as e:
            return False, f"twilio error: {str(e)[:120]}"
    # macOS Messages fallback — guarded by a hard timeout (Messages scripting can
    # block on an Automation-permission prompt).
    # `buddy ph of s` is the form that actually delivers; `participant ph of svc`
    # compiles but hangs until the osascript timeout fires.
    try:
        r = subprocess.run([
            "osascript",
            "-e", "on run {msg, ph}",
            "-e", 'tell application "Messages"',
            "-e", "set s to first service whose service type = iMessage",
            "-e", "set b to buddy ph of s",
            "-e", "send msg to b",
            "-e", "end tell",
            "-e", "end run",
            "--", text, phone,
        ], capture_output=True, text=True, timeout=12)
        if r.returncode == 0:
            return True, "imessage"
        return False, f"imessage error: {(r.stderr or '').strip()[:100]}"
    except subprocess.TimeoutExpired:
        return False, "imessage timed out — grant Automation permission for Messages, or set TWILIO_* creds"
    except Exception as e:
        return False, f"imessage error: {str(e)[:100]}"


_urgent_alert_last = {}  # message-hash → ts, for a light flood guard


def _send_urgent_alert(message: str, session: str = "", reason: str = ""):
    """Owner URGENT alert — fan out to enabled channels (in-app push + SMS).
    Meant to be used *sparingly*; a soft 60s dedupe blocks accidental repeats."""
    msg = (message or "").strip()
    if not msg:
        return {"ok": False, "error": "empty message"}
    if reason:
        msg = f"{msg}\n({reason})"
    key = _hashlib.sha256((session + "|" + msg).encode()).hexdigest()[:16]
    now = time.time()
    if now - _urgent_alert_last.get(key, 0) < 60:
        return {"ok": True, "deduped": True, "channels": {}, "message": msg}
    _urgent_alert_last[key] = now
    channels = {}
    if os.environ.get("AMUX_URGENT_PUSH", "1") != "0":
        try:
            _push_alert("urgent", session or "amux", msg)
            channels["push"] = "sent"
        except Exception as e:
            channels["push"] = f"error: {str(e)[:80]}"
    phone = os.environ.get("AMUX_OWNER_PHONE", "")
    if os.environ.get("AMUX_URGENT_SMS", "1") != "0" and phone:
        ok, detail = _send_sms(phone, "amux URGENT: " + msg.replace("\n", " — "))
        channels["sms"] = detail if ok else ("failed: " + detail)
    slog(f"[urgent-alert] session={session!r} reason={reason!r} channels={channels} msg={message[:120]!r}")
    return {"ok": True, "channels": channels, "message": msg}
_VAPID_CACHE = None
_VAPID_PATH = CC_HOME / "vapid_private.pem"
_PUSH_SUBS_PRESENT = None  # None=unknown, False=confirmed empty (skip), True=have subs


_PUSH_SSL_CTX = None


def _push_ssl_context():
    """SSL context for outbound calls to push services. macOS' bundled Python
    doesn't read the system keychain, so plain urlopen fails Apple's cert with
    'unable to get local issuer certificate' — back it with certifi's CA bundle."""
    global _PUSH_SSL_CTX
    if _PUSH_SSL_CTX is not None:
        return _PUSH_SSL_CTX
    try:
        import certifi
        _PUSH_SSL_CTX = ssl.create_default_context(cafile=certifi.where())
    except Exception:
        _PUSH_SSL_CTX = ssl.create_default_context()
    return _PUSH_SSL_CTX


def _b64url(data: bytes) -> str:
    return base64.urlsafe_b64encode(data).rstrip(b"=").decode("ascii")


def _b64url_decode(s: str) -> bytes:
    return base64.urlsafe_b64decode(s + "=" * (-len(s) % 4))


def _vapid_keys():
    """Return (private_key_obj, public_key_b64url). Generated once and persisted."""
    global _VAPID_CACHE
    if _VAPID_CACHE:
        return _VAPID_CACHE
    from cryptography.hazmat.primitives.asymmetric import ec
    from cryptography.hazmat.primitives import serialization
    if _VAPID_PATH.exists():
        pk = serialization.load_pem_private_key(_VAPID_PATH.read_bytes(), password=None)
    else:
        pk = ec.generate_private_key(ec.SECP256R1())
        _VAPID_PATH.write_bytes(pk.private_bytes(
            serialization.Encoding.PEM,
            serialization.PrivateFormat.PKCS8,
            serialization.NoEncryption()))
        try:
            _VAPID_PATH.chmod(0o600)
        except Exception:
            pass
    pub = pk.public_key().public_bytes(
        serialization.Encoding.X962,
        serialization.PublicFormat.UncompressedPoint)
    _VAPID_CACHE = (pk, _b64url(pub))
    return _VAPID_CACHE


def _vapid_jwt(audience: str) -> str:
    """Signed ES256 JWT for the VAPID Authorization header."""
    from cryptography.hazmat.primitives import hashes
    from cryptography.hazmat.primitives.asymmetric import ec
    from cryptography.hazmat.primitives.asymmetric.utils import decode_dss_signature
    pk, _ = _vapid_keys()
    sub = os.environ.get("AMUX_VAPID_SUBJECT", "mailto:amux@localhost")
    header = _b64url(json.dumps({"alg": "ES256", "typ": "JWT"}, separators=(",", ":")).encode())
    claims = _b64url(json.dumps(
        {"aud": audience, "exp": int(time.time()) + 12 * 3600, "sub": sub},
        separators=(",", ":")).encode())
    signing_input = (header + "." + claims).encode("ascii")
    der = pk.sign(signing_input, ec.ECDSA(hashes.SHA256()))
    r, s = decode_dss_signature(der)
    raw = r.to_bytes(32, "big") + s.to_bytes(32, "big")
    return header + "." + claims + "." + _b64url(raw)


def _encrypt_web_push(p256dh_b64: str, auth_b64: str, payload: bytes) -> bytes:
    """Encrypt payload with aes128gcm content coding (RFC 8291). Returns the
    full message body (salt+rs+keyid header followed by the GCM ciphertext)."""
    from cryptography.hazmat.primitives.asymmetric import ec
    from cryptography.hazmat.primitives import serialization, hashes
    from cryptography.hazmat.primitives.kdf.hkdf import HKDF
    from cryptography.hazmat.primitives.ciphers.aead import AESGCM

    ua_public_bytes = _b64url_decode(p256dh_b64)
    auth_secret = _b64url_decode(auth_b64)
    ua_public = ec.EllipticCurvePublicKey.from_encoded_point(ec.SECP256R1(), ua_public_bytes)

    as_private = ec.generate_private_key(ec.SECP256R1())
    as_public_bytes = as_private.public_key().public_bytes(
        serialization.Encoding.X962, serialization.PublicFormat.UncompressedPoint)
    shared = as_private.exchange(ec.ECDH(), ua_public)

    # PRK / IKM per RFC 8291 §3.4
    key_info = b"WebPush: info\x00" + ua_public_bytes + as_public_bytes
    ikm = HKDF(algorithm=hashes.SHA256(), length=32, salt=auth_secret, info=key_info).derive(shared)

    salt = os.urandom(16)
    cek = HKDF(algorithm=hashes.SHA256(), length=16, salt=salt,
               info=b"Content-Encoding: aes128gcm\x00").derive(ikm)
    nonce = HKDF(algorithm=hashes.SHA256(), length=12, salt=salt,
                 info=b"Content-Encoding: nonce\x00").derive(ikm)

    # Single record: plaintext + 0x02 delimiter (last-record marker), then GCM.
    ciphertext = AESGCM(cek).encrypt(nonce, payload + b"\x02", None)
    rs = (4096).to_bytes(4, "big")
    header = salt + rs + bytes([len(as_public_bytes)]) + as_public_bytes
    return header + ciphertext


def _send_one_push(endpoint: str, p256dh_b64: str, auth_b64: str, payload: bytes):
    """Send one encrypted push. Returns (status, detail). status is the HTTP code
    (0 on transport error); detail carries the push service's error body so we can
    surface why Apple/Mozilla/Google rejected it."""
    import urllib.request as _ur
    from urllib.parse import urlparse as _urlparse
    try:
        body = _encrypt_web_push(p256dh_b64, auth_b64, payload)
        parts = _urlparse(endpoint)
        aud = f"{parts.scheme}://{parts.netloc}"
        _, vapid_pub = _vapid_keys()
        req = _ur.Request(endpoint, data=body, method="POST", headers={
            "TTL": "2419200",
            "Urgency": "high",            # wake the device promptly (iOS)
            "Content-Encoding": "aes128gcm",
            "Content-Type": "application/octet-stream",
            "Content-Length": str(len(body)),
            "Authorization": f"vapid t={_vapid_jwt(aud)},k={vapid_pub}",
        })
    except Exception as e:
        slog(f"[webpush] build error: {e}")
        return 0, f"build error: {e}"
    try:
        with _ur.urlopen(req, timeout=10, context=_push_ssl_context()) as resp:
            return resp.status, ""
    except _ur.HTTPError as e:
        detail = ""
        try:
            detail = e.read().decode("utf-8", "replace")[:300]
        except Exception:
            pass
        slog(f"[webpush] {endpoint[:50]}… -> {e.code} {detail}")
        return e.code, detail
    except Exception as e:
        slog(f"[webpush] transport error: {e}")
        return 0, f"transport error: {e}"


def _web_push_send_all(title: str, body: str, session: str = "", tag: str = "amux", url: str = "/"):
    """Send synchronously to every subscription. Returns a list of per-endpoint
    {host, status, detail} results. Prunes dead (404/410) subscriptions."""
    global _PUSH_SUBS_PRESENT
    from urllib.parse import urlparse as _urlparse
    payload = json.dumps({"title": title, "body": body, "session": session, "tag": tag, "url": url}).encode()
    try:
        db = get_db()
        rows = db.execute("SELECT endpoint, p256dh, auth FROM push_subscriptions").fetchall()
    except Exception as e:
        return [{"host": "", "status": 0, "detail": f"db error: {e}"}]
    _PUSH_SUBS_PRESENT = len(rows) > 0
    results = []
    for r in rows:
        status, detail = _send_one_push(r["endpoint"], r["p256dh"], r["auth"], payload)
        results.append({"host": _urlparse(r["endpoint"]).netloc, "status": status, "detail": detail})
        if status in (404, 410):
            try:
                db.execute("DELETE FROM push_subscriptions WHERE endpoint=?", (r["endpoint"],))
                db.commit()
                slog("[webpush] pruned expired subscription")
            except Exception:
                pass
    return results


def _web_push_broadcast(title: str, body: str, session: str = "", tag: str = "amux", url: str = "/"):
    """Fan out a notification to every registered subscription (in a background
    thread so callers never block on the network)."""
    # Fast path: if a prior broadcast confirmed there are no subscriptions, skip
    # spawning a thread for every alert. Reset to True on subscribe.
    if _PUSH_SUBS_PRESENT is False:
        return
    threading.Thread(target=lambda: _web_push_send_all(title, body, session, tag, url), daemon=True).start()

    threading.Thread(target=_run, daemon=True).start()


def _read_jsonl_tail(filepath: Path, max_bytes: int = 5_000_000) -> list:
    """Read the last max_bytes of a JSONL file and return parsed lines.

    Avoids reading entire multi-hundred-MB files into memory when only
    recent entries are needed. Skips the first (likely partial) line
    when seeking into the middle of a file.
    """
    try:
        size = filepath.stat().st_size
    except OSError:
        return []
    lines = []
    try:
        with filepath.open("rb") as fh:
            if size > max_bytes:
                fh.seek(size - max_bytes)
                fh.readline()  # discard partial first line
            for raw in fh:
                try:
                    lines.append(json.loads(raw))
                except (json.JSONDecodeError, ValueError):
                    continue
    except Exception:
        pass
    return lines


def _iter_jsonl_tail(filepath: Path, max_bytes: int = 5_000_000):
    """Iterate over parsed entries from the tail of a JSONL file.

    Unlike _read_jsonl_tail, this yields entries one at a time instead of
    accumulating them all in a list — much less memory for large files.
    """
    try:
        size = filepath.stat().st_size
    except OSError:
        return
    try:
        with filepath.open("rb") as fh:
            if size > max_bytes:
                fh.seek(size - max_bytes)
                fh.readline()  # discard partial first line
            for raw in fh:
                try:
                    yield json.loads(raw)
                except (json.JSONDecodeError, ValueError):
                    continue
    except Exception:
        pass


def _last_meaningful_user_message(work_dir: str) -> str:
    """Extract the last meaningful user message (>20 chars) from the session's JSONL history."""
    if not work_dir:
        return ""
    project_dir = CLAUDE_HOME / "projects" / _project_name(work_dir)
    if not project_dir.is_dir():
        return ""
    jsonl_files = sorted(project_dir.glob("*.jsonl"), key=lambda f: f.stat().st_mtime, reverse=True)
    if not jsonl_files:
        return ""
    last_msg = ""
    try:
        for entry in _iter_jsonl_tail(jsonl_files[0], max_bytes=2_000_000):
            try:
                msg = entry.get("message", {})
                if msg.get("role") == "user":
                    content = msg.get("content", [])
                    text = ""
                    if isinstance(content, list):
                        for block in content:
                            if isinstance(block, dict) and block.get("type") == "text":
                                text = block.get("text", "")
                    elif isinstance(content, str):
                        text = content
                    if len(text) > 20:
                        last_msg = text
            except (json.JSONDecodeError, AttributeError):
                continue
    except Exception:
        pass
    return last_msg


_STRIP_ANSI = re.compile(
    r'\x1b\[[0-9;?]*[a-zA-Z]|\x1b\]8;[^\x1b]*\x1b\\|\x1b\][^\x07]*\x07'
    r'|\x1b\][^\x1b]*\x1b\\|\x1b[()][A-Z0-9]|\x1b[\x20-\x2f]*[\x40-\x7e]'
)


def _claude_ui_visible(clean_output: str) -> bool:
    """Return True if Claude's or Codex's status bar/spinner is present in the terminal output."""
    lines = [l for l in clean_output.splitlines() if l.strip()]
    # Check last 3 lines for Claude status bar markers.
    # Guard: when Claude is killed (signal 9), its status bar text can leak
    # into the bash prompt line as garbled output (e.g. "videos$ ass permissions
    # on \u00b7 1 shell"). Require that the line does NOT start with a shell prompt.
    _shell_prompt_re = re.compile(r'^.*[$%]\s')
    for l in lines[-3:]:
        ls = l.strip().lower()
        if _shell_prompt_re.match(ls):
            continue
        if "\u23f5\u23f5" in l or "bypass permissions" in ls or "plan mode" in ls:
            return True
        if "codex" in ls and ("full-auto" in ls or "suggest" in ls or "workspace" in ls or "approval" in ls or "-a never" in ls):
            return True
    # Check last 12 lines for an active spinner (dingbat-prefixed status line
    # like "\u273b Crunched for 1m 38s"). Exclude U+276F \u276f \u2014 that's Claude's input
    # prompt; after /exit, "\u276f /exit" stays in scrollback and false-positives.
    for l in lines[-12:]:
        s = l.strip()
        if s and "\u2700" <= s[0] <= "\u27bf" and s[0] != "\u276f":
            return True
    # Codex UI patterns — checked unconditionally so long-running sessions still
    # match after the initial "codex" banner has scrolled past the capture window
    for l in lines[-12:]:
        s = l.strip()
        # "• Working (Xs • esc to interrupt)" spinner — U+2022 is below dingbats range
        if s.startswith("•") and "working" in s.lower() and "esc to interrupt" in s.lower():
            return True
        # Codex model status bar: "gpt-5.5 xhigh · ~/path"
        if "·" in s and re.search(r"gpt-\d|o[34][-m]", s):
            return True
    # Codex idle prompt: > or › (gate on "codex" in first 15 OR last 20 lines)
    has_codex = any("codex" in l.lower() for l in lines[:15] + lines[-20:])
    if has_codex:
        for l in lines[-5:]:
            ls = l.strip()
            if ls == ">" or ls.startswith("> "):
                return True
            if ls.startswith("›"):
                return True
            # Codex model status line: "gpt-X xhigh · ~/path"
            if "·" in ls and ("gpt-" in ls or "o3" in ls or "o4" in ls):
                return True
    # Gemini CLI prompt/status. Gemini's UI is also Ink-based and may use
    # ">" / "›" prompt lines, but only treat those as ready if the banner/model
    # is visible somewhere in the recent pane.
    has_gemini = any("gemini" in l.lower() for l in lines[:20] + lines[-12:])
    if has_gemini:
        for l in lines[-8:]:
            ls = l.strip().lower()
            if ls == ">" or ls.startswith("> ") or ls.startswith("›"):
                return True
            if "gemini-" in ls or "yolo" in ls or "approval" in ls:
                return True
    return False


def _at_resume_picker(clean_output: str) -> bool:
    """Return True if Claude's --resume picker is showing (interactive session selector)."""
    return bool(clean_output and
                ("Resume Session" in clean_output or "Type to Search" in clean_output or
                 "Enter to select" in clean_output or "Esc to cancel" in clean_output) and
                "⌕" in clean_output)  # ⌕ search icon in the picker


def _at_compact_resume_prompt(clean_output: str) -> bool:
    """Return True if Claude is showing the 'Resume from summary' compaction dialog.

    This appears when a session's context is large and Claude Code asks whether to
    compact before resuming. Option 1 (Resume from summary) is pre-selected.
    """
    return bool(clean_output and
                "Resume from summary" in clean_output and
                "Resume full session" in clean_output)


def _at_shell_prompt(clean_output: str) -> bool:
    """Return True if the terminal looks like a bare shell prompt (no Claude UI)."""
    if _claude_ui_visible(clean_output):
        return False
    lines = [l for l in clean_output.splitlines() if l.strip()]
    for l in lines[-5:]:
        ls = l.strip()
        # Bash/zsh prompt: ends with $ or % (not Claude's ❯ prompt)
        if re.search(r'[$%]\s*$', ls) and "\u276f" not in ls:
            return True
        # After Killed/signal 9, status bar text leaks after the prompt char:
        # e.g. "mixpeek$ ss permissions on · 5 shells"
        if re.match(r'\S+[$%]\s', ls) and "\u276f" not in ls:
            return True
    return False


_snapshot_running = False

def _snapshot_all_sessions():
    """Capture scrollback for health checks on all running sessions.

    Session output is streamed to disk in real-time via tmux pipe-pane (set up
    in start_session). This loop only reads output for health-check logic:
    1. Proactive: if context < 50% remaining before auto-compact, send /compact
    2. Reactive: if thinking-block corruption error detected, restart conversation
       and replay the last meaningful user message automatically.
    3. Auto-continue: if CC_AUTO_CONTINUE=1 and session is stuck waiting for user
       input for 2+ consecutive snapshots (~60s), auto-respond to unblock it.
    4. Auto-restart: if CC_AUTO_CONTINUE=1 and Claude has exited to a shell prompt,
       restart it automatically (handles context-limit exits mid-task).
    """
    global _snapshot_running
    if _snapshot_running:
        return
    _snapshot_running = True
    try:
        _snapshot_all_sessions_inner()
    finally:
        _snapshot_running = False

def _steer_enqueue(name: str, text: str, guard: str = "") -> str:
    """Append a message to a session's durable steering queue (memory + DB).
    Delivered (batched) at the next turn boundary by _steer_try_deliver.

    Dedup-on-enqueue: an identical text already waiting is REPLACED, not
    stacked — observed live on mvs-infra: recurring scheduled prompts piled up
    behind a busy session (the same PULSE health-loop queued twice runs the
    same loop back-to-back for nothing), and sender retries queued literal
    duplicates ("YES to the census" ×2).

    `guard`: optional re-validation tag (e.g. "commit"). _steer_try_deliver
    rechecks the condition at DELIVERY and drops the entry if it went stale —
    a commit-guard nudge whose tree got committed while the nudge waited
    (AMUX-1737). In-memory only; a restart-reloaded entry delivers without it."""
    msg_id = f"steer-{int(time.time()*1000)}"
    entry = {"id": msg_id, "text": text, "queued_at": time.time(), "guard": guard}
    with _steering_lock:
        q = _steering_queue.setdefault(name, [])
        stale = [m for m in q if m["text"] == text and not m.get("_inflight")]
        if stale:
            _steering_queue[name] = [m for m in q if m not in stale]
        _steering_queue[name].append(entry)
    if stale:
        try:
            db = get_db()
            for m in stale:
                db.execute("DELETE FROM steering_queue WHERE id=?", (m["id"],))
            db.commit()
        except Exception:
            pass
    try:
        db = get_db()
        db.execute(
            "INSERT OR REPLACE INTO steering_queue(id, session, text, queued_at) VALUES(?,?,?,?)",
            (msg_id, name, text, entry["queued_at"]),
        )
        db.commit()
    except Exception:
        pass
    _emit_event(name, "message.queued", {"chars": len(text), "preview": text[:120], "guard": guard or None},
                idem="q:" + msg_id, source="steering")
    return msg_id


_STEER_HISTORY_KEEP = 100  # per-session cap on delivered-steer log rows


def _steer_record_history(name: str, text: str, queued_at=None, msg_id: str = "") -> None:
    """Log a steering message that was actually delivered to a session, so the
    steering tab can show what was sent (queue rows are deleted on delivery).
    Best-effort: never let history bookkeeping break a delivery. Pruned to the
    most recent _STEER_HISTORY_KEEP rows per session."""
    try:
        hid = msg_id or f"steerh-{int(time.time()*1000)}"
        db = get_db()
        db.execute(
            "INSERT OR REPLACE INTO steering_history(id, session, text, queued_at, delivered_at) "
            "VALUES(?,?,?,?,?)",
            (hid, name, text, queued_at, time.time()),
        )
        db.execute(
            "DELETE FROM steering_history WHERE session=? AND id NOT IN "
            "(SELECT id FROM steering_history WHERE session=? ORDER BY delivered_at DESC LIMIT ?)",
            (name, name, _STEER_HISTORY_KEEP),
        )
        db.commit()
    except Exception:
        pass


# A single tmux frame that momentarily reads idle is not proof a session
# finished its task — captures tear, and a session pauses briefly between steps.
# Before delivering steering we require the session to read idle/waiting
# *continuously* for this settle window; any active/unknown frame in between
# resets the timer. This trades a few seconds of latency for not interrupting a
# session that only looked done for one frame. Tunable via env.
_STEER_SETTLE_SECS = float(os.environ.get("AMUX_STEER_SETTLE_SECS", "6"))
_steer_settle_since: dict = {}   # name -> monotonic ts of first deliverable observation


def _steer_try_deliver(name: str, status: str, raw: str = "") -> None:
    """Deliver the head of a session's steering queue once it has sat at an IDLE
    turn boundary *continuously* for _STEER_SETTLE_SECS.

    The settle window is the accuracy guard: a lone torn/between-task frame that
    momentarily reads idle only starts the timer — the session must STILL be
    idle on a later confirming tick before anything is sent, and any active
    frame in the meantime resets it. Shared by the 60s snapshot loop and the 4s
    steering tick; the in-flight marker under the lock prevents the two loops
    from double-delivering the same message.

    `raw` (the tmux frame) lets us look past the main loop: a session whose main
    loop rests at the prompt while a background subagent is still working is NOT
    done, so an in-flight subagent holds steering exactly like an active frame
    (mirrors the client-facing status).

    Delivery requires a genuinely IDLE prompt — NOT 'waiting'. A 'waiting' frame
    means a live selector is up (a tool-approval "Do you want to proceed?", an
    AskUserQuestion, or a rate-limit/compact picker). Injecting a queued message
    there does NOT answer the selector — send_text's picker-closing Escape
    REJECTS the pending tool ("[Request interrupted by user] for tool use",
    gtm-engine 2026-07-15). Hold until the selector resolves (human answer or
    auto-continue) and the session returns to an empty prompt."""
    now = time.monotonic()
    deliverable = status == "idle"
    if deliverable and raw and _has_running_subagent(raw):
        deliverable = False  # main loop idle but a subagent is still running
    # Re-validate commit-guard nudges at DELIVERY: a nudge enqueued when a session
    # went idle-dirty is HELD while the session's next turn commits, then would
    # deliver against a now-clean tree — a stale warning (AMUX-1737, fired 4/4
    # today). When the session is idle again and the tree is clean, drop them.
    if deliverable:
        with _steering_lock:
            _guard_ids = [m["id"] for m in _steering_queue.get(name, [])
                          if m.get("guard") == "commit" and not m.get("_inflight")]
        if _guard_ids:
            _wd = _session_work_dir(name)
            if _wd and not _session_dirty_files(name, _wd):
                _drop = set(_guard_ids)
                with _steering_lock:
                    _steering_queue[name] = [m for m in _steering_queue.get(name, []) if m["id"] not in _drop]
                try:
                    _db = get_db()
                    for _mid in _drop:
                        _db.execute("DELETE FROM steering_queue WHERE id=?", (_mid,))
                    _db.commit()
                except Exception:
                    pass
                _commit_guard_nudged.pop(name, None)   # tree clean → re-arm the guard
                slog(f"[commit-guard] {name}: tree clean at delivery — dropped {len(_drop)} stale nudge(s)")
                _emit_event(name, "message.dropped", {"count": len(_drop), "reason": "tree clean at delivery"},
                            source="commit-guard")
    with _steering_lock:
        queue = _steering_queue.get(name, [])
        if not queue or not deliverable:
            # Working again (active/unknown/subagent) or nothing queued → drop
            # the timer so the next idle stretch has to settle from scratch.
            _steer_settle_since.pop(name, None)
            return
        first = _steer_settle_since.get(name)
        if first is None:
            _steer_settle_since[name] = now
            return  # start settling; a later confirming tick delivers
        if (now - first) < _STEER_SETTLE_SECS:
            return  # idle, but not for long enough yet — keep waiting
        if any(m.get("_inflight") for m in queue):
            return
        # Deliver the WHOLE queue as ONE turn (size-capped), not one message per
        # turn boundary. Observed live on mvs-infra: per-message delivery let a
        # busy session backlog 5+ messages, so a correction ("⚠️ before you act
        # on my ruling") sat queued while the session could act on the wrong
        # ruling for a full turn — and each drained message cost its own
        # full-context turn. One batched turn delivers corrections WITH what
        # they correct and costs 1× context instead of N×.
        batch, size = [], 0
        for m in queue:
            if batch and size + len(m["text"]) > 12000:
                break  # leave the rest for the next boundary
            batch.append(m)
            size += len(m["text"])
        for m in batch:
            m["_inflight"] = True
    if len(batch) == 1:
        combined = batch[0]["text"]
    else:
        now_t = time.time()
        parts = [f"You have {len(batch)} queued messages (oldest first — read ALL "
                 f"before acting; later ones may correct earlier ones):"]
        for i, m in enumerate(batch, 1):
            age = max(0, int((now_t - m.get("queued_at", now_t)) / 60))
            parts.append(f"--- [{i}/{len(batch)}] queued {age}m ago ---\n{m['text']}")
        combined = "\n\n".join(parts)
    ok, err = send_text(name, combined, _from_steering=True)
    if ok:
        ids = {m["id"] for m in batch}
        with _steering_lock:
            q = _steering_queue.get(name, [])
            _steering_queue[name] = [m for m in q if m["id"] not in ids]
            # Reset settle: the session is now busy handling what we just sent,
            # and any following message must settle against a fresh idle stretch.
            _steer_settle_since.pop(name, None)
        try:
            db = get_db()
            for mid in ids:
                db.execute("DELETE FROM steering_queue WHERE id=?", (mid,))
            db.commit()
        except Exception:
            pass
        for m in batch:
            _steer_record_history(name, m["text"], m.get("queued_at"), m["id"])
            _emit_event(name, "message.delivered", {"preview": m["text"][:120]},
                        idem="d:" + m["id"], source="steering")
        _push_alert("steering_delivered", name,
                    f"{len(batch)} steering message{'s' if len(batch) > 1 else ''} delivered to '{name}'")
    else:
        with _steering_lock:
            for m in batch:
                m.pop("_inflight", None)


def _steering_fast_tick():
    """Deliver queued steering to idle/waiting sessions within seconds — the
    snapshot loop only ticks every 60s, which read as 'queue does nothing'
    when a message was queued to an already-idle session. Only captures
    sessions that actually have a queue, so it costs nothing when empty."""
    with _steering_lock:
        names = [n for n, q in _steering_queue.items() if q]
    for name in names:
        try:
            if not is_running(name):
                continue
            raw = tmux_capture(name, 60)
            if not raw:
                continue
            _steer_try_deliver(name, _detect_claude_status(raw), raw)
        except Exception:
            pass


def _snapshot_all_sessions_inner():
    # Fetch running tmux sessions once to avoid spawning a subprocess per session
    running_sessions = set()
    try:
        r = subprocess.run(
            ["tmux", "list-sessions", "-F", "#{session_name}"],
            capture_output=True, text=True, timeout=5,
        )
        if r.returncode == 0:
            running_sessions = set(r.stdout.splitlines())
    except Exception:
        return
    _HIBERNATE_IDLE_SECS = 1800  # 30 minutes
    _HIBERNATE_STARTUP_GRACE = 600  # 10 min grace after server restart
    for f in CC_SESSIONS.glob("*.env"):
        name = f.stem
        if _is_session_blocked(name):
            continue
        if tmux_name(name) not in running_sessions:
            continue
        try:
            output = tmux_capture(name, 500)
            if not output:
                continue

            # Strip ANSI codes for pattern matching
            clean = _STRIP_ANSI.sub("", output)
            now = time.time()
            actions = _session_auto_actions.setdefault(name, {})

            # ── 1. Proactive: auto-compact when context is low ──────────────
            # Skip if the context % appears in /status output (user was just checking)
            ctx_match = re.search(r'context left until auto-compact[:\s]+(\d+)%', clean, re.IGNORECASE)
            _from_status_cmd = bool(ctx_match and re.search(r'❯\s*/status', clean))
            if ctx_match and not _from_status_cmd:
                pct = int(ctx_match.group(1))
                _ac_row = get_db().execute("SELECT value FROM prefs WHERE key='auto_compact_enabled'").fetchone()
                _ac_enabled = (_ac_row is None) or (_ac_row[0] != "0")  # default ON
                # Backup JSONL before compaction (regardless of whether auto-compact fires)
                if pct < 30 and now - actions.get("last_backup", 0) > 120:
                    actions["last_backup"] = now
                    threading.Thread(target=backup_session_jsonl, args=(name, "pre_compact"), daemon=True).start()
                if _ac_enabled and pct < 50 and now - actions.get("last_compact", 0) > 300:
                    actions["last_compact"] = now
                    actions["post_compact_continue"] = True  # send continuation when compact finishes
                    send_text(name, "/compact")
                    _push_alert("auto_compact", name,
                                f"Auto-compacted '{name}' — context was at {pct}%")

            # ── 1b. Reactive: image dimension limit → auto-compact ─────────
            # Sessions using browser screenshots fill context with large images
            # until Claude errors with "image exceeds the dimension limit".
            # The session gets stuck at the prompt unable to proceed.
            # Guard: only fire once per error. The error text persists in tmux
            # scrollback after compaction, so without this flag the handler
            # re-triggers every 120s and floods /compact commands.
            _img_dim_error = "image" in clean and "exceeds the dimension limit" in clean
            if (_img_dim_error and not actions.get("img_dim_compacted") and
                    now - actions.get("last_compact", 0) > 120):
                actions["last_compact"] = now
                actions["img_dim_compacted"] = True
                actions["post_compact_continue"] = True
                threading.Thread(target=backup_session_jsonl, args=(name, "pre_compact_img"), daemon=True).start()
                send_text(name, "/compact")
                _push_alert("auto_compact", name,
                            f"Auto-compacted '{name}' — image dimension limit hit")
            elif not _img_dim_error:
                actions.pop("img_dim_compacted", None)

            # ── 1c. Reactive: corrupted image in context → auto-compact ────
            # When a malformed image (truncated PNG, SVG-as-PNG, etc.) gets
            # loaded via Read, every subsequent API call fails with "Could not
            # process image". The bad image is stuck in conversation history.
            _img_corrupt_error = "Could not process image" in clean
            if (_img_corrupt_error and not actions.get("img_corrupt_compacted") and
                    now - actions.get("last_compact", 0) > 120):
                actions["last_compact"] = now
                actions["img_corrupt_compacted"] = True
                actions["post_compact_continue"] = True
                threading.Thread(target=backup_session_jsonl, args=(name, "pre_compact_img"), daemon=True).start()
                send_text(name, "/compact")
                _push_alert("auto_compact", name,
                            f"Auto-compacted '{name}' — corrupted image in context")
            elif not _img_corrupt_error:
                actions.pop("img_corrupt_compacted", None)

            # ── 1d. Reactive: compact/resume dialog → auto-select "Resume from summary" ──
            # When a session's context is large, CC shows an interactive dialog:
            #   ❯ 1. Resume from summary (recommended)
            #     2. Resume full session as-is
            #     3. Don't ask me again
            # Option 1 is pre-selected; pressing Enter confirms it.
            # Guard: 120s cooldown to avoid double-firing if the dialog lingers.
            if (_at_compact_resume_prompt(clean) and
                    now - actions.get("last_compact_prompt", 0) > 120):
                # Dedicated pref (default ON): auto_compact_enabled used to gate this
                # too, so turning off auto-compaction ALSO silently disabled answering
                # the resume dialog — sessions sat at the selector for hours
                # (observability's 3am audit blocked until 4:22, 2026-07-17).
                _ar_row = get_db().execute("SELECT value FROM prefs WHERE key='auto_resume_summary'").fetchone()
                _ar_enabled = (_ar_row is None) or (_ar_row[0] != "0")
                if _ar_enabled:
                    actions["last_compact_prompt"] = now
                    subprocess.run(
                        ["tmux", "send-keys", "-t", tmux_target(name), "Enter"],
                        capture_output=True, timeout=5,
                    )
                    _push_alert("auto_compact", name,
                                f"Auto-selected 'Resume from summary' for '{name}'")
                    _emit_event(name, "session.dialog_answered",
                                {"dialog": "resume_from_summary", "choice": 1}, source="auto-resume")

            # ── 2. Reactive: thinking-block corruption → restart + replay ───
            if ("redacted_thinking" in clean and
                    "cannot be modified" in clean and
                    now - actions.get("last_restart", 0) > 120):
                actions["last_restart"] = now
                wd = _session_work_dir(name)
                last_msg = _last_meaningful_user_message(wd)
                _hard_kill_claude(name)
                start_session(name)
                if last_msg:
                    def _replay(sname=name, msg=last_msg):
                        time.sleep(6)
                        send_text(sname, msg)
                    threading.Thread(target=_replay, daemon=True).start()
                _emit_event(name, "session.crashed", {"reason": "thinking_block_corruption", "replayed": bool(last_msg)},
                            source="self-heal")
                _push_alert("thinking_reset", name,
                            f"Session '{name}' auto-restarted: thinking block corruption"
                            + (" — last message replayed" if last_msg else ""))

            # ── 2b. Reactive: session ID already in use → hard-kill + restart ─
            # Claude Code exits with "Session ID ... is already in use" when a
            # stale process holds the lock.
            if ("is already in use" in clean and "Session ID" in clean and
                    now - actions.get("last_restart", 0) > 120):
                actions["last_restart"] = now
                wd = _session_work_dir(name)
                last_msg = _last_meaningful_user_message(wd)
                _hard_kill_claude(name)
                start_session(name)
                if last_msg:
                    def _replay_id(sname=name, msg=last_msg):
                        time.sleep(6)
                        send_text(sname, msg)
                    threading.Thread(target=_replay_id, daemon=True).start()
                _emit_event(name, "session.crashed", {"reason": "session_id_conflict", "replayed": bool(last_msg)},
                            source="self-heal")
                _push_alert("auto_restart", name,
                            f"Session '{name}' auto-restarted: session ID conflict resolved"
                            + (" — last message replayed" if last_msg else ""))

            # ── 3. Auto-continue: unblock waiting sessions ───────────────────
            status = _detect_claude_status(clean)

            # ── 2c. Ghost-text rescue: amux-injected text stuck in the box ──
            # Every message amux sends carries a client-side "[H:MM AM]" prefix,
            # so pending input starting with one is OURS — never something the
            # user is composing at a real terminal. If it's sitting unsubmitted
            # in an IDLE session, its Enter was eaten (typically keystrokes
            # buffered through a Claude restart) and it will sit there forever:
            # submit it. Space-stripped match because _pending_input strips.
            if status == "idle":
                _ghost = _pending_input(clean)
                if _ghost and re.match(r"^\[\d{1,2}:\d{2}[AP]M\]", _ghost):
                    with _get_send_lock(name):
                        raw2 = tmux_capture(name, 25) or ""
                        if (_detect_claude_status(raw2) == "idle"
                                and _pending_input(_STRIP_ANSI.sub("", raw2)) == _ghost):
                            subprocess.run(["tmux", "send-keys", "-t", tmux_target(name), "Escape"],
                                           capture_output=True, timeout=5)
                            time.sleep(0.06)
                            subprocess.run(["tmux", "send-keys", "-t", tmux_target(name), "Enter"],
                                           capture_output=True, timeout=5)
                            slog(f"[ghost-rescue] session={name} submitted stuck "
                                 f"amux message: {_ghost[:80]!r}")
                            _emit_event(name, "message.rescued", {"preview": _ghost[:120]}, source="ghost-rescue")
                            _push_alert("ghost_rescue", name,
                                        f"Rescued a stuck message in '{name}' — it was typed but never submitted")

            # Track last time Claude UI was visible (used by auto-restart below)
            if _claude_ui_visible(clean):
                actions["last_claude_alive"] = now
                actions.pop("hibernated", None)

            # ── 4. Auto-restart: Claude exited to shell prompt ────────────────
            # Triggered when: CC_AUTO_CONTINUE=1 AND terminal shows a bare shell
            # prompt (no Claude UI). Rate-limited to once per 90s.
            # Always restarts when CC_AUTO_CONTINUE=1 — the user explicitly opted
            # in. Previous logic required last_alive < 600s which failed after
            # macOS hibernate (hours-long SIGKILL gaps).
            if _at_shell_prompt(clean) and not actions.get("restarting") and not actions.get("hibernated"):
                cfg_ar = parse_env_file(f)
                if cfg_ar.get("CC_ARCHIVED") == "1":
                    pass  # don't auto-restart archived sessions
                elif cfg_ar.get("CC_AUTO_CONTINUE") in ("1", "true", "yes"):
                    last_restart = actions.get("last_auto_restart", 0)
                    if now - last_restart > 90:
                        actions["restarting"] = True
                        actions["last_auto_restart"] = now
                        def _do_restart(sname=name, _actions=actions):
                            time.sleep(3)
                            start_session(sname)
                            # Wait for Claude UI to appear before clearing
                            # restarting flag — prevents auto-continue from
                            # sending text into the resume picker.
                            for _w in range(30):
                                time.sleep(1)
                                _o = tmux_capture(sname, 10)
                                if _o and _claude_ui_visible(_o):
                                    break
                            _actions.pop("restarting", None)
                        threading.Thread(target=_do_restart, daemon=True).start()
                        _push_alert("auto_restart", name,
                                    f"Claude exited in '{name}' — auto-restarting")

            # ── 4b. Process-level auto-restart: Claude killed (OOM / signal 9) ──
            # _at_shell_prompt can miss exits when Claude's status bar text leaks
            # into scrollback after a kill (causes _claude_ui_visible to
            # false-positive). This check doesn't parse terminal output — it
            # directly checks if the shell's child process is gone.
            # During startup grace, only fire if stale Claude UI is visible
            # (killed mid-operation) — skip bare shell prompts (legitimately hibernated).
            _in_grace = now - _server_start_time < _HIBERNATE_STARTUP_GRACE
            _ui_stale = _claude_ui_visible(clean) and not _at_resume_picker(clean)
            if (not actions.get("restarting") and not actions.get("hibernated")
                    and (not _in_grace or _ui_stale)):
                cfg_pl = parse_env_file(f)
                if (cfg_pl.get("CC_AUTO_CONTINUE") in ("1", "true", "yes")
                        and cfg_pl.get("CC_ARCHIVED") != "1"):
                    last_restart = actions.get("last_auto_restart", 0)
                    if now - last_restart > 90:
                        try:
                            tmux_sess = tmux_name(name)
                            r_pp = subprocess.run(
                                ["tmux", "list-panes", "-t", tmux_sess, "-F", "#{pane_pid}"],
                                capture_output=True, text=True, timeout=5)
                            if r_pp.returncode == 0 and r_pp.stdout.strip():
                                shell_pid = r_pp.stdout.strip().split("\n")[0]
                                r_ch = subprocess.run(
                                    ["pgrep", "-P", shell_pid],
                                    capture_output=True, text=True, timeout=5)
                                if not r_ch.stdout.strip():
                                    # Shell has no children — Claude is gone
                                    slog(f"[4b] {name}: no child process under shell PID {shell_pid} — triggering OOM restart")
                                    actions["restarting"] = True
                                    actions["last_auto_restart"] = now
                                    def _do_oom_restart(sname=name, _actions=actions):
                                        time.sleep(3)
                                        start_session(sname)
                                        for _w in range(30):
                                            time.sleep(1)
                                            _o = tmux_capture(sname, 10)
                                            if _o and _claude_ui_visible(_o):
                                                break
                                        _actions.pop("restarting", None)
                                    threading.Thread(target=_do_oom_restart, daemon=True).start()
                                    _push_alert("auto_restart", name,
                                                f"Claude process died in '{name}' (OOM/signal) — auto-restarting")
                                else:
                                    pass  # Claude child exists — healthy
                            else:
                                slog(f"[4b] {name}: list-panes failed rc={r_pp.returncode}")
                        except Exception as e:
                            slog(f"[4b] {name}: exception: {e}")
                    else:
                        pass  # rate-limited (restart < 90s ago)

            # ── 5. Stale process reaper: restart idle sessions with old Claude processes
            # Claude processes lose their API connection after ~2 days but stay running.
            # Sends succeed (tmux delivers text) but Claude never processes them.
            # Check once per hour; restart if Claude process uptime > 48h and session is idle.
            if status == "idle" and not actions.get("restarting"):
                last_stale_check = actions.get("last_stale_check", 0)
                if now - last_stale_check > 3600:  # check once per hour
                    actions["last_stale_check"] = now
                    try:
                        tmux_sess = tmux_name(name)
                        r = subprocess.run(["tmux", "list-panes", "-t", tmux_sess, "-F", "#{pane_pid}"],
                                           capture_output=True, text=True, timeout=5)
                        if r.returncode == 0 and r.stdout.strip():
                            shell_pid = r.stdout.strip().split("\n")[0]
                            r2 = subprocess.run(["pgrep", "-P", shell_pid],
                                                capture_output=True, text=True, timeout=5)
                            if r2.stdout.strip():
                                claude_pid = r2.stdout.strip().split("\n")[0]
                                r3 = subprocess.run(["ps", "-o", "etime=", "-p", claude_pid],
                                                    capture_output=True, text=True, timeout=5)
                                if r3.stdout.strip():
                                    # Parse etime format: [[DD-]HH:]MM:SS
                                    _et = r3.stdout.strip()
                                    _parts = _et.replace("-", ":").split(":")
                                    _parts = [int(p) for p in _parts]
                                    if len(_parts) == 2: elapsed_secs = _parts[0]*60 + _parts[1]
                                    elif len(_parts) == 3: elapsed_secs = _parts[0]*3600 + _parts[1]*60 + _parts[2]
                                    elif len(_parts) == 4: elapsed_secs = _parts[0]*86400 + _parts[1]*3600 + _parts[2]*60 + _parts[3]
                                    else: elapsed_secs = 0
                                    if elapsed_secs > 48 * 3600:  # > 48 hours
                                        last_restart = actions.get("last_auto_restart", 0)
                                        if now - last_restart > 300:
                                            actions["restarting"] = True
                                            actions["last_auto_restart"] = now
                                            def _do_stale_restart(sname=name, _actions=actions, _age=elapsed_secs):
                                                _hard_kill_claude(sname)
                                                time.sleep(3)
                                                start_session(sname)
                                                for _w in range(30):
                                                    time.sleep(1)
                                                    _o = tmux_capture(sname, 10)
                                                    if _o and _claude_ui_visible(_o):
                                                        break
                                                _actions.pop("restarting", None)
                                            threading.Thread(target=_do_stale_restart, daemon=True).start()
                                            _push_alert("auto_restart", name,
                                                        f"Recycled stale session '{name}' — Claude process was "
                                                        f"{elapsed_secs // 3600}h old")
                    except Exception:
                        pass

            # ── 6. Auto-hibernate: stop idle sessions to reclaim memory ───────
            # Claude processes hold 400-750 MB each even when idle. With 30+
            # sessions that causes OOM kills. Stop Claude in sessions idle for
            # >30 min. The conversation is preserved — next send auto-wakes it.
            # Auto-continue sessions are hibernated too — auto-restart already
            # checks `not actions.get("hibernated")` so they won't bounce back.
            # They wake on next send_text (which calls start_session).
            if status == "idle" and not actions.get("restarting"):
                cfg_hib = parse_env_file(f)
                _skip_hibernate = (
                    # Grace period after server restart: actions dict is wiped
                    # so we can't tell if a session was recently active
                    now - _server_start_time < _HIBERNATE_STARTUP_GRACE
                )
                if not _skip_hibernate:
                    last_activity = actions.get("last_claude_alive", 0)
                    meta_h = _load_meta(name)
                    last_send = meta_h.get("last_send", 0)
                    last_real_activity = max(last_activity, last_send)
                    if last_real_activity and now - last_real_activity > _HIBERNATE_IDLE_SECS:
                        if not actions.get("hibernated"):
                            actions["hibernated"] = True
                            def _do_hibernate(sname=name):
                                try:
                                    stop_session(sname)
                                    print(f"[hibernate] {sname}: stopped after {int(now - last_real_activity)}s idle")
                                except Exception:
                                    pass
                            threading.Thread(target=_do_hibernate, daemon=True).start()

            # ── 3a. Post-compact continuation ──────────────────────────────────
            # After we trigger auto-compact, the session goes idle at the ❯ prompt.
            # status == 'idle' doesn't trigger normal auto-continue, so we handle
            # it explicitly: wait ≥30s for compact to finish, then send a continue msg.
            # Skip if mid-restart — text would land in resume picker search box.
            if actions.get("post_compact_continue") and status in ("idle", "waiting") and not actions.get("restarting"):
                elapsed_since_compact = now - actions.get("last_compact", 0)
                if elapsed_since_compact > 30 and now - actions.get("last_auto_continue", 0) > 60:
                    cfg_ac = parse_env_file(f)
                    cont_msg = cfg_ac.get("CC_AUTO_CONTINUE_MSG", "continue")
                    send_text(name, cont_msg)
                    actions["last_auto_continue"] = now
                    actions.pop("post_compact_continue", None)
                    _push_alert("auto_continue", name,
                                f"Post-compact auto-continue sent to '{name}'")

            if status == "waiting" and not actions.get("restarting"):
                if "ac_waiting_since" not in actions:
                    # First snapshot seeing this session waiting — remember it
                    actions["ac_waiting_since"] = now
                else:
                    # Still waiting on a subsequent snapshot — check opt-in flag
                    cfg_ac = parse_env_file(f)
                    if cfg_ac.get("CC_AUTO_CONTINUE") in ("1", "true", "yes"):
                        if now - actions.get("last_auto_continue", 0) > 30:
                            # Determine what kind of waiting and what to send
                            lines_ac = [l.strip() for l in clean.splitlines() if l.strip()]
                            response = None
                            label = ""
                            for l in reversed(lines_ac[-15:]):
                                sl = l.lower()
                                if "enter to select" in sl:
                                    response = ""   # bare Enter → select current option
                                    label = "Enter (select option)"
                                    break
                                if re.match(r".*\u276f\s*\d+\.", l):  # ❯ 1. Yes selector
                                    response = "1"
                                    label = "1 (first option)"
                                    break
                                if "do you want to proceed" in sl:
                                    response = "1"
                                    label = "1 (proceed)"
                                    break
                                if "interrupted" in sl and "what should claude do" in sl:
                                    custom = cfg_ac.get("CC_AUTO_CONTINUE_MSG", "continue")
                                    response = custom
                                    label = repr(custom)
                                    break
                            if response is not None:
                                send_text(name, response)
                                actions["last_auto_continue"] = now
                                actions.pop("ac_waiting_since", None)
                                _push_alert("auto_continue", name,
                                            f"Auto-continued '{name}': sent {label}")
            else:
                # Session no longer waiting — reset tracking
                actions.pop("ac_waiting_since", None)

            # ── 5. Steering: deliver queued messages at turn boundary ────────
            _steer_try_deliver(name, status, output)

        except Exception:
            pass


def _snapshot_loop():
    try:
        _snapshot_all_sessions()
    except Exception:
        pass


# ── Browser idle reaper ──────────────────────────────────────────────────────
_BROWSER_IDLE_SECONDS = 15 * 60   # kill browser-use sessions idle >15 min
_BROWSER_MAX_TTL_SECONDS = 2 * 3600  # hard cap: kill any browser process >2h regardless

def _parse_etime(etime: str) -> int | None:
    """Parse ps etime format [[DD-]HH:]MM:SS into seconds."""
    if not etime:
        return None
    parts = etime.replace("-", ":").split(":")
    try:
        parts = [int(p) for p in parts]
    except ValueError:
        return None
    if len(parts) == 2: return parts[0]*60 + parts[1]
    elif len(parts) == 3: return parts[0]*3600 + parts[1]*60 + parts[2]
    elif len(parts) == 4: return parts[0]*86400 + parts[1]*3600 + parts[2]*60 + parts[3]
    return None

def _reap_stale_browsers():
    """Kill browser-use Chrome/Playwright processes that are idle or exceed max TTL.

    Two checks:
    1. Idle check — if no API call has touched a session in _BROWSER_IDLE_SECONDS, close it.
    2. Hard TTL — any browser-use Chrome process older than _BROWSER_MAX_TTL_SECONDS is killed
       regardless of activity (safety net for leaked processes).
    """
    now = time.time()

    # ── Phase 1: close idle browser-use sessions via CLI ──
    idle_sessions = []
    for session, last_active in list(_browser_session_activity.items()):
        if now - last_active > _BROWSER_IDLE_SECONDS:
            idle_sessions.append(session)
    for session in idle_sessions:
        try:
            _bu_call(["close"], session=session, timeout_s=10)
            slog(f"[browser-reaper] closed idle session '{session}' "
                 f"(idle {int(now - _browser_session_activity.get(session, now))}s)")
        except Exception:
            pass
        _browser_session_activity.pop(session, None)

    # ── Phase 2: hard-kill orphan Chrome/Playwright processes past max TTL ──
    try:
        r = subprocess.run(["pgrep", "-f", "browser-use-user-data-dir"],
                           capture_output=True, text=True, timeout=5)
        pids = [p.strip() for p in r.stdout.strip().split("\n") if p.strip()]
        if not pids:
            return
        reaped = 0
        for pid in pids:
            try:
                r2 = subprocess.run(["ps", "-o", "etime=", "-p", pid],
                                    capture_output=True, text=True, timeout=5)
                secs = _parse_etime(r2.stdout.strip())
                if secs is None:
                    continue
                if secs > _BROWSER_MAX_TTL_SECONDS:
                    os.kill(int(pid), 9)
                    reaped += 1
            except (ProcessLookupError, ValueError, subprocess.TimeoutExpired):
                pass
        if reaped:
            slog(f"[browser-reaper] hard-killed {reaped} orphan Chrome processes "
                 f"(>{_BROWSER_MAX_TTL_SECONDS//3600}h old)")
    except Exception:
        pass


# ── Ray Serve killer — Ray should never be running locally for extended periods ──
_last_ray_check = 0.0

def _kill_stale_ray():
    """Kill Ray Serve if it's been running for more than 30 minutes.
    Sessions occasionally start Ray for local testing but never stop it,
    consuming massive CPU/RAM (multiple ML model workers)."""
    global _last_ray_check
    now = time.time()
    if now - _last_ray_check < 600:
        return
    _last_ray_check = now
    try:
        r = subprocess.run(["pgrep", "-f", "ray::ServeController"],
                           capture_output=True, text=True, timeout=5)
        if not r.stdout.strip():
            return
        pid = r.stdout.strip().split("\n")[0]
        r2 = subprocess.run(["ps", "-o", "etime=", "-p", pid],
                            capture_output=True, text=True, timeout=5)
        etime = r2.stdout.strip()
        if not etime:
            return
        parts = etime.replace("-", ":").split(":")
        parts = [int(p) for p in parts]
        if len(parts) == 2: secs = parts[0]*60 + parts[1]
        elif len(parts) == 3: secs = parts[0]*3600 + parts[1]*60 + parts[2]
        elif len(parts) == 4: secs = parts[0]*86400 + parts[1]*3600 + parts[2]*60 + parts[3]
        else: return
        if secs > 1800:  # > 30 minutes
            subprocess.run("pkill -9 -f 'ray::' 2>/dev/null; pkill -9 -f 'ray/core/src/ray' 2>/dev/null; "
                           "pkill -9 -f 'ray/dashboard' 2>/dev/null; pkill -9 -f 'ray/autoscaler' 2>/dev/null; "
                           "pkill -9 -f 'ray.util.client' 2>/dev/null",
                           shell=True, timeout=15)
            slog(f"[ray-reaper] killed Ray Serve cluster — was running for {secs//60}m")
    except Exception:
        pass


def get_claude_stats(work_dir: str) -> dict:
    """Get token usage and last activity from Claude Code session files for a directory.

    Only reads the tail of the JSONL file (last 5MB) to avoid loading
    hundreds of MB into memory for long-running sessions.
    """
    if not work_dir:
        return {"tokens": 0, "last_active": ""}
    # Map dir path to Claude project directory name
    project_name = _project_name(work_dir)
    project_dir = CLAUDE_HOME / "projects" / project_name
    if not project_dir.is_dir():
        return {"tokens": 0, "last_active": ""}
    # Find the most recent JSONL file
    jsonl_files = sorted(project_dir.glob("*.jsonl"), key=lambda f: f.stat().st_mtime, reverse=True)
    if not jsonl_files:
        return {"tokens": 0, "last_active": ""}
    # Sum tokens from tail of most recent session, get last timestamp
    total_in = 0
    total_out = 0
    last_ts = ""
    for entry in _iter_jsonl_tail(jsonl_files[0], max_bytes=5_000_000):
        try:
            ts = entry.get("timestamp", "")
            if ts:
                last_ts = ts
            msg = entry.get("message", {})
            usage = msg.get("usage", {})
            if usage:
                total_in += usage.get("input_tokens", 0)
                total_in += usage.get("cache_read_input_tokens", 0)
                total_out += usage.get("output_tokens", 0)
        except (json.JSONDecodeError, AttributeError):
            continue
    return {"tokens": total_in + total_out, "last_active": last_ts}


_model_cache = {}  # {work_dir: (model, mtime, timestamp)}
_MODEL_CACHE_TTL = 15  # seconds

def detect_active_model(work_dir: str, conversation_id: str = "") -> str:
    """Detect the model in use from the session's own JSONL conversation file."""
    if not work_dir:
        return ""
    project_name = _project_name(work_dir)
    project_dir = CLAUDE_HOME / "projects" / project_name
    if not project_dir.is_dir():
        return ""
    # Prefer the session's own conversation JSONL file
    if conversation_id:
        conv_file = project_dir / f"{conversation_id}.jsonl"
        if conv_file.exists():
            f = conv_file
        else:
            return ""
    else:
        jsonl_files = sorted(project_dir.glob("*.jsonl"), key=lambda f: f.stat().st_mtime, reverse=True)
        if not jsonl_files:
            return ""
        f = jsonl_files[0]
    try:
        mtime = f.stat().st_mtime
    except OSError:
        return ""
    # Cache hit: same file mtime and within TTL
    cache_key = (work_dir, conversation_id)
    cached = _model_cache.get(cache_key)
    if cached:
        c_model, c_mtime, c_ts = cached
        if c_mtime == mtime or (time.time() - c_ts < _MODEL_CACHE_TTL):
            return c_model
    try:
        # Search from end in increasing chunks until we find a model
        size = f.stat().st_size
        for chunk_size in [200_000, 1_000_000, size]:
            with f.open("rb") as fh:
                offset = max(0, size - chunk_size)
                if offset > 0:
                    fh.seek(offset)
                    fh.readline()  # skip partial line
                data = fh.read().decode("utf-8", errors="replace")
            for line in reversed(data.splitlines()):
                try:
                    entry = json.loads(line)
                    model = entry.get("message", {}).get("model", "")
                    if model:
                        _model_cache[cache_key] = (model, mtime, time.time())
                        return model
                except (json.JSONDecodeError, AttributeError):
                    continue
            if chunk_size >= size:
                break
    except Exception:
        pass
    _model_cache[cache_key] = ("", mtime, time.time())
    return ""


_TOKEN_BASELINE_FILE = CC_HOME / "token_baseline.json"


def _load_token_baseline() -> dict:
    if _TOKEN_BASELINE_FILE.exists():
        try:
            data = json.loads(_TOKEN_BASELINE_FILE.read_text())
            from datetime import datetime
            if data.get("date") == datetime.now().strftime("%Y-%m-%d"):
                return data
        except Exception:
            pass
    return {}


def save_token_baseline(stats: dict):
    from datetime import datetime
    baseline = {"date": datetime.now().strftime("%Y-%m-%d"), "sessions": {}}
    # Key by project dir (stable) not by display label (can change)
    for s in stats.get("sessions", []):
        key = s.get("proj_dir", s["name"])
        baseline["sessions"][key] = {"input": s["input"], "output": s["output"]}
    baseline["total_input"] = stats.get("total_input", 0)
    baseline["total_output"] = stats.get("total_output", 0)
    _TOKEN_BASELINE_FILE.write_text(json.dumps(baseline))


